/**
 * General AI Document Extraction API
 * 
 * Accepts an image/PDF and uses OpenAI Vision to extract document data.
 * Supports: receipts, supplier_invoices, customer_invoices
 * 
 * SECURITY: Requires authentication (GPT-4o Vision is expensive)
 */

import { NextRequest, NextResponse } from 'next/server'
import OpenAI from 'openai'
import { verifyAuth, ApiResponse } from '@/lib/api-auth'

function getOpenAIClient() {
    return new OpenAI({
        apiKey: process.env.OPENAI_API_KEY,
        timeout: 30000,
    })
}

const EXTRACTION_PROMPTS: Record<string, string> = {
    supplier_invoice: `You are an OCR system specialized in Swedish supplier invoices (leverantörsfakturor).
Extract data from the invoice image and return JSON:
{
    "supplier": "Company/vendor name",
    "invoiceNumber": "Invoice number (fakturanummer)",
    "ocr": "OCR number if present",
    "issueDate": "YYYY-MM-DD issue date",
    "dueDate": "YYYY-MM-DD due date (förfallodatum)",
    "amount": numeric amount excluding VAT in SEK,
    "vatAmount": numeric VAT amount in SEK (moms),
    "totalAmount": numeric total amount including VAT,
    "category": "Category suggestion",
    "confidence": 0-100 overall confidence
}

Categories: Kontorsmaterial, Programvara, Konsulttjänster, Hyra, Inköp material, IT-utrustning, Övriga kostnader

Swedish invoice hints:
- "Fakturanr" or "Fakturanummer" = invoice number
- "OCR" = payment reference
- "Förfallodatum" = due date
- "Fakturadatum" = issue date
- "Moms" or "Mervärdesskatt" = VAT
- "Att betala" or "Summa" = total amount

Return ONLY valid JSON, no markdown.`,

    receipt: `You are an OCR system specialized in Swedish receipts (kvitton).
Extract data from the receipt image and return JSON:
{
    "supplier": "Store/vendor name",
    "date": "YYYY-MM-DD",
    "amount": numeric total amount in SEK including VAT,
    "vatAmount": numeric VAT amount in SEK,
    "category": "Category suggestion",
    "confidence": 0-100 overall confidence
}

Categories: Kontorsmaterial, Programvara, Resekostnader, Representation, IT-utrustning, Övriga kostnader

Return ONLY valid JSON, no markdown.`,

    customer_invoice: `You are an OCR system specialized in Swedish customer invoices.
Extract data from the invoice image and return JSON:
{
    "customer": "Customer name",
    "invoiceNumber": "Invoice number",
    "issueDate": "YYYY-MM-DD",
    "dueDate": "YYYY-MM-DD",
    "amount": numeric amount excluding VAT,
    "vatAmount": numeric VAT amount,
    "totalAmount": numeric total amount,
    "confidence": 0-100 overall confidence
}

Return ONLY valid JSON, no markdown.`
}

export async function POST(request: NextRequest) {
    // Verify authentication - this endpoint uses expensive GPT-4o Vision API
    const auth = await verifyAuth(request)
    if (!auth) {
        return ApiResponse.unauthorized('Authentication required for AI extraction')
    }

    try {
        const formData = await request.formData()
        const file = formData.get('file') as File | null
        const documentType = (formData.get('type') as string) || 'receipt'

        if (!file) {
            return NextResponse.json({ error: 'No file provided' }, { status: 400 })
        }

        // Check if OpenAI is configured
        if (!process.env.OPENAI_API_KEY) {
            return NextResponse.json(
                { error: 'AI extraction is not configured. Set OPENAI_API_KEY to enable OCR.' },
                { status: 503 }
            )
        }

        console.log(`[AI Extract] Processing ${documentType}: ${file.name}, size: ${file.size}`)

        // Convert file to base64 for OpenAI Vision API
        const bytes = await file.arrayBuffer()
        const base64 = Buffer.from(bytes).toString('base64')
        const mimeType = file.type || 'image/jpeg'
        const dataUrl = `data:${mimeType};base64,${base64}`

        // Get the appropriate prompt
        const systemPrompt = EXTRACTION_PROMPTS[documentType] || EXTRACTION_PROMPTS.receipt

        // Call OpenAI Vision API
        const openai = getOpenAIClient()
        const response = await openai.chat.completions.create({
            model: 'gpt-4o',
            messages: [
                {
                    role: 'system',
                    content: systemPrompt
                },
                {
                    role: 'user',
                    content: [
                        {
                            type: 'image_url',
                            image_url: {
                                url: dataUrl,
                                detail: 'high'
                            }
                        },
                        {
                            type: 'text',
                            text: 'Extract all relevant data from this document.'
                        }
                    ]
                }
            ],
            max_tokens: 1000,
            temperature: 0.1,
        })

        const content = response.choices[0]?.message?.content || '{}'

        // Parse the JSON response
        let extractedData
        try {
            // Clean up markdown code blocks if present
            const cleanedContent = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()
            extractedData = JSON.parse(cleanedContent)
        } catch (parseError) {
            console.error('[AI Extract] Failed to parse response:', content)
            return NextResponse.json({ 
                error: 'Failed to parse AI response',
                raw: content 
            }, { status: 500 })
        }

        console.log('[AI Extract] Extracted:', extractedData)

        return NextResponse.json({
            success: true,
            ...extractedData
        })
    } catch (error) {
        console.error('[AI Extract] Error:', error)
        return NextResponse.json({ 
            error: 'Extraction failed',
            message: error instanceof Error ? error.message : 'Unknown error'
        }, { status: 500 })
    }
}

import { NextResponse } from 'next/server';
import ical, { ICalCalendarMethod } from 'ical-generator';
import { getRoadmaps } from '@/services/roadmap-service'; // NOTE: This will require service to work on server (it does)

export async function GET(request: Request) {
    // In a real app, we would validate the 'userId' or 'token' query param
    // const { searchParams } = new URL(request.url);
    // const token = searchParams.get('token');

    const calendar = ical({
        name: 'Scope AI - Viktiga Datum',
        method: ICalCalendarMethod.PUBLISH,
        scale: 'GREGORIAN',
        url: 'https://scope-ai.se', // Your app URL
        ttl: 3600, // Check for updates every hour
    });

    const currentYear = new Date().getFullYear();

    // 1. Static Tax Events (Always present)
    calendar.createEvent({
        start: new Date(currentYear, 4, 12, 9, 0), // May 12
        end: new Date(currentYear, 4, 12, 10, 0),
        summary: 'Momsdeklaration Q1',
        description: 'Sista dag att lämna och betala moms för Q1 (jan-mars).',
        url: 'https://scope-ai.se/rapporter/moms'
    });

    // 2. Dynamic Roadmap Events (From DB)
    try {
        const roadmaps = await getRoadmaps();

        roadmaps.forEach(roadmap => {
            if (roadmap.status === 'archived') return;

            roadmap.steps?.forEach(step => {
                // Only add if it has a due date and isn't completed/skipped
                if (step.due_date && step.status !== 'completed' && step.status !== 'skipped') {
                    const date = new Date(step.due_date);
                    // Standard 1 hour duration
                    const endDate = new Date(date);
                    endDate.setHours(date.getHours() + 1);

                    calendar.createEvent({
                        start: date,
                        end: endDate,
                        summary: step.title, // e.g. "Skicka in Bolagsverket-anmälan"
                        description: `Del av plan: ${roadmap.title}\n\n${step.description || ''}`,
                        url: `https://scope-ai.se/handelser?roadmap=${roadmap.id}`,
                    });
                }
            });
        });
    } catch (error) {
        // Fallback or log error, but still return static calendar
        console.error("Failed to fetch roadmaps for calendar", error);
    }

    // 3. Payroll (Static example, could also be dynamic)
    const nextPayDay = new Date();
    nextPayDay.setDate(25);
    if (nextPayDay < new Date()) {
        nextPayDay.setMonth(nextPayDay.getMonth() + 1);
    }

    calendar.createEvent({
        start: new Date(nextPayDay.getFullYear(), nextPayDay.getMonth(), 25, 10, 0),
        end: new Date(nextPayDay.getFullYear(), nextPayDay.getMonth(), 25, 11, 0),
        summary: 'Löneutbetalning',
        description: 'Dags att betala ut lönerna.',
        url: 'https://scope-ai.se/loner'
    });

    return new NextResponse(calendar.toString(), {
        headers: {
            'Content-Type': 'text/calendar; charset=utf-8',
            'Content-Disposition': 'attachment; filename="scope-ai-calendar.ics"',
        },
    });
}

/**
 * OpenAI GPT Provider for Chat API
 */

import { streamText, streamData } from '../streaming'
import { SYSTEM_PROMPT } from '../system-prompt'
import { aiToolRegistry, toolsToOpenAIFunctions, type AIToolResult } from '@/lib/ai-tools'
import type { 
    AIContentPart, 
    AIToolDefinition, 
    ProviderHandlerParams 
} from '../types'

// Model mapping
const OPENAI_MODEL_MAP: Record<string, string> = {
    'gpt-4o': 'gpt-4o',
    'gpt-4o-mini': 'gpt-4o-mini',
    'gpt-4-turbo': 'gpt-4-turbo',
}

/**
 * Handle a chat request using OpenAI's GPT API
 */
export async function handleOpenAIProvider(params: ProviderHandlerParams): Promise<string> {
    const { 
        modelId, 
        messagesForAI, 
        controller, 
        conversationId, 
        tools, 
        userDb 
    } = params

    const OpenAI = (await import('openai')).default
    const openai = new OpenAI({
        apiKey: process.env.OPENAI_API_KEY,
    })

    const actualModel = OPENAI_MODEL_MAP[modelId] || 'gpt-4o-mini'

    // Convert messages to OpenAI format with null safety
    const openaiMessages = [
        { role: 'system' as const, content: SYSTEM_PROMPT },
        ...messagesForAI.map(m => ({
            role: m.role as 'user' | 'assistant',
            content: typeof m.content === 'string'
                ? m.content
                : Array.isArray(m.content)
                    ? (m.content as AIContentPart[]).map((c) => {
                        if (c.type === 'text') return { type: 'text' as const, text: c.text || '' }
                        if (c.type === 'image_url' && c.image_url && typeof c.image_url === 'object' && 'url' in c.image_url) {
                            return {
                                type: 'image_url' as const,
                                image_url: { url: (c.image_url as { url: string }).url, detail: 'low' as const }
                            }
                        }
                        return { type: 'text' as const, text: '' }
                    })
                    : m.content || ''
        }))
    ]

    // Convert tools to OpenAI function format
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const openaiTools = tools.length > 0 ? toolsToOpenAIFunctions(tools as any) : undefined

    // Debug: Log tools being passed
    console.log(`[OpenAI] Passing ${openaiTools?.length || 0} tools to model ${actualModel}`)
    if (openaiTools && openaiTools.length > 0) {
        console.log(`[OpenAI] Tool names:`, openaiTools.map(t => t.function.name).join(', '))
    }

    let fullContent = ''

    // Debug: Log message structure
    console.log('[OpenAI] Messages structure:')
    for (const msg of openaiMessages) {
        if (typeof msg.content === 'string') {
            console.log(`  ${msg.role}: string (${msg.content.length} chars)`)
        } else if (Array.isArray(msg.content)) {
            console.log(`  ${msg.role}: array with ${msg.content.length} parts:`)
            for (const part of msg.content) {
                if (part.type === 'text') {
                    console.log(`    - text: "${part.text?.slice(0, 50)}..."`)
                } else if (part.type === 'image_url') {
                    const url = part.image_url?.url || ''
                    console.log(`    - image_url: ${url.slice(0, 50)}... (${url.length} chars)`)
                } else {
                    console.log(`    - unknown type: ${JSON.stringify(part).slice(0, 100)}`)
                }
            }
        } else {
            console.log(`  ${msg.role}: ${typeof msg.content}`)
        }
    }

    try {
        const stream = await openai.chat.completions.create({
            model: actualModel,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            messages: openaiMessages as any,
            stream: true,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            tools: openaiTools as any,
            tool_choice: openaiTools ? 'auto' : undefined,
        })

        // Accumulate tool calls across chunks (OpenAI streams them incrementally)
        const toolCallsInProgress: Map<number, { id: string; name: string; arguments: string }> = new Map()

        for await (const chunk of stream) {
            const delta = chunk.choices[0]?.delta
            const finishReason = chunk.choices[0]?.finish_reason

            // Handle text content
            if (delta?.content) {
                fullContent += delta.content
                streamText(controller, delta.content)
            }

            // Accumulate tool call chunks
            if (delta?.tool_calls) {
                for (const toolCall of delta.tool_calls) {
                    const index = toolCall.index
                    const existing = toolCallsInProgress.get(index) || { id: '', name: '', arguments: '' }

                    if (toolCall.id) existing.id = toolCall.id
                    if (toolCall.function?.name) existing.name += toolCall.function.name
                    if (toolCall.function?.arguments) existing.arguments += toolCall.function.arguments

                    toolCallsInProgress.set(index, existing)
                }
            }

            // When streaming completes with tool_calls finish reason, execute them
            if (finishReason === 'tool_calls' || finishReason === 'stop') {
                for (const [, toolCall] of toolCallsInProgress) {
                    if (toolCall.name && toolCall.arguments) {
                        console.log(`[OpenAI] Executing tool: ${toolCall.name}`)
                        try {
                            const toolArgs = JSON.parse(toolCall.arguments)
                            const tool = aiToolRegistry.get(toolCall.name)

                            if (tool) {
                                const result = await tool.execute(toolArgs, {
                                    userId: userDb?.userId || '',
                                    companyId: userDb?.companyId || '',
                                    userDb: userDb!
                                }) as AIToolResult

                                // Stream back the result data
                                if (result.display) {
                                    streamData(controller, { display: result.display })
                                }
                                if (result.navigation) {
                                    streamData(controller, { navigation: result.navigation })
                                }
                                if (result.confirmationRequired) {
                                    streamData(controller, { confirmationRequired: result.confirmationRequired })
                                }
                                streamData(controller, { toolResults: [{ tool: toolCall.name, result: result.data }] })
                            } else {
                                console.error(`[OpenAI] Tool not found: ${toolCall.name}`)
                            }
                        } catch (parseError) {
                            console.error(`[OpenAI] Tool ${toolCall.name} failed:`, parseError)
                        }
                    }
                }
                toolCallsInProgress.clear()
            }
        }
    } catch (error: unknown) {
        console.error('OpenAI API error:', error)
        // Extract meaningful error message from OpenAI error
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        let errorDetail = (error as any).message || 'Ett fel uppstod vid generering.'
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((error as any).error?.message) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            errorDetail = (error as any).error.message
        }
        // Check for common image-related errors
        if (errorDetail.includes('image') || errorDetail.includes('content_policy')) {
            errorDetail = 'Kunde inte behandla bilden. Försök med en annan bild eller mindre storlek.'
        }
        const errorMsg = `\n\nFel: ${errorDetail}`
        fullContent += errorMsg
        streamText(controller, errorMsg)
    }

    // Persist message
    if (conversationId && fullContent && userDb) {
        try {
            await userDb.messages.create({
                conversation_id: conversationId,
                role: 'assistant',
                content: fullContent,
                user_id: userDb.userId
            })
        } catch (e) {
            console.error('Failed to save message', e)
        }
    }

    return fullContent
}

/**
 * Compliance API (Shareholders, Corporate Documents)
 * 
 * Security: Uses user-scoped DB access with RLS enforcement
 */

import { NextRequest, NextResponse } from "next/server"
import { createUserScopedDb } from '@/lib/database/user-scoped-db'

export async function GET(request: NextRequest) {
    const { searchParams } = new URL(request.url)
    const type = searchParams.get('type')

    try {
        const userDb = await createUserScopedDb();

        if (!userDb) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        // Use raw client for tables not yet in typed accessors
        const supabase = userDb.client;

        if (type === 'shareholders') {
            const { data: shareholders, error } = await supabase
                .from('shareholders')
                .select('*')

            if (error) throw error;
            return NextResponse.json({ success: true, data: shareholders || [] })
        }

        const { data: documents, error } = await supabase
            .from('corporate_documents' as any)
            .select('*')

        if (error) throw error;
        return NextResponse.json({ success: true, data: documents || [] })
    } catch (error) {
        console.error('Compliance API GET error:', error)
        return NextResponse.json(
            { success: false, error: 'Failed to fetch compliance data' },
            { status: 500 }
        )
    }
}

export async function POST(request: NextRequest) {
    try {
        const userDb = await createUserScopedDb();

        if (!userDb) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const body = await request.json()
        // Use 'action' key to avoid collision with document's 'type' field
        const { action, ...data } = body
        const supabase = userDb.client;

        if (action === 'document') {
            // Note: corporate_documents doesn't have company_id column, only user_id
            const insertData = { ...data, user_id: userDb.userId }
            console.log('[Compliance API] Inserting document:', insertData)
            const { data: newDoc, error } = await supabase
                .from('corporate_documents' as any)
                .insert(insertData)
                .select()
                .single();

            console.log('[Compliance API] Insert result:', { newDoc, error })
            if (error) throw error;
            return NextResponse.json({ success: true, data: newDoc })
        }

        if (action === 'document_update') {
            const { id, ...updates } = data
            console.log('[Compliance API] Updating document:', { id, updates })
            const { data: updated, error } = await supabase
                .from('corporate_documents' as any)
                .update(updates)
                .eq('id', id)
                .eq('user_id', userDb.userId) // Ensure user owns this document
                .select()
                .single();

            console.log('[Compliance API] Update result:', { updated, error })
            if (error) throw error;
            return NextResponse.json({ success: true, data: updated })
        }

        if (action === 'shareholder_update') {
            const { id, ...updates } = data
            const { data: updated, error } = await supabase
                .from('shareholders')
                .update(updates)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return NextResponse.json({ success: true, data: updated })
        }

        if (action === 'shareholder_create') {
            const { id: _id, ...newShareholder } = data
            const { data: created, error } = await supabase
                .from('shareholders')
                .insert({ ...newShareholder, company_id: userDb.companyId })
                .select()
                .single();

            if (error) throw error;
            return NextResponse.json({ success: true, data: created })
        }

        return NextResponse.json(
            { success: false, error: 'Invalid compliance action type' },
            { status: 400 }
        )
    } catch (error) {
        console.error('Compliance API POST error:', error)
        return NextResponse.json(
            { success: false, error: 'Failed to process compliance action' },
            { status: 500 }
        )
    }
}

import { NextResponse } from 'next/server';
import { sendEmail } from '@/lib/email';
import PayslipEmail from '@/emails/payslip-template';

export async function POST(req: Request) {
    try {
        const { email } = await req.json();

        if (!email) {
            return NextResponse.json({ error: 'Email is required' }, { status: 400 });
        }

        const result = await sendEmail({
            to: email,
            subject: 'Test av lönespecifikation - Scope AI',
            react: PayslipEmail({
                employeeName: 'Test Testson',
                period: 'Mars 2026',
                netSalary: 42000,
                paymentDate: new Date().toLocaleDateString('sv-SE')
            }),
        });

        if (!result.success) {
            return NextResponse.json({ error: result.error }, { status: 500 });
        }

        return NextResponse.json({ success: true, data: result.data });
    } catch (error) {
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

/**
 * Monthly Review API
 *
 * GET /api/monthly-review?year=2026&month=3
 *
 * Returns detailed data for a single month: transactions, invoices, receipts,
 * payslips, VAT reports, verifications, and financial summary — all grouped
 * by status with counts for the Notion-style month review dialog.
 *
 * Security: Uses user-scoped DB access with RLS enforcement.
 */

import { NextRequest, NextResponse } from "next/server"
import { createUserScopedDb } from '@/lib/database/user-scoped-db'

interface StatusBreakdown {
    status: string
    count: number
    variant: string
}

interface Section {
    type: string
    label: string
    totalCount: number
    statusBreakdown: StatusBreakdown[]
}

interface MonthlyReviewResponse {
    financial: {
        revenue: number
        expenses: number
        result: number
    }
    sections: Section[]
}

// Status → variant mapping (mirrors status-types.ts)
const TRANSACTION_VARIANTS: Record<string, string> = {
    "Att bokföra": "warning",
    "Bokförd": "success",
    "Saknar underlag": "error",
    "Ignorerad": "neutral",
}

const INVOICE_VARIANTS: Record<string, string> = {
    "Betald": "success",
    "Skickad": "info",
    "Utkast": "neutral",
    "Förfallen": "error",
    "Makulerad": "neutral",
    "Bokförd": "violet",
    "Mottagen": "info",
}

const SUPPLIER_VARIANTS: Record<string, string> = {
    "Mottagen": "violet",
    "Attesterad": "warning",
    "Betald": "success",
    "Förfallen": "error",
    "Tvist": "purple",
    "Bokförd": "violet",
}

const RECEIPT_VARIANTS: Record<string, string> = {
    "Verifierad": "success",
    "Väntar": "warning",
    "Bearbetar": "neutral",
    "Granskning krävs": "error",
    "Behandlad": "success",
    "Matchad": "success",
    "Avvisad": "error",
    "Bokförd": "violet",
}

const PAYSLIP_VARIANTS: Record<string, string> = {
    "draft": "neutral",
    "pending": "warning",
    "sent": "success",
    "paid": "success",
}

function groupByStatus<T extends Record<string, unknown>>(
    items: T[],
    statusField: string,
    variantMap: Record<string, string>,
    defaultStatus = "Okänd"
): StatusBreakdown[] {
    const counts = new Map<string, number>()
    for (const item of items) {
        const status = (item[statusField] as string) || defaultStatus
        counts.set(status, (counts.get(status) || 0) + 1)
    }

    return Array.from(counts.entries()).map(([status, count]) => ({
        status,
        count,
        variant: variantMap[status] || "neutral",
    }))
}

export async function GET(request: NextRequest) {
    try {
        const userDb = await createUserScopedDb()
        if (!userDb) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const { searchParams } = new URL(request.url)
        const year = parseInt(searchParams.get('year') || '') || new Date().getFullYear()
        const month = parseInt(searchParams.get('month') || '') || (new Date().getMonth() + 1)

        if (month < 1 || month > 12) {
            return NextResponse.json({ error: 'Invalid month' }, { status: 400 })
        }

        const startDate = `${year}-${String(month).padStart(2, '0')}-01`
        const lastDay = new Date(year, month, 0).getDate()
        const endDate = `${year}-${String(month).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`

        // Determine which quarter this month belongs to for VAT
        const quarter = Math.ceil(month / 3)
        const quarterPeriodId = `${year}-Q${quarter}`

        // Run 8 parallel queries
        const results = await Promise.allSettled([
            // 0: Transactions
            userDb.client
                .from('transactions')
                .select('id, status')
                .gte('date', startDate)
                .lte('date', endDate),

            // 1: Customer invoices
            userDb.client
                .from('customerinvoices')
                .select('id, status')
                .gte('invoice_date', startDate)
                .lte('invoice_date', endDate),

            // 2: Supplier invoices
            userDb.client
                .from('supplierinvoices')
                .select('id, status')
                .gte('issue_date', startDate)
                .lte('issue_date', endDate),

            // 3: Receipts
            userDb.client
                .from('receipts')
                .select('id, status')
                .gte('date', startDate)
                .lte('date', endDate),

            // 4: Payslips
            userDb.client
                .from('payslips')
                .select('id, status')
                .eq('year', year)
                .eq('month', month),

            // 5: VAT reports
            userDb.client
                .from('taxreports')
                .select('id, status, period_id')
                .eq('type', 'vat')
                .eq('period_id', quarterPeriodId),

            // 6: Verifications (count only)
            userDb.client
                .from('verifications')
                .select('id', { count: 'exact', head: true })
                .gte('date', startDate)
                .lte('date', endDate),

            // 7: Financial balances
            userDb.client.rpc('get_account_balances', {
                p_start_date: startDate,
                p_end_date: endDate,
            }),
        ])

        // Extract results safely — cast to any to avoid union type issues from allSettled
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const extract = (idx: number): { data: any[] | null; count: number | null; error: unknown } => {
            const r = results[idx]
            if (r.status === 'fulfilled') return r.value as { data: any[] | null; count: number | null; error: unknown }
            console.error(`monthly-review query ${idx} failed:`, r.reason)
            return { data: null, count: null, error: r.reason }
        }

        const txResult = extract(0)
        const custInvResult = extract(1)
        const suppInvResult = extract(2)
        const receiptResult = extract(3)
        const payslipResult = extract(4)
        const vatResult = extract(5)
        const verifResult = extract(6)
        const balanceResult = extract(7)

        // Build sections (only include non-empty)
        const sections: Section[] = []

        const transactions = (txResult.data || []) as Record<string, unknown>[]
        if (transactions.length > 0) {
            sections.push({
                type: 'transactions',
                label: 'Transaktioner',
                totalCount: transactions.length,
                statusBreakdown: groupByStatus(transactions, 'status', TRANSACTION_VARIANTS),
            })
        }

        const customerInvoices = (custInvResult.data || []) as Record<string, unknown>[]
        if (customerInvoices.length > 0) {
            sections.push({
                type: 'customer_invoices',
                label: 'Kundfakturor',
                totalCount: customerInvoices.length,
                statusBreakdown: groupByStatus(customerInvoices, 'status', INVOICE_VARIANTS),
            })
        }

        const supplierInvoices = (suppInvResult.data || []) as Record<string, unknown>[]
        if (supplierInvoices.length > 0) {
            sections.push({
                type: 'supplier_invoices',
                label: 'Leverantörsfakturor',
                totalCount: supplierInvoices.length,
                statusBreakdown: groupByStatus(supplierInvoices, 'status', SUPPLIER_VARIANTS),
            })
        }

        const receipts = (receiptResult.data || []) as Record<string, unknown>[]
        if (receipts.length > 0) {
            sections.push({
                type: 'receipts',
                label: 'Kvitton',
                totalCount: receipts.length,
                statusBreakdown: groupByStatus(receipts, 'status', RECEIPT_VARIANTS),
            })
        }

        const payslips = (payslipResult.data || []) as Record<string, unknown>[]
        if (payslips.length > 0) {
            sections.push({
                type: 'payslips',
                label: 'Lönespecifikationer',
                totalCount: payslips.length,
                statusBreakdown: groupByStatus(payslips, 'status', PAYSLIP_VARIANTS),
            })
        }

        const vatReports = (vatResult.data || []) as Record<string, unknown>[]
        if (vatReports.length > 0) {
            sections.push({
                type: 'vat',
                label: 'Momsrapporter',
                totalCount: vatReports.length,
                statusBreakdown: groupByStatus(vatReports, 'status', { submitted: 'success', draft: 'neutral', pending: 'warning' }),
            })
        }

        // Verifications — just count
        const verificationCount = verifResult.count ?? 0
        if (verificationCount > 0) {
            sections.push({
                type: 'verifications',
                label: 'Verifikationer',
                totalCount: verificationCount,
                statusBreakdown: [],
            })
        }

        // Financial summary
        const balanceData = (balanceResult.data || []) as { account_number: number; balance: number }[]
        let revenue = 0
        let expenses = 0

        for (const row of balanceData) {
            const acc = row.account_number
            const balance = row.balance
            if (acc >= 3000 && acc <= 3999) {
                revenue += Math.abs(balance)
            } else if (acc >= 4000 && acc <= 8999) {
                expenses += balance
            }
        }

        const response: MonthlyReviewResponse = {
            financial: {
                revenue,
                expenses,
                result: revenue - expenses,
            },
            sections,
        }

        return NextResponse.json(response)
    } catch (error) {
        console.error("Failed to fetch monthly review:", error)
        return NextResponse.json({ error: "Failed to fetch" }, { status: 500 })
    }
}

