        )
    }

    const handleHistory = (signatory: Signatory) => {
        setSelectedSignatory(signatory)
        setShowHistoryDialog(true)
    }

    const handleDeregister = (signatory: Signatory) => {
        toast.info(
            "Avregistrera firmatecknare",
