// Attachment preview with image error fallback
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const AttachmentPreview = React.memo(function AttachmentPreview({ attachment }: { attachment: any }) {
    const [imageError, setImageError] = useState(false)
    const isImage = attachment.type?.startsWith('image/')

    // Determine the image source
    const getImageSrc = () => {
        if (attachment.url) return attachment.url
        if (attachment.data && attachment.type) {
            return `data:${attachment.type};base64,${attachment.data}`
        }
        if (attachment.content) return attachment.content
        return null
    }

    const imageSrc = isImage ? getImageSrc() : null
    const showImage = isImage && imageSrc && !imageError

    return (
        <div className="flex items-center gap-2 bg-muted/60 rounded-lg p-2 pr-3 text-xs max-w-[200px]">
            {showImage ? (
                <div className="w-10 h-10 rounded overflow-hidden bg-muted flex-shrink-0">
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img
                        src={imageSrc}
                        alt={attachment.name || 'Bild'}
                        className="w-full h-full object-cover"
                        onError={() => setImageError(true)}
                    />
                </div>
            ) : (
                <div className="w-10 h-10 rounded bg-muted flex items-center justify-center flex-shrink-0">
                    {isImage ? (
                        <ImageIcon className="h-5 w-5 text-muted-foreground" />
                    ) : (
                        <FileText className="h-5 w-5 text-muted-foreground" />
                    )}
                </div>
            )}
            <div className="flex flex-col min-w-0">
                <span className="font-medium truncate max-w-[100px]">{attachment.name || 'Fil'}</span>
                <span className="text-muted-foreground">Bifogad fil</span>
            </div>
        </div>
    )
})


interface ChatMessageListProps {
    messages: Message[]
    isLoading: boolean
    onRetry: (messageId: string) => void
    onConfirm: (confirmationId: string) => void
    onCancelConfirmation: (messageId: string) => void
    onRegenerate?: () => void
}

export const ChatMessageList = React.memo(function ChatMessageList({
    messages,
    isLoading,
    onRetry,
    onConfirm,
    onCancelConfirmation,
}: ChatMessageListProps) {
    // Only used to check if a message is last
    const lastMessageId = messages.length > 0 ? messages[messages.length - 1].id : null

    // Helper component for AI messages
    const AIMessageContent = ({ message, isLast }: { message: Message; isLast: boolean }) => {
        if (message.error) {
            return (
                <div className="flex items-center gap-2 text-destructive">
                    <AlertCircle className="h-4 w-4" />
                    <span className="text-sm">{message.content}</span>
                    <Button
                        variant="ghost"
                        size="sm"
                        className="h-7 gap-1 text-xs"
                        onClick={() => onRetry(message.id)}
                    >
                        <RefreshCw className="h-3 w-3" />
                        Försök igen
                    </Button>
                </div>
            )
        }

        return (
            <div className="space-y-4 w-full">
                {/* Markdown Text */}
                {message.content && (
                    <div className="prose prose-sm max-w-none dark:prose-invert prose-table:border-collapse prose-td:border prose-td:border-border/40 prose-td:p-2 prose-th:border prose-th:border-border/40 prose-th:p-2 prose-th:bg-muted/30">
                        <ReactMarkdown remarkPlugins={[remarkGfm]}>{message.content}</ReactMarkdown>
                    </div>
                )}

                {/* Confirmation Card - Only show on mobile, desktop uses dialog overlay */}
                {message.confirmationRequired && (
                    <div className="md:hidden">
                        <ConfirmationCard
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            confirmation={message.confirmationRequired as any}
                            isLoading={isLoading && isLast}
                            onConfirm={() => onConfirm(message.confirmationRequired!.id)}
                            onCancel={() => onCancelConfirmation(message.id)}
                        />
                    </div>
                )}

                {/* Display Cards - Only show on mobile, desktop uses dialog overlay */}
                {message.display && (
                    <div className="my-2 md:hidden">
                        {message.display.type === 'ReceiptCard' && (
                            <ReceiptCard receipt={(message.display.data.receipt || message.display.data) as Parameters<typeof ReceiptCard>[0]['receipt']} />
                        )}
                        {message.display.type === 'TransactionCard' && (
                            <TransactionCard transaction={(message.display.data.transaction || message.display.data) as Parameters<typeof TransactionCard>[0]['transaction']} />
                        )}
                        {message.display.type === 'TaskChecklist' && (
                            <TaskChecklist
                                title={message.display.data.title || "Uppgifter"}
                                tasks={message.display.data.tasks || []}
                            />
                        )}
                        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                        {message.display.type === ('BenefitsTable' as any) && (
                            <div className="rounded-lg border border-border p-4 bg-muted/30">
                                <h4 className="text-sm font-medium mb-2">Tillgängliga Förmåner</h4>
                                <ul className="space-y-2">
                                    { }
                                    {((message.display.data as { benefits?: Array<{ id?: string; name?: string; category?: string }> }).benefits || []).map((b) => (
                                        <li key={b.id || Math.random()} className="text-xs flex justify-between items-center">
                                            <span>{b.name}</span>
                                            <span className="text-muted-foreground">{b.category}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        )}
                        {message.display.type === 'ActivityCard' && (
                            <ActivityCard
                                action={message.display.data.action || 'created'}
                                entityType={message.display.data.entityType || 'transaction'}
                                title={message.display.data.title || 'Åtgärd utförd'}
                                subtitle={message.display.data.subtitle}
                                changes={message.display.data.changes || []}
                                link={message.display.data.link}
                                linkLabel={message.display.data.linkLabel}
                            />
                        )}
                        {message.display.type === 'ComparisonTable' && (
                            <ComparisonTable
                                title={message.display.data.title}
                                rows={message.display.data.rows || []}
                            />
                        )}
                    </div>
                )}

                {/* Inline-only cards (always visible, no overlay) */}
                {message.display && (message.display.type === 'BalanceAuditCard' || (message.display as any)?.component === 'BalanceAuditCard') && (
                    <div className="my-2">
                        <BalanceAuditCard audit={(message.display.data as any)?.audit} data={(message.display.data as any)?.audit || message.display.data as any} />
                    </div>
                )}

                {/* Typing Indicator / Processing State */}
                {isLoading && isLast && !message.content && !message.display && !message.confirmationRequired && (
                    <div className="w-full">
                        <AiProcessingState
                            className="py-2 items-start"
                            messages={[
                                "Snurrar",
                                "Kokar på en idé",
                                "Brygger ett svar",
                                "Funderar djupt",
                                "Knådar tankar"
                            ]}
                        />
                    </div>
                )}
            </div>
        )
    }

    return (
        <div className="w-full max-w-2xl mx-auto flex flex-col gap-4 py-4">
            {messages.map((message) => (
                <div
                    key={message.id}
                    className={cn(
                        "flex flex-col gap-2",
                        message.role === 'user' ? 'items-end' : 'items-start'
                    )}
                >
                    {message.role === 'user' ? (
                        <div className="max-w-[85%] flex flex-col gap-2 items-end">
                            {/* Action Trigger Chip - shown instead of text for action triggers */}
                            {message.actionTrigger ? (
                                <ActionTriggerChip
                                    display={{
                                        type: 'action-trigger',
                                        icon: message.actionTrigger.icon,
                                        title: message.actionTrigger.title,
                                        subtitle: message.actionTrigger.subtitle,
                                        meta: message.actionTrigger.meta
                                    }}
                                />
                            ) : (
                                <>
                                    {/* Text message */}
                                    {message.content && (
                                        <div className="rounded-lg px-3 py-1.5 bg-primary text-primary-foreground">
                                            <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                                        </div>
                                    )}
                                </>
                            )}
                            {/* Mentions */}
                            {message.mentions && message.mentions.length > 0 && (
                                <div className="flex flex-wrap gap-2 justify-end">
                                    {message.mentions.map((mention) => (
                                        <MentionBadge
                                            key={mention.id || mention.label}
                                            item={mention}
                                        />
                                    ))}
                                </div>
                            )}
                            {/* Attachments */}
                            {message.attachments && message.attachments.length > 0 && (
                                <div className="flex flex-wrap gap-2 justify-end">
                                    {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                                    {message.attachments.map((att: any, i: number) => (
                                        <AttachmentPreview key={att.id || att.name || `att-${i}`} attachment={att} />
                                    ))}
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="w-full max-w-[85%]">
                            <AIMessageContent
                                message={message}
                                isLast={message.id === lastMessageId}
                            />
                        </div>
                    )}

                </div>
            ))}
        </div>
    )
})

"use client"

import * as React from "react"
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command"
import { Popover, PopoverContent, PopoverAnchor } from "@/components/ui/popover"
import { FileText, Receipt, CreditCard, ScrollText, Building2, type LucideIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import { 
    PAGE_CONTEXTS, 
    PAGE_CATEGORIES, 
    getPagesByCategory, 
    searchPages,
    formatPageContextForAI,
    type PageContext, 
    type PageCategory 
} from "@/data/page-contexts"

// =============================================================================
// Types
// =============================================================================

export type MentionCategory = "faktura" | "kvitto" | "transaktion" | "konto" | "leverantor" | "page"

export interface MentionItem {
    id: string
    type: MentionCategory
    label: string
    sublabel?: string
    data?: Record<string, unknown>
    /** For page mentions, the page context */
    pageContext?: PageContext
    /** Formatted context for AI */
    aiContext?: string
}

interface MentionPopoverProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    onSelect: (item: MentionItem) => void
    searchQuery: string
    items?: MentionItem[] // Optional custom items
    anchorRef: React.RefObject<HTMLElement | null>
    position?: { top: number; left: number }
}

// Category icons for non-page items
const categoryIcons: Record<MentionCategory, LucideIcon> = {
    faktura: FileText,
    kvitto: Receipt,
    transaktion: CreditCard,
    konto: ScrollText,
    leverantor: Building2,
    page: FileText, // Default, pages use their own icons
}

// Category labels
const categoryLabels: Record<MentionCategory, string> = {
    faktura: "Fakturor",
    kvitto: "Kvitton",
    transaktion: "Transaktioner",
    konto: "Konton",
    leverantor: "Leverantörer",
    page: "Sidor",
}

// Map PageCategory to display labels
const pageCategoryLabels: Record<PageCategory, string> = {
    bokforing: "📒 Bokföring",
    rapporter: "📊 Rapporter & Deklarationer",
    loner: "💰 Löner & Personal",
    agare: "🏢 Ägare & Styrning",
    ovrigt: "⚙️ Övrigt",
}

// =============================================================================
// Component
// =============================================================================

export function MentionPopover({
    open,
    onOpenChange,
    onSelect,
    searchQuery,
    items: customItems,
    anchorRef,
}: MentionPopoverProps) {
    const [internalSearch, setInternalSearch] = React.useState("")

    // Get pages organized by category
    const pagesByCategory = React.useMemo(() => getPagesByCategory(), [])

    // Filter pages based on search
    const filteredPages = React.useMemo(() => {
        if (!internalSearch) return pagesByCategory

        const matching = searchPages(internalSearch)
        const grouped: Record<PageCategory, PageContext[]> = {
            bokforing: [],
            rapporter: [],
            loner: [],
            agare: [],
            ovrigt: [],
        }

        matching.forEach(page => {
            grouped[page.category].push(page)
        })

        return grouped
    }, [pagesByCategory, internalSearch])

    // Convert PageContext to MentionItem
    const pageToMentionItem = React.useCallback((page: PageContext): MentionItem => ({
        id: `page-${page.id}`,
        type: "page",
        label: page.title,
        sublabel: page.description.slice(0, 60) + (page.description.length > 60 ? '...' : ''),
        pageContext: page,
        aiContext: formatPageContextForAI(page),
        data: {
            url: page.url,
            capabilities: page.aiCapabilities,
            tools: page.relatedTools,
        },
    }), [])

    // Get category order
    const categoryOrder: PageCategory[] = ['bokforing', 'rapporter', 'loner', 'agare', 'ovrigt']

    // Check if we have any results
    const hasResults = categoryOrder.some(cat => filteredPages[cat].length > 0)

    return (
        <Popover open={open} onOpenChange={onOpenChange}>
            <PopoverAnchor asChild>
                <span ref={anchorRef as React.RefObject<HTMLSpanElement>} />
            </PopoverAnchor>
            <PopoverContent
                className="w-80 p-0"
                side="top"
                align="start"
                sideOffset={8}
                onOpenAutoFocus={(e) => e.preventDefault()}
            >
                <Command className="rounded-lg">
                    <CommandInput
                        placeholder="Sök sidor..."
                        value={internalSearch}
                        onValueChange={setInternalSearch}
                        className="h-9"
                    />
                    <CommandList className="max-h-80">
                        {!hasResults && (
                            <CommandEmpty>Inga sidor hittades</CommandEmpty>
                        )}

                        {categoryOrder.map(category => {
                            const pages = filteredPages[category]
                            if (pages.length === 0) return null

                            return (
                                <CommandGroup 
                                    key={category} 
                                    heading={pageCategoryLabels[category]}
                                >
                                    {pages.map((page) => {
                                        const Icon = page.icon
                                        return (
                                            <CommandItem
                                                key={page.id}
                                                value={`${page.id}:${page.title}:${page.keywords.join(' ')}`}
                                                onSelect={() => onSelect(pageToMentionItem(page))}
                                                className="flex items-start gap-2 cursor-pointer py-2"
                                            >
                                                <Icon className="h-4 w-4 text-muted-foreground shrink-0 mt-0.5" />
                                                <div className="flex-1 min-w-0">
                                                    <span className="font-medium block text-sm">{page.title}</span>
                                                    <span className="text-xs text-muted-foreground line-clamp-1">
                                                        {page.description.slice(0, 50)}...
                                                    </span>
                                                </div>
                                            </CommandItem>
                                        )
                                    })}
                                </CommandGroup>
                            )
                        })}
                    </CommandList>
                </Command>
            </PopoverContent>
        </Popover>
    )
}

// =============================================================================
// Hook to provide mentionable items
// =============================================================================

export function useMentionItems() {
    const [items, setItems] = React.useState<MentionItem[]>([])
    const [isLoading, setIsLoading] = React.useState(true)

    React.useEffect(() => {
        // Convert all pages to mention items
        const pageItems: MentionItem[] = PAGE_CONTEXTS.map(page => ({
            id: `page-${page.id}`,
            type: "page" as const,
            label: page.title,
            sublabel: page.description.slice(0, 60),
            pageContext: page,
            aiContext: formatPageContextForAI(page),
            data: {
                url: page.url,
                capabilities: page.aiCapabilities,
                tools: page.relatedTools,
            },
        }))

        setItems(pageItems)
        setIsLoading(false)
    }, [])

    return { items, isLoading }
}

// =============================================================================
// Badge component for displaying mentioned items
// =============================================================================

export function MentionBadge({
    item,
    onRemove
}: {
    item: MentionItem
    onRemove?: () => void
}) {
    // For page mentions, use the page's icon
    const Icon = item.pageContext?.icon || categoryIcons[item.type]

    return (
        <span className={cn(
            "inline-flex items-center gap-1 px-1.5 py-0.5 rounded-md text-xs font-medium",
            "bg-primary/10 text-primary border border-primary/20"
        )}>
            <Icon className="h-3 w-3" />
            <span className="truncate max-w-[120px]">{item.label}</span>
            {onRemove && (
                <button
                    onClick={onRemove}
                    className="ml-0.5 hover:text-destructive"
                >
                    ×
                </button>
            )}
        </span>
    )
}

