interface BillingItem {
    id: string
    date: string
    description: string
    amount: string
    status: "Betald" | "Obetald" | "Väntande"
    type: "subscription" | "credits"
    invoiceUrl?: string
    receiptUrl?: string
}

interface PaymentMethodInfo {
    brand: string
    last4: string
    expMonth: number
    expYear: number
}

function useBillingHistory() {
    const [items, setItems] = useState<BillingItem[]>([])
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethodInfo | null>(null)
    const [loading, setLoading] = useState(true)

    const fetch_ = useCallback(async () => {
        try {
            const response = await fetch("/api/stripe/billing-history")
            if (response.ok) {
                const data = await response.json()
                setItems(data.items || [])
                setPaymentMethod(data.paymentMethod || null)
            }
        } catch (error) {
            console.error("[Billing] Failed to fetch billing history:", error)
        } finally {
            setLoading(false)
        }
    }, [])

    useEffect(() => { fetch_() }, [fetch_])

    return { items, paymentMethod, loading }
}

