import { useModel } from "@/providers/model-provider"
import { ChatInput } from "@/components/ai/chat-input"
import { ChatMessageList } from "@/components/ai/chat-message-list"
import { BuyCreditsDialog } from "@/components/billing"
import { type MentionItem } from "@/components/ai/mention-popover"
import { getGreeting } from "@/lib/chat-utils"
import { Plus, MessageSquare } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
    SidebarGroup,
    SidebarGroupContent,
    SidebarMenu,
    SidebarMenuItem,
    SidebarMenuButton,
    useSidebar,
} from "@/components/ui/sidebar"
import { type SidebarMode } from "./app-sidebar"
import { AI_CHAT_EVENT, type PageContext, consumePendingAIContext } from "@/lib/ai/context"

interface AIChatSidebarProps {
    mode?: SidebarMode
    onModeChange?: (mode: SidebarMode) => void
}

export function AIChatSidebar({ }: AIChatSidebarProps) {
    const { state } = useSidebar()
    const isCollapsed = state === "collapsed"
    const { modelId } = useModel()
    const { canAfford, refresh: refreshUsage } = useAIUsage()
    const { isDemo, isPaid } = useSubscription()

    const {
        conversations,
        currentConversationId,
        messages,
        isLoading,
        sendMessage,
        regenerateResponse,
        startNewConversation,
        loadConversation,
        deleteMessage,
    } = useChat()

    const [textareaValue, setTextareaValue] = useState("")
    const [mentionItems, setMentionItems] = useState<MentionItem[]>([])
    const [attachedFiles, setAttachedFiles] = useState<File[]>([])
    const [showHistory, setShowHistory] = useState(false)
    const [isInputFocused, setIsInputFocused] = useState(false)
    const [showBuyCredits, setShowBuyCredits] = useState(false)
    const messagesEndRef = useRef<HTMLDivElement>(null)

    // Scroll to bottom when messages change
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, [messages])

    const handleSend = useCallback(() => {
        // Check if user can afford this request (Pro users only)
        if (isPaid && !canAfford(modelId)) {
            setShowBuyCredits(true)
            return
        }

        const content = textareaValue
        const files = [...attachedFiles]
        const mentions = [...mentionItems]

        setTextareaValue("")
        setAttachedFiles([])
        setMentionItems([])

        sendMessage({
            content,
            files,
            mentions
        })

        // Refresh usage after sending
        setTimeout(() => refreshUsage(), 2000)
    }, [textareaValue, attachedFiles, mentionItems, sendMessage, isPaid, canAfford, modelId, refreshUsage])

    const handleCancelConfirmation = useCallback((messageId: string) => {
        deleteMessage(messageId)
    }, [deleteMessage])

    const handleNewConversation = useCallback(() => {
        startNewConversation()
        setTextareaValue("")
        setMentionItems([])
        setAttachedFiles([])
        setShowHistory(false)
    }, [startNewConversation])

    // Handle incoming AI context (from event or pending)
    const handleAIContextRef = useRef((context: PageContext) => { })
    useEffect(() => {
        handleAIContextRef.current = (context: PageContext) => {
            startNewConversation()
            if (context.autoSend) {
                sendMessage({
                    content: context.initialPrompt,
                    actionTrigger: context.actionTrigger
                })
            } else {
                setTextareaValue(context.initialPrompt)
            }
            setShowHistory(false)
        }
    })

    // On mount, check for pending context (set before this component mounted)
    const mountedRef = useRef(false)
    useEffect(() => {
        if (mountedRef.current) return
        mountedRef.current = true
        const pending = consumePendingAIContext()
        if (pending) {
            handleAIContextRef.current(pending)
        }
    }, [])

    // Listen for global events to trigger chat actions
    useEffect(() => {
        const handleOpenAIChat = (e: Event) => {
            // If there's pending context, it was already handled by mount effect
            const pending = consumePendingAIContext()
            if (pending) {
                // Already handled or handle now
                handleAIContextRef.current(pending)
                return
            }
            const context = (e as CustomEvent).detail as PageContext
            if (context) {
                handleAIContextRef.current(context)
            }
        }

        const handleLoadConversation = (e: Event) => {
            const conversationId = (e as CustomEvent).detail as string
            if (conversationId) {
                loadConversation(conversationId)
                setShowHistory(false)
            }
        }

        const handleShowHistory = () => {
            setShowHistory(true)
        }

        const onNewConversationEvent = () => {
            startNewConversation()
            setTextareaValue("")
            setMentionItems([])
            setAttachedFiles([])
            setShowHistory(false)
        }

        // Handle focus input event from AI dialog edit button
        const handleFocusInput = (e: Event) => {
            const detail = (e as CustomEvent<{ prefill?: string }>).detail
            setShowHistory(false)

            // Set prefill value if provided
            if (detail?.prefill) {
                setTextareaValue(detail.prefill)
            }

            // Focus the textarea after a short delay to ensure DOM is ready
            setTimeout(() => {
                const textarea = document.querySelector('[data-ai-chat-input]') as HTMLTextAreaElement
                if (textarea) {
                    textarea.focus()
                    // Move cursor to end
                    textarea.setSelectionRange(textarea.value.length, textarea.value.length)
                }
            }, 100)
        }

        window.addEventListener(AI_CHAT_EVENT, handleOpenAIChat)
        window.addEventListener("load-conversation", handleLoadConversation)
        window.addEventListener("ai-chat-show-history", handleShowHistory)
        window.addEventListener("ai-chat-new-conversation", onNewConversationEvent)
        window.addEventListener("ai-chat-focus-input", handleFocusInput)

        return () => {
            window.removeEventListener(AI_CHAT_EVENT, handleOpenAIChat)
            window.removeEventListener("load-conversation", handleLoadConversation)
            window.removeEventListener("ai-chat-show-history", handleShowHistory)
            window.removeEventListener("ai-chat-new-conversation", onNewConversationEvent)
            window.removeEventListener("ai-chat-focus-input", handleFocusInput)
        }
    }, [loadConversation])

    // When collapsed, show only icons
    if (isCollapsed) {
        return (
            <SidebarGroup className="flex-1 flex flex-col">
                <SidebarMenu>
                    <SidebarMenuItem>
                        <SidebarMenuButton
                            tooltip="Ny chatt"
                            onClick={handleNewConversation}
                        >
                            <Plus className="h-5 w-5" />
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                    <SidebarMenuItem>
                        <SidebarMenuButton
                            tooltip="Visa historik"
                            onClick={() => setShowHistory(!showHistory)}
                        >
                            <MessageSquare className="h-5 w-5" />
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                </SidebarMenu>
            </SidebarGroup>
        )
    }

    // History view
    if (showHistory) {
        return (
            <SidebarGroup className="flex-1 flex flex-col overflow-hidden">
                <div className="flex items-center justify-between px-2 py-2">
                    <span className="text-sm font-medium">Konversationer</span>
                    <Button
                        variant="ghost"
                        size="icon"
                        className="h-7 w-7"
                        onClick={() => setShowHistory(false)}
                    >
                        <Plus className="h-4 w-4" />
                    </Button>
                </div>
                <SidebarGroupContent className="flex-1 overflow-y-auto">
                    {conversations.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground text-sm">
                            Inga konversationer ännu
                        </div>
                    ) : (
                        <SidebarMenu>
                            {conversations.slice(0, 10).map((conv) => (
                                <SidebarMenuItem key={conv.id}>
                                    <SidebarMenuButton
                                        isActive={conv.id === currentConversationId}
                                        onClick={() => {
                                            loadConversation(conv.id)
                                            setShowHistory(false)
                                        }}
                                    >
                                        <MessageSquare className="h-4 w-4" />
                                        <span className="truncate">{conv.title}</span>
                                    </SidebarMenuButton>
                                </SidebarMenuItem>
                            ))}
                        </SidebarMenu>
                    )}
                </SidebarGroupContent>
            </SidebarGroup>
        )
    }

    // Chat view
    return (
        <SidebarGroup className="flex-1 flex flex-col overflow-hidden gap-2 -mt-0.5">
            {/* Main Chat Container */}
            <div className="flex-1 flex flex-col min-h-0 bg-sidebar-accent rounded-lg overflow-hidden">
                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto px-3">
                    {messages.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center py-8">
                            {/* Interactive Pixel Art Dog - click to hop, smiles when input focused */}
                            <div
                                className="mb-4 cursor-pointer"
                                onClick={(e) => {
                                    const dog = e.currentTarget.querySelector('svg')
                                    if (dog) {
                                        dog.classList.add('animate-bounce')
                                        setTimeout(() => dog.classList.remove('animate-bounce'), 500)
                                    }
                                }}
                            >
                                <svg width="48" height="48" viewBox="0 0 16 16" shapeRendering="crispEdges">
                                    {/* Ears */}
                                    <rect x="2" y="2" width="2" height="3" className="fill-amber-600 dark:fill-amber-500" />
                                    <rect x="12" y="2" width="2" height="3" className="fill-amber-600 dark:fill-amber-500" />
                                    {/* Head */}
                                    <rect x="3" y="4" width="10" height="6" className="fill-amber-400 dark:fill-amber-300" />
                                    {/* Face markings */}
                                    <rect x="5" y="5" width="6" height="4" className="fill-amber-100 dark:fill-amber-50" />
                                    {/* Eyes - open when not focused */}
                                    {!isInputFocused && (
                                        <>
                                            <rect x="5" y="6" width="2" height="2" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="9" y="6" width="2" height="2" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="5" y="6" width="1" height="1" className="fill-white" />
                                            <rect x="9" y="6" width="1" height="1" className="fill-white" />
                                        </>
                                    )}
                                    {/* Closed Eyes (^ ^) - when input focused */}
                                    {isInputFocused && (
                                        <>
                                            {/* Left Eye ^ */}
                                            <rect x="5" y="7" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="6" y="6" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="7" y="7" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                            {/* Right Eye ^ */}
                                            <rect x="9" y="7" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="10" y="6" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                            <rect x="11" y="7" width="1" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                        </>
                                    )}
                                    {/* Nose */}
                                    <rect x="7" y="8" width="2" height="1" className="fill-gray-800 dark:fill-gray-900" />
                                    {/* Tongue */}
                                    <rect x="7" y="9" width="2" height="1" className="fill-pink-400" />
                                    {/* Body */}
                                    <rect x="4" y="10" width="8" height="4" className="fill-amber-400 dark:fill-amber-300" />
                                    {/* Chest */}
                                    <rect x="6" y="10" width="4" height="3" className="fill-amber-100 dark:fill-amber-50" />
                                    {/* Tail */}
                                    <rect x="12" y="11" width="2" height="2" className="fill-amber-600 dark:fill-amber-500" />
                                    {/* Feet */}
                                    <rect x="4" y="14" width="2" height="1" className="fill-amber-600 dark:fill-amber-500" />
                                    <rect x="10" y="14" width="2" height="1" className="fill-amber-600 dark:fill-amber-500" />
                                </svg>
                            </div>
                            <p className="text-sm font-medium">{getGreeting()}!</p>
                            <p className="text-xs text-muted-foreground mt-1">
                                Hur kan jag hjälpa dig?
                            </p>
                        </div>
                    ) : (
                        <div className="space-y-4 py-4">
                            <ChatMessageList
                                messages={messages}
                                isLoading={isLoading}
                                onRetry={(id) => sendMessage({ retryMessageId: id, content: '' })}
                                onConfirm={(id) => sendMessage({ confirmationId: id, content: '' })}
                                onCancelConfirmation={handleCancelConfirmation}
                                onRegenerate={regenerateResponse}
                            />
                            <div ref={messagesEndRef} />
                        </div>
                    )}
                </div>

                {/* Chat Input Area */}
                <div className="shrink-0 p-3 pt-0 bg-transparent">
                    <ChatInput
                        value={textareaValue}
                        onChange={setTextareaValue}
                        onSend={handleSend}
                        isLoading={isLoading}
                        files={attachedFiles}
                        onFilesChange={setAttachedFiles}
                        mentions={mentionItems}
                        onMentionsChange={setMentionItems}
                        showNavLinks={false}
                        onFocus={() => setIsInputFocused(true)}
                        onBlur={() => setIsInputFocused(false)}
                    />

                    {/* Disclaimer */}
                    <div className="px-2 pt-2 text-center">
                        <p className="text-[10px] text-muted-foreground/60">
                            Scope AI kan göra misstag. Kontrollera viktig information.
                        </p>
                    </div>
                </div>
            </div>

            {/* Out of tokens dialog */}
            <BuyCreditsDialog
                open={showBuyCredits}
                onOpenChange={setShowBuyCredits}
                outOfTokens
            />
        </SidebarGroup>
    )
}

"use client"


import * as React from "react"
import { PanelLeft, Sparkles, type LucideIcon, Settings2, LayoutGrid } from "lucide-react"

import { NavSettings, NavCollapsibleSection, NavAIConversations } from "./sidebar"
import { UserTeamSwitcher } from "./user-team-switcher"
import { AIChatSidebar } from "./ai-chat-sidebar"
import { useRouter, usePathname, useSearchParams } from "next/navigation"
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuItem,
  SidebarMenuButton,
  SidebarMenuAction,
  useSidebar,
} from "@/components/ui/sidebar"
import { SettingsDialog } from "@/components/installningar/settings-dialog"
import { SidebarModeDropdown } from "./sidebar-mode-dropdown"
import { AI_CHAT_EVENT, type PageContext } from "@/lib/ai/context"
import { useAuth } from "@/hooks/use-auth"

// Import data from the data layer
import {
  navBokforing,
  navRapporter,
  navLoner,
  navAgare,
  navSettings
} from "../../data/app-navigation"
import { getTeams } from "@/services/navigation"
import { Building2, Box } from "lucide-react"

// Default team based on company provider
const defaultTeam = {
  id: 'default',
  name: 'Mitt Företag',
  logo: Building2,
  plan: 'Free',
}

export type SidebarMode = "navigation" | "ai-chat"

interface AppSidebarProps extends Omit<React.ComponentProps<typeof Sidebar>, "variant"> {
  /** 'sidebar' shows full navigation, 'minimal' shows empty sidebar with custom header */
  variant?: "sidebar" | "floating" | "minimal" | "inset"
  /** Custom header config for minimal variant */
  minimalHeader?: {
    icon?: LucideIcon
    iconClassName?: string
    title: string
    subtitle?: string
  }
  /** Mode of the sidebar (controlled) */
  mode?: SidebarMode
  /** Callback when mode changes */
  onModeChange?: (mode: SidebarMode) => void
}



export function AppSidebar({
  variant = "sidebar",
  minimalHeader,
  mode,
  onModeChange,
  ...props
}: AppSidebarProps) {
  const router = useRouter()
  const pathname = usePathname()
  const searchParams = useSearchParams()
  const settingsParam = searchParams?.get("settings")
  const { state, toggleSidebar } = useSidebar()
  const { user } = useAuth()

  // Build user object from auth, with fallbacks
  const currentUser = {
    name: user?.user_metadata?.full_name || user?.email?.split('@')[0] || 'Användare',
    email: user?.email || '',
    avatar: user?.user_metadata?.avatar_url || '',
  }

  // Teams state - fetched from API
  const [teams, setTeams] = React.useState([defaultTeam])

  React.useEffect(() => {
    getTeams().then(response => {
      if (response.success && response.data && response.data.length > 0) {
        // Map teams to include logo icons
        const mappedTeams = response.data.map((team, i) => ({
          id: team.id || `team-${i}`,
          name: team.name,
          logo: i === 0 ? Box : Building2,
          plan: team.plan || 'Free',
        }))
        setTeams(mappedTeams)
      }
    }).catch(console.error)
  }, [])

  // Sidebar mode state (internal state for uncontrolled)
  const [internalMode, setInternalMode] = React.useState<SidebarMode>("navigation")

  // Use controlled mode if provided, otherwise internal
  const sidebarMode = mode ?? internalMode

  // State for settings dialog
  const [settingsOpen, setSettingsOpen] = React.useState(!!settingsParam)

  // Sync state with URL param
  React.useEffect(() => {
    setSettingsOpen(!!settingsParam)
  }, [settingsParam])

  // Handle opening settings (pushes to history for back button support)
  const handleOpenSettings = React.useCallback(() => {
    const params = new URLSearchParams(searchParams?.toString())
    params.set("settings", "Konto") // Default tab
    router.push(`${pathname}?${params.toString()}`)
  }, [router, pathname, searchParams])

  // Handle dialog state change
  const handleSettingsOpenChange = (open: boolean) => {
    if (!open && settingsParam) {
      const params = new URLSearchParams(searchParams?.toString())
      params.delete("settings")
      router.replace(`${pathname}?${params.toString()}`)
    } else if (open && !settingsParam) {
      handleOpenSettings()
    }
    setSettingsOpen(open)
  }

  // Store pending AI context when mode switches
  const pendingAIContextRef = React.useRef<PageContext | null>(null)

  // Handle global AI chat events
  React.useEffect(() => {
    const handleOpenAIChat = (e: Event) => {
      const context = (e as CustomEvent).detail as PageContext

      // Store context to re-dispatch after sidebar mounts
      if (context) {
        pendingAIContextRef.current = context
      }

      setInternalMode("ai-chat")
      if (onModeChange) onModeChange("ai-chat")

      // If already in ai-chat mode, the sidebar is mounted and will handle it
      // If switching modes, we need to wait for mount then re-dispatch
      if (sidebarMode !== "ai-chat" && context) {
        // Re-dispatch after a short delay to allow sidebar to mount
        setTimeout(() => {
          if (pendingAIContextRef.current) {
            window.dispatchEvent(new CustomEvent(AI_CHAT_EVENT, {
              detail: pendingAIContextRef.current
            }))
            pendingAIContextRef.current = null
          }
        }, 100)
      }
    }

    const handleLoadConversation = () => {
      setInternalMode("ai-chat")
      if (onModeChange) onModeChange("ai-chat")
    }

    window.addEventListener(AI_CHAT_EVENT, handleOpenAIChat)
    window.addEventListener("load-conversation", handleLoadConversation)

    return () => {
      window.removeEventListener(AI_CHAT_EVENT, handleOpenAIChat)
      window.removeEventListener("load-conversation", handleLoadConversation)
    }
  }, [onModeChange])

  // Default minimal header for AI workspace style
  const header = minimalHeader ?? {
    icon: Sparkles,
    iconClassName: "text-purple-500",
    title: "AI Workspace",
    subtitle: "Ditt AI-verktyg"
  }
  const HeaderIcon = header.icon ?? Sparkles

  if (variant === "minimal") {
    return (
      <Sidebar {...props} collapsible="icon">
        <SidebarHeader>
          <SidebarMenu>
            <SidebarMenuItem>
              <SidebarMenuButton
                size="lg"
                className="data-[state=open]:bg-sidebar-accent data-[state=open]:text-sidebar-accent-foreground cursor-default hover:bg-transparent"
                onClick={() => {
                  if (state === "collapsed") {
                    toggleSidebar()
                  }
                }}
              >
                <div className="flex aspect-square size-8 items-center justify-center rounded-lg bg-purple-100 dark:bg-purple-900/30">
                  <HeaderIcon className={`size-4 ${header.iconClassName ?? "text-purple-500"}`} />
                </div>
                <div className="grid flex-1 text-left text-sm leading-tight">
                  <span className="truncate font-semibold">{header.title}</span>
                  {header.subtitle && (
                    <span className="truncate text-xs text-muted-foreground">{header.subtitle}</span>
                  )}
                </div>
              </SidebarMenuButton>
              <SidebarMenuAction
                showOnHover
                className="cursor-pointer"
                onClick={(e) => {
                  e.stopPropagation()
                  toggleSidebar()
                }}
              >
                <PanelLeft />
                <span className="sr-only">Toggle Sidebar</span>
              </SidebarMenuAction>
            </SidebarMenuItem>
          </SidebarMenu>
        </SidebarHeader>
        <SidebarContent>
          {/* Empty - minimal variant has no navigation */}
        </SidebarContent>
      </Sidebar>
    )
  }
  // Determine sidebar variant to pass to underlying Sidebar
  // Note: 'minimal' is handled above with early return, so variant is always a valid Sidebar variant here
  const sidebarVariant = variant as "sidebar" | "floating" | "inset"

  return (
    <>
      <SettingsDialog
        open={settingsOpen}
        onOpenChange={handleSettingsOpenChange}
        defaultTab={settingsParam || undefined}
      />
      <Sidebar
        collapsible="offcanvas"
        variant={sidebarVariant}
        className={`[&_*]:!border-0 [&_[data-slot=sidebar-inner]]:shadow-none ${sidebarMode === "ai-chat"
          ? "[--sidebar-width:380px] xl:[--sidebar-width:440px] 2xl:[--sidebar-width:500px]"
          : "[--sidebar-width:340px] xl:[--sidebar-width:380px] 2xl:[--sidebar-width:420px]"
          }`}
        {...props}
      >
        <SidebarHeader className="p-0 px-2 pt-1">
          <SidebarModeDropdown mode={sidebarMode} onModeChange={onModeChange || setInternalMode} />
        </SidebarHeader>

        <SidebarContent>
          {sidebarMode === "navigation" ? (
            <>
              {/* Section header for modules */}
              <div className="px-4 pt-4 pb-1 flex items-center gap-1.5">
                <LayoutGrid className="h-4 w-4 text-muted-foreground/70" />
                <span className="text-xs font-medium text-muted-foreground/70">Moduler</span>
              </div>

              {/* Collapsible navigation items */}
              <NavCollapsibleSection
                items={navBokforing}
                label="Bokföring"
                storageKey="bokforing"
              />
              <NavCollapsibleSection
                items={navLoner}
                label="Löner"
                storageKey="loner"
              />
              <NavCollapsibleSection
                items={navRapporter}
                label="Rapporter"
                storageKey="rapporter"
              />
              <NavCollapsibleSection
                items={navAgare}
                label="Ägare & Styrning"
                storageKey="agare"
              />

              {/* AI Conversations section - fills middle space */}
              <NavAIConversations />

              {/* Settings section at bottom - simple header style */}
              <NavSettings items={navSettings} onSettingsClick={handleOpenSettings} icon={Settings2} />
            </>
          ) : (
            <AIChatSidebar mode={sidebarMode} onModeChange={onModeChange || setInternalMode} />
          )}
        </SidebarContent>

        {sidebarMode === "navigation" && (
          <SidebarFooter>
            <UserTeamSwitcher user={currentUser} teams={teams} />
          </SidebarFooter>
        )}


      </Sidebar>

    </>
  )
}

