                                    defaultOpen={false}
                                    onRowClick={handleRowClick}
                                />

                                {/* Löneväxling */}
                                <BenefitSection
                                    title="Löneväxling"
                                    benefits={groupedBenefits.salarySacrifice}
                                    assignedBenefits={assignedBenefits}
                                    totalEmployees={stats.totalEmployees}
                                    defaultOpen={false}
                                    onRowClick={handleRowClick}
                                />
                            </div>
                        </div>
                    </>
                )}

                <BenefitDetailsDialog
                    benefit={selectedBenefit}
                    open={isDetailsOpen}
                    onOpenChange={setIsDetailsOpen}
                    onAssign={handleAssign}
                    assignedEmployees={assignedBenefits}
                />
            </div>
        </SectionErrorBoundary>
    )
}

import { useState } from "react"
import { useToast } from "@/components/ui/toast"
import { useCompany } from "@/providers"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Info } from "lucide-react"
import { type Partner } from "@/types/ownership"

interface NewWithdrawalDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  partners: Partner[]
  onSave: (
    type: 'uttag' | 'lön' | 'insättning', 
    partnerId: string, 
    amount: number, 
    date: string, 
    description: string
  ) => Promise<void>
}

export function NewWithdrawalDialog({ open, onOpenChange, partners, onSave }: NewWithdrawalDialogProps) {
  const toast = useToast()
  const { company } = useCompany()

  const [newType, setNewType] = useState<'uttag' | 'insättning' | 'lön'>('uttag')
  const [newPartnerId, setNewPartnerId] = useState<string>("")
  const [newAmount, setNewAmount] = useState("")
  const [newDate, setNewDate] = useState(new Date().toISOString().split('T')[0])
  const [newDesc, setNewDesc] = useState("")
  const [isSubmitting, setIsSubmitting] = useState(false)

  const handleSave = async () => {
    if (!newPartnerId || !newAmount || !newDesc) {
      toast.error("Saknas uppgifter", "Vänligen fyll i alla fält")
      return
    }

    try {
      setIsSubmitting(true)
      await onSave(newType, newPartnerId, parseFloat(newAmount), newDate, newDesc)
      toast.success("Transaktion sparad", "Transaktionen har bokförts.")

      // Reset
      setNewAmount("")
      setNewDesc("")
      setNewPartnerId("")
      onOpenChange(false)
    } catch (error) {
      toast.error("Något gick fel", "Kunde inte spara transaktionen.")
      console.error(error)
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle>Registrera händelse</DialogTitle>
          <DialogDescription>
            Bokför ett nytt uttag, insättning eller löneutbetalning.
          </DialogDescription>
        </DialogHeader>
        <div className="grid gap-4 py-4">
          <div className="grid grid-cols-3 gap-2">
             {['uttag', 'insättning', 'lön'].map((t) => (
               <Button
                 key={t}
                 variant={newType === t ? "default" : "outline"}
                 className="w-full capitalize"
                 // eslint-disable-next-line @typescript-eslint/no-explicit-any
                 onClick={() => setNewType(t as any)}
               >
                 {t}
               </Button>
             ))}
          </div>
          <div className="space-y-2">
            <Label>Delägare</Label>
            <select 
               className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
               value={newPartnerId}
               onChange={(e) => setNewPartnerId(e.target.value)}
            >
               <option value="" disabled>Välj delägare</option>
               {partners.map(p => (
                  <option key={p.id} value={p.id}>{p.name}</option>
               ))}
            </select>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Datum</Label>
              <Input 
                 type="date" 
                 value={newDate}
                 onChange={(e) => setNewDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Belopp (kr)</Label>
              <Input 
                 type="number" 
                 placeholder="0.00"
                 value={newAmount}
                 onChange={(e) => setNewAmount(e.target.value)}
              />
            </div>
          </div>
          <div className="space-y-2">
            <Label>Beskrivning</Label>
            <Input
               placeholder="T.ex. Privatuttag november"
               value={newDesc}
               onChange={(e) => setNewDesc(e.target.value)}
            />
          </div>

          {/* Bank instruction info */}
          {newType === 'uttag' && newAmount && (
            <div className="rounded-lg border bg-blue-50 dark:bg-blue-900/20 p-3 space-y-2">
              <div className="flex items-center gap-2 text-sm font-medium">
                <Info className="h-4 w-4 text-blue-600" />
                <span>Utbetalningsinstruktion</span>
              </div>
              <div className="text-xs text-muted-foreground space-y-1 pl-6">
                <p>Överför <strong>{parseFloat(newAmount).toLocaleString('sv-SE')} kr</strong> från företagets konto till delägarens privatkonto.</p>
                <p>Ange &quot;{newDesc || 'Privatuttag'}&quot; som meddelande i bankens överföring.</p>
                <p className="text-amber-600 dark:text-amber-400">Verifikation skapas automatiskt i bokföringen vid spara.</p>
              </div>
            </div>
          )}
        </div>
        <DialogFooter>
          <Button variant="ghost" onClick={() => onOpenChange(false)}>Avbryt</Button>
          <Button onClick={handleSave} disabled={isSubmitting}>Spara transaktion</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState, useEffect, useMemo, useCallback } from "react"
import { useToast } from "@/components/ui/toast"
import { useVerifications } from "@/hooks/use-verifications"
import { useAllTaxRates } from "@/hooks/use-tax-parameters"
import { taxService } from "@/services/tax-service"

export interface AiDeduction {
    label: string
    amount: number
}

export interface ChatMessage {
    role: "user" | "ai"
    text: string
}

export interface Payslip {
    id: string | number
    employee: string
    period: string
    grossSalary: number
    netSalary: number
    tax: number
    status: string
    paymentDate?: string
}

export interface PayslipCreateDialogProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    onPayslipCreated: (payslip: Payslip) => void
    currentPeriod: string
}

export interface PayslipEmployee {
    id: string
    name: string
    role: string
    lastSalary: number
    taxRate: number
    personalNumber?: string
    employmentType?: string
    taxTable?: number
    taxColumn?: number
    pensionRate?: number // Tjänstepension as decimal (e.g. 0.045 = 4.5%)
    kommun?: string // Folkbokföringskommun — determines kommunalskatt
}

export interface ManualPersonData {
    name: string
    role: string
    salary: number
    personalNumber: string
    employmentType: string
    taxRate: string
    kommun: string        // Folkbokföringskommun
    pensionRate: string   // Tjänstepension % (default "4.5")
    fackavgift: string    // Union fee kr/month (default "0")
    akassa: string        // A-kassa kr/month (default "0")
}

export function useCreatePayslipLogic({
    open,
    onOpenChange,
    onPayslipCreated,
    currentPeriod
}: PayslipCreateDialogProps) {
    const toast = useToast()
    const { addVerification } = useVerifications()
    const { rates: taxRates } = useAllTaxRates(new Date().getFullYear())

    const [employees, setEmployees] = useState<PayslipEmployee[]>([])
    const [isLoadingEmployees, setIsLoadingEmployees] = useState(true)
    const [selectedEmployee, setSelectedEmployee] = useState<string | null>(null)
    const [chatInput, setChatInput] = useState("")
    const [chatMessages, setChatMessages] = useState<ChatMessage[]>([])
    const [useAIRecommendation, setUseAIRecommendation] = useState(true)
    const [customSalary, setCustomSalary] = useState("")
    const [aiDeductions, setAiDeductions] = useState<AiDeduction[]>([])
    const [isCreating, setIsCreating] = useState(false)

    // New states for manual person entry
    const [useManualEntry, setUseManualEntry] = useState(false)
    // Default tax rate derives from system_parameters (marginalTaxRateApprox)
    const defaultTaxPercent = taxRates ? String(Math.round(taxRates.marginalTaxRateApprox * 100)) : "32"
    const [manualPerson, setManualPerson] = useState<ManualPersonData>({ name: "", role: "", salary: 0, personalNumber: "", employmentType: "tillsvidare", taxRate: defaultTaxPercent, kommun: "", pensionRate: "4.5", fackavgift: "0", akassa: "0" })
    const [saveAsEmployee, setSaveAsEmployee] = useState(true)
    const [searchQuery, setSearchQuery] = useState("")

    // Fetch real employees
    useEffect(() => {
        const fetchEmployees = async () => {
            setIsLoadingEmployees(true)
            try {
                const res = await fetch('/api/employees')
                const data = await res.json()
                if (data.employees) {
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    const fallbackRate = taxRates?.marginalTaxRateApprox ?? 0.32
                    setEmployees(data.employees.map((e: any): PayslipEmployee => ({
                        id: e.id,
                        name: e.name,
                        role: e.role,
                        lastSalary: Number(e.monthly_salary),
                        taxRate: Number(e.tax_rate) || fallbackRate,
                        personalNumber: e.personal_number || undefined,
                        employmentType: e.employment_type || undefined,
                        taxTable: e.tax_table ? Number(e.tax_table) : undefined,
                        taxColumn: e.tax_column ? Number(e.tax_column) : undefined,
                        pensionRate: e.pension_rate ? Number(e.pension_rate) : 0.045, // Default ITP1 4.5%
                        kommun: e.kommun || undefined,
                    })))
                }
            } catch (err) {
                console.error("Failed to fetch employees:", err)
            } finally {
                setIsLoadingEmployees(false)
            }
        }
        if (open) fetchEmployees()
    }, [open])

    // Filter employees by search query
    const filteredEmployees = useMemo(() => {
        if (!searchQuery.trim()) return employees
        const query = searchQuery.toLowerCase()
        return employees.filter(e =>
            e.name.toLowerCase().includes(query) ||
            e.role.toLowerCase().includes(query)
        )
    }, [employees, searchQuery])

    // selectedEmp can be either from database or manual entry
    const selectedEmp: PayslipEmployee | null = useManualEntry
        ? (manualPerson.name && manualPerson.salary > 0
            ? {
                id: 'manual',
                name: manualPerson.name,
                role: manualPerson.role,
                lastSalary: manualPerson.salary,
                taxRate: (parseFloat(manualPerson.taxRate) || parseFloat(defaultTaxPercent)) / 100,
                personalNumber: manualPerson.personalNumber || undefined,
                employmentType: manualPerson.employmentType || undefined,
                pensionRate: (parseFloat(manualPerson.pensionRate) || 4.5) / 100,
                kommun: manualPerson.kommun || undefined,
            }
            : null)
        : employees.find(e => e.id === selectedEmployee) || null

    const totalDeductions = aiDeductions.reduce((sum, d) => sum + d.amount, 0)
    const recommendedSalary = selectedEmp ? selectedEmp.lastSalary - totalDeductions : 0
    const finalSalary = useAIRecommendation ? recommendedSalary : (parseInt(customSalary) || recommendedSalary)
    const taxRate = selectedEmp?.taxRate || (taxRates?.marginalTaxRateApprox ?? 0.32)

    // SKV tax table lookup (SFL 11 kap)
    const [skvTaxDeduction, setSkvTaxDeduction] = useState<number | null>(null)
    const [taxMethod, setTaxMethod] = useState<'table' | 'flat'>('flat')

    const lookupSkvTax = useCallback(async (emp: PayslipEmployee, salary: number) => {
        if (!emp.taxTable || salary <= 0) {
            setSkvTaxDeduction(null)
            setTaxMethod('flat')
            return
        }
        const year = new Date().getFullYear()
        const result = await taxService.lookupTaxDeduction(
            year,
            emp.taxTable,
            emp.taxColumn || 1,
            salary
        )
        if (result !== null) {
            setSkvTaxDeduction(result)
            setTaxMethod('table')
        } else {
            setSkvTaxDeduction(null)
            setTaxMethod('flat')
        }
    }, [])

    // Re-lookup when employee or salary changes
    useEffect(() => {
        if (selectedEmp && finalSalary > 0) {
            lookupSkvTax(selectedEmp, finalSalary)
        }
    }, [selectedEmp, finalSalary, lookupSkvTax])

    // Use SKV table deduction if available, otherwise fall back to flat rate
    const tax = taxMethod === 'table' && skvTaxDeduction !== null
        ? skvTaxDeduction
        : Math.round(finalSalary * taxRate)

    // Employee deductions (reduce net pay)
    const fackavgift = useManualEntry ? (parseFloat(manualPerson.fackavgift) || 0) : 0
    const akassa = useManualEntry ? (parseFloat(manualPerson.akassa) || 0) : 0
    const netSalary = finalSalary - tax - fackavgift - akassa

    // Derive age from personnummer for age-based employer contributions
    const getAgeFromPersonnummer = (pnr?: string): number | null => {
        if (!pnr || pnr.length < 8) return null
        const digits = pnr.replace(/\D/g, '')
        if (digits.length < 8) return null
        const birthYear = parseInt(digits.substring(0, 4))
        if (birthYear < 1900 || birthYear > 2100) return null
        return new Date().getFullYear() - birthYear
    }

    // Legal breakdown for lönespecifikation
    const employeeAge = getAgeFromPersonnummer(selectedEmp?.personalNumber)
    const isSenior = employeeAge !== null && employeeAge >= 66
    const employerContributionRate = taxRates
        ? (isSenior ? taxRates.employerContributionRateSenior : taxRates.employerContributionRate)
        : 0
    const sempioneersattning = Math.round(finalSalary * (taxRates?.vacationPayRate ?? 0))
    const employerContribution = Math.round(finalSalary * employerContributionRate)
    const pensionRate = selectedEmp?.pensionRate || 0.045 // Default ITP1 4.5%
    const pension = Math.round(finalSalary * pensionRate) // Employer cost
    const totalEmployerCost = finalSalary + employerContribution + pension

    // Check if can proceed from step 1
    const canProceedFromStep1 = useManualEntry
        ? (manualPerson.name.trim().length > 0 && manualPerson.salary > 0)
        : selectedEmployee !== null

    const resetDialog = () => {
        setSelectedEmployee(null)
        setChatInput("")
        setChatMessages([])
        setUseAIRecommendation(true)
        setCustomSalary("")
        setAiDeductions([])
        setIsCreating(false)
        // Reset manual entry states
        setUseManualEntry(false)
        setManualPerson({ name: "", role: "", salary: 0, personalNumber: "", employmentType: "tillsvidare", taxRate: defaultTaxPercent, kommun: "", pensionRate: "4.5", fackavgift: "0", akassa: "0" })
        setSaveAsEmployee(true)
        setSearchQuery("")
    }

    const handleSendMessage = () => {
        if (!chatInput.trim()) return

        setChatMessages(prev => [...prev, { role: "user", text: chatInput }])

        // Simulate AI response
        setTimeout(() => {
            const input = chatInput.toLowerCase()
            let response = "Jag har noterat det. Något annat som påverkar lönen?"
            const newDeductions: AiDeduction[] = []

            if (input.includes("sjuk")) {
                const days = parseInt(input.match(/(\d+)/)?.[1] || "1")
                const dailyRate = (selectedEmp?.lastSalary || 0) / 21
                // Day 1 = karensdag (full deduction), day 2-14 = 80% sjuklön from employer
                const karensDeduction = Math.round(dailyRate) // 1 karensdag
                const sickPayDays = Math.max(0, days - 1)
                const sickDeduction = Math.round(dailyRate * sickPayDays * 0.2) // Employer pays 80%, deduct 20%
                const totalSickDeduction = karensDeduction + sickDeduction
                newDeductions.push({ label: `Sjukavdrag (${days} dag${days > 1 ? 'ar' : ''}, 1 karensdag)`, amount: totalSickDeduction })
                response = `Noterat ${days} sjukdag${days > 1 ? 'ar' : ''}. 1 karensdag + ${sickPayDays} dag${sickPayDays !== 1 ? 'ar' : ''} sjuklön (80%). Avdrag: ${totalSickDeduction.toLocaleString('sv-SE')} kr.`
            }
            if (input.includes("övertid")) {
                const hours = parseInt(input.match(/(\d+)/)?.[1] || "1")
                // Overtime rate: hourly rate × 1.5 (enkel övertid). Hourly = monthly / 168 (avg hours/month)
                const hourlyRate = Math.round((selectedEmp?.lastSalary || 0) / 168)
                const overtimeRate = Math.round(hourlyRate * 1.5)
                const bonus = hours * overtimeRate
                newDeductions.push({ label: `Övertid (${hours}h × ${overtimeRate} kr)`, amount: -bonus })
                response = `Noterat ${hours} timmar övertid (${overtimeRate} kr/h). ${bonus.toLocaleString('sv-SE')} kr extra läggs till.`
            }
            if (input.includes("bonus")) {
                const amount = parseInt(input.match(/(\d+)/)?.[1] || "0")
                if (amount > 0) {
                    newDeductions.push({ label: "Bonus", amount: -amount })
                    response = `Bonus på ${amount.toLocaleString('sv-SE')} kr har lagts till.`
                }
            }

            if (newDeductions.length > 0) {
                setAiDeductions(prev => [...prev, ...newDeductions])
            }

            setChatMessages(prev => [...prev, { role: "ai", text: response }])
        }, 600)

        setChatInput("")
    }

    const handleConfirmPayslip = async () => {
        if (!selectedEmp) return
        // Prevent duplicate submissions
        if (isCreating) return
        setIsCreating(true)

        try {
            let employeeId = selectedEmp.id

            // If manual entry and user wants to save as employee, create the employee first
            if (useManualEntry && saveAsEmployee) {
                const empResponse = await fetch('/api/employees', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        name: manualPerson.name,
                        role: manualPerson.role || 'Anställd',
                        monthly_salary: manualPerson.salary,
                        personal_number: manualPerson.personalNumber || null,
                        employment_type: manualPerson.employmentType || 'tillsvidare',
                        tax_rate: (parseFloat(manualPerson.taxRate) || parseFloat(defaultTaxPercent)) / 100,
                        pension_rate: (parseFloat(manualPerson.pensionRate) || 4.5) / 100,
                        kommun: manualPerson.kommun || null,
                        status: 'active',
                    })
                })

                if (empResponse.ok) {
                    const empData = await empResponse.json()
                    employeeId = empData.employee?.id || employeeId
                    toast.success("Anställd sparad", `${manualPerson.name} har lagts till i teamet`)
                }
            }

            const payslipId = `LB-${Date.now()}`
            const response = await fetch('/api/payroll/payslips', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    id: payslipId,
                    employee_id: employeeId !== 'manual' ? employeeId : null,
                    period: currentPeriod,
                    gross_salary: finalSalary,
                    tax_deduction: tax,
                    net_salary: netSalary,
                    employer_contributions: employerContribution,
                    bonuses: aiDeductions.filter(d => d.amount < 0).reduce((sum, d) => sum + Math.abs(d.amount), 0),
                    deductions: aiDeductions.filter(d => d.amount > 0).reduce((sum, d) => sum + d.amount, 0),
                    status: "draft",
                    payment_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
                    // Store manual person data if not saved as employee
                    manual_employee_name: useManualEntry && !saveAsEmployee ? manualPerson.name : null,
                    // Client creates its own (more detailed) verification with age-based rates, pension, etc.
                    skip_verification: true,
                })
            })

            if (!response.ok) throw new Error("Failed to save payslip")

            const saved = await response.json()

            // Use the already-computed values (age-aware employer contribution rate)
            const verificationRows = [
                { account: "7010", description: `Lön ${selectedEmp.name}`, debit: finalSalary, credit: 0 },
                { account: "7510", description: `Arbetsgivaravgift ${selectedEmp.name}${isSenior ? ' (reducerad)' : ''}`, debit: employerContribution, credit: 0 },
                { account: "7411", description: `Tjänstepension ${selectedEmp.name}`, debit: pension, credit: 0 },
                { account: "2710", description: `Personalskatt ${selectedEmp.name}`, debit: 0, credit: tax },
                { account: "2730", description: `Arbetsgivaravgift skuld ${selectedEmp.name}`, debit: 0, credit: employerContribution },
                { account: "2810", description: `Pensionsskuld ${selectedEmp.name}`, debit: 0, credit: pension },
                { account: "1930", description: `Utbetalning lön ${selectedEmp.name}`, debit: 0, credit: netSalary },
            ]

            // Add union/A-kassa deduction rows if applicable
            if (fackavgift > 0) {
                verificationRows.push({ account: "2790", description: `Fackavgift ${selectedEmp.name}`, debit: 0, credit: fackavgift })
            }
            if (akassa > 0) {
                verificationRows.push({ account: "2790", description: `A-kassa ${selectedEmp.name}`, debit: 0, credit: akassa })
            }

            // Create verification (ledger entries)
            await addVerification({
                description: `Lön ${selectedEmp.name} ${currentPeriod}`,
                date: new Date().toISOString().split('T')[0],
                rows: verificationRows,
            })

            toast.success("Lönebesked skapat!", `${selectedEmp.name}s lön för ${currentPeriod} har registrerats`)
            onPayslipCreated(saved.payslip)
            onOpenChange(false)
            resetDialog()
        } catch (error) {
            console.error(error)
            toast.error("Kunde inte skapa lönebesked", "Ett fel uppstod")
            setIsCreating(false)
        }
    }

    // Tax method description for UI
    const kommunLabel = selectedEmp?.kommun ? ` (${selectedEmp.kommun})` : ''
    const taxMethodLabel = taxMethod === 'table' && selectedEmp?.taxTable
        ? `Skattetabell ${selectedEmp.taxTable}, kolumn ${selectedEmp.taxColumn || 1}${kommunLabel}`
        : `Kommunalskatt ${Math.round(taxRate * 100)}%${kommunLabel}`

    return {
        employees, filteredEmployees, isLoadingEmployees,
        selectedEmployee, setSelectedEmployee,
        selectedEmp,
        canProceedFromStep1,
        currentPeriod,

        // Manual entry
        useManualEntry, setUseManualEntry,
        manualPerson, setManualPerson,
        saveAsEmployee, setSaveAsEmployee,
        searchQuery, setSearchQuery,
        defaultTaxPercent,

        chatInput, setChatInput,
        chatMessages,
        handleSendMessage,

        aiDeductions,
        totalDeductions,
        recommendedSalary,
        customSalary, setCustomSalary,
        useAIRecommendation, setUseAIRecommendation,
        finalSalary,
        tax,
        taxRate,
        taxMethod,
        taxMethodLabel,
        netSalary,
        fackavgift,
        akassa,
        sempioneersattning,
        employerContribution,
        employerContributionRate,
        isSenior,
        pension,
        pensionRate,
        totalEmployerCost,
        isCreating,
        handleConfirmPayslip,
        resetDialog
    }
}

import { useState, useMemo } from "react"
import { useVerifications } from "@/hooks/use-verifications"
import { useAllTaxRates } from "@/hooks/use-tax-parameters"
import type { TaxRates } from "@/services/tax-service"

/**
 * @deprecated Use useAllTaxRates() hook instead. Kept for backwards compatibility with components
 * that import TAX_RATES directly — these should be migrated to the hook.
 */
export const TAX_RATES = {
  egenavgifter: {
    sjukforsakring: 0.0388,
    foraldraforsakring: 0.0260,
    alderspension: 0.1021,
    efterlevandepension: 0.0070,
    arbetsmarknadsavgift: 0.0264,
    arbetsskadeavgift: 0.0020,
    allmänLöneAvgift: 0.1150,
  },
  fullRate: 0.2897,
  reducedRate: 0.1021,
  karensReduction: 0.0076,
}

export interface MonthlyData {
  month: string
  revenue: number
  expenses: number
  profit: number
  egenavgifter: number
}

function formatComponentName(key: string): string {
    const names: Record<string, string> = {
      sjukforsakring: 'Sjukförsäkringsavgift',
      foraldraforsakring: 'Föräldraförsäkringsavgift',
      alderspension: 'Ålderspensionsavgift',
      efterlevandepension: 'Efterlevandepensionsavgift',
      arbetsmarknadsavgift: 'Arbetsmarknadsavgift',
      arbetsskadeavgift: 'Arbetsskadeavgift',
      allmanLoneavgift: 'Allmän löneavgift',
      // Legacy keys
      allmänLöneAvgift: 'Allmän löneavgift',
    }
    return names[key] || key
}


export function useTaxCalculator() {
    const { verifications } = useVerifications()
    const { rates: taxRates } = useAllTaxRates(new Date().getFullYear())
    const [annualProfit, setAnnualProfit] = useState<number>(500000)
    const [isReduced, setIsReduced] = useState(false)
    const [includeKarensReduction, setIncludeKarensReduction] = useState(false)

    // Calculate Real Profit from Ledger (YTD)
    const realProfit = useMemo(() => {
        let revenue = 0
        let expenses = 0

        verifications.forEach(v => {
          v.rows.forEach(r => {
            const acc = parseInt(r.account)
            if (acc >= 3000 && acc <= 3999) {
              revenue += (r.credit - r.debit) 
            } else if (acc >= 4000 && acc <= 7999) {
              expenses += (r.debit - r.credit) 
            }
          })
        })

        return revenue - expenses
    }, [verifications])

    const calculation = useMemo(() => {
        if (!taxRates) {
          return { rate: 0, avgifter: 0, nettoEfterAvgifter: annualProfit, monthlyNet: Math.round(annualProfit / 12), components: [], error: 'Skattesatser ej tillgängliga' }
        }
        let rate = isReduced ? taxRates.egenavgifterReduced : taxRates.egenavgifterFull
        if (includeKarensReduction && !isReduced) {
          rate -= taxRates.egenavgifterKarensReduction
        }

        const avgifter = Math.round(annualProfit * rate)
        const nettoEfterAvgifter = annualProfit - avgifter
        const monthlyNet = Math.round(nettoEfterAvgifter / 12)

        const components = !isReduced ? Object.entries(taxRates.egenavgiftComponents).map(([key, pct]) => ({
          name: formatComponentName(key),
          rate: pct as number,
          amount: Math.round(annualProfit * (pct as number)),
        })) : []

        return {
          rate,
          avgifter,
          nettoEfterAvgifter,
          monthlyNet,
          components,
        }
      }, [annualProfit, isReduced, includeKarensReduction, taxRates])

    const monthlyData: MonthlyData[] = useMemo(() => {
        const months = ['Jan', 'Feb', 'Mar', 'Apr', 'Maj', 'Jun', 'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dec']
        const monthlyStats = Array(12).fill(0).map(() => ({ revenue: 0, expenses: 0 }))
        const currentYear = new Date().getFullYear()

        verifications.forEach(v => {
            const d = new Date(v.date)
            if (d.getFullYear() !== currentYear) return 

            const monthIndex = d.getMonth()
            v.rows.forEach(r => {
                const acc = parseInt(r.account)
                if (acc >= 3000 && acc <= 3999) {
                   monthlyStats[monthIndex].revenue += (r.credit - r.debit)
                } else if (acc >= 4000 && acc <= 7999) {
                   monthlyStats[monthIndex].expenses += (r.debit - r.credit)
                }
            })
        })

        // Calculate derived stats
        return months.map((month, i) => {
            const s = monthlyStats[i]
            const profit = s.revenue - s.expenses
            // Estimate egenavgifter for that month based on current rate
            const egenavgifter = Math.round(profit * calculation.rate)
            return {
                month,
                revenue: s.revenue,
                expenses: s.expenses,
                profit,
                egenavgifter
            }
        })
    }, [verifications, calculation.rate])

    return {
        annualProfit,
        setAnnualProfit,
        isReduced,
        setIsReduced,
        includeKarensReduction,
        setIncludeKarensReduction,
        realProfit,
        calculation,
        monthlyData
    }
}

"use client"

import { useState, useCallback, useRef } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { ChevronRight, ChevronLeft, CheckCircle2, ArrowRight } from "lucide-react"
import { cn } from "@/lib/utils"
