            case "partners":
                return (
                    <PartnersStep
                        initialData={partnersRef.current}
                        onDataChange={(data) => { partnersRef.current = data }}
                    />
                )
            case "profile":
                return <ProfileStep />
            case "bank":
                return <BankStep />
            case "import-history":
                return <ImportHistoryStep />
            case "documents":
                return <DocumentsStep step={step} />
            case "team":
                return <TeamStep step={step} />
            default:
                return null
