// ============================================================================
// Entity Links
// ============================================================================

function getEntityLink(entityType: EntityType, entityId: string | null): string | null {
  if (!entityId) return null

  const routes: Record<EntityType, string> = {
    transactions: `/dashboard/bokforing?tab=transaktioner&id=${entityId}`,
    customerinvoices: `/dashboard/bokforing?tab=fakturor&id=${entityId}`,
    supplierinvoices: `/dashboard/bokforing?tab=fakturor&id=${entityId}`,
    receipts: `/dashboard/bokforing?tab=kvitton&id=${entityId}`,
    verifications: `/dashboard/bokforing?tab=verifikationer&id=${entityId}`,
    payslips: `/dashboard/loner?tab=lonebesked&id=${entityId}`,
    employees: `/dashboard/loner?tab=team&id=${entityId}`,
    shareholders: `/dashboard/agare?tab=aktiebok&id=${entityId}`,
    companies: `/dashboard/installningar`,
    profiles: `/dashboard/installningar`,
  }

  return routes[entityType] || null
}

// ============================================================================
// Components
// ============================================================================

interface ActivityItemProps {
  activity: ActivityLogEntry
  showAvatar?: boolean
}

export function ActivityItem({ activity, showAvatar = true }: ActivityItemProps) {
  const Icon = ACTION_ICONS[activity.action] ?? Pencil
  const colorClass = ACTION_COLORS[activity.action] ?? "bg-gray-500/10 text-gray-600"
  const link = getEntityLink(activity.entityType, activity.entityId)

  const who = activity.userName || activity.userEmail?.split("@")[0] || "Okänd"
  const action = ACTION_LABELS[activity.action] || activity.action
  const entityLabel = ENTITY_LABELS[activity.entityType] || activity.entityType

  return (
    <div className="flex items-start gap-3 py-3">
      {showAvatar && (
        <Avatar className="h-8 w-8 mt-0.5">
          <AvatarFallback className="text-xs bg-muted">
            {getInitials(who)}
          </AvatarFallback>
        </Avatar>
      )}

      <div className="flex-1 min-w-0">
        <p className="text-sm">
          <span className="font-medium">{who}</span>
          <span className="text-muted-foreground"> {action} </span>
          {link ? (
            <Link href={link} className="font-medium hover:underline text-primary">
              {activity.entityName || entityLabel}
            </Link>
          ) : (
            <span className="font-medium">{activity.entityName || entityLabel}</span>
          )}
        </p>

        {/* Show changes if any */}
        {activity.changes && Object.keys(activity.changes).length > 0 && (
          <div className="mt-1 text-xs text-muted-foreground">
            {Object.entries(activity.changes).map(([key, change]) => (
              <span key={key} className="mr-2">
                {key}: {String(change.from)} → {String(change.to)}
              </span>
            ))}
          </div>
        )}

        <p className="text-xs text-muted-foreground mt-0.5">
          {formatActivityTime(activity.createdAt)}
        </p>
      </div>

      <div className={cn("flex h-8 w-8 items-center justify-center rounded-full", colorClass)}>
        <Icon className="h-4 w-4" />
      </div>
    </div>
  )
}

interface ActivityFeedProps {
  /** Filter by entity type */
  entityType?: EntityType
  /** Filter by specific entity ID */
  entityId?: string
  /** Maximum height */
  maxHeight?: string | number
  /** Maximum number of activities to load initially */
  limit?: number
  /** Show title */
  showTitle?: boolean
  /** Title text */
  title?: string
  /** Class name */
  className?: string
}

export function ActivityFeed({
  entityType,
  entityId,
  maxHeight = 400,
  limit = 20,
  showTitle = true,
  title = "Aktivitet",
  className,
}: ActivityFeedProps) {
  const { activities, loading, hasMore, loadMore } = useActivityLog({
    entityType,
    entityId,
    limit,
    realtime: true,
  })

  if (loading && activities.length === 0) {
    return (
      <Card className={className}>
        {showTitle && (
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <History className="h-4 w-4" />
              {title}
            </CardTitle>
          </CardHeader>
        )}
        <CardContent>
          <div className="space-y-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="flex items-start gap-3">
                <Skeleton className="h-8 w-8 rounded-full" />
                <div className="flex-1 space-y-2">
                  <Skeleton className="h-4 w-3/4" />
                  <Skeleton className="h-3 w-1/4" />
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    )
  }

  if (activities.length === 0) {
    return (
      <Card className={className}>
        {showTitle && (
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <History className="h-4 w-4" />
              {title}
            </CardTitle>
          </CardHeader>
        )}
        <CardContent>
          <p className="text-sm text-muted-foreground text-center py-8">
            Ingen aktivitet ännu
          </p>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card className={className}>
      {showTitle && (
        <CardHeader className="pb-3">
          <CardTitle className="text-base flex items-center gap-2">
            <History className="h-4 w-4" />
            {title}
          </CardTitle>
        </CardHeader>
      )}
      <CardContent className="pt-0">
        <ScrollArea style={{ maxHeight }}>
          <div className="divide-y">
            {activities.map((activity) => (
              <ActivityItem key={activity.id} activity={activity} />
            ))}
          </div>

          {hasMore && (
            <div className="pt-3">
              <Button
                variant="ghost"
                size="sm"
                className="w-full"
                onClick={loadMore}
                disabled={loading}
              >
                <ChevronDown className="h-4 w-4 mr-2" />
                Visa mer
              </Button>
            </div>
          )}
        </ScrollArea>
      </CardContent>
    </Card>
  )
}

/**
 * Compact activity timeline for sidebars
 */
export function ActivityTimeline({
  entityType,
  entityId,
  limit = 5,
  className,
}: {
  entityType?: EntityType
  entityId?: string
  limit?: number
  className?: string
}) {
  const { activities, loading } = useActivityLog({
    entityType,
    entityId,
    limit,
    realtime: true,
  })

  if (loading) {
    return (
      <div className={cn("space-y-3", className)}>
        {[...Array(3)].map((_, i) => (
          <div key={i} className="flex items-center gap-2">
            <Skeleton className="h-2 w-2 rounded-full" />
            <Skeleton className="h-3 w-full" />
          </div>
        ))}
      </div>
    )
  }

  return (
    <div className={cn("space-y-2", className)}>
      {activities.map((activity) => {
        const who = activity.userName || activity.userEmail?.split("@")[0] || "Okänd"
        const action = ACTION_LABELS[activity.action]
        const colorClass = ACTION_COLORS[activity.action]

        return (
          <div key={activity.id} className="flex items-start gap-2 text-xs">
            <div className={cn("h-2 w-2 rounded-full mt-1.5", colorClass.replace("text-", "bg-").replace("/10", ""))} />
            <div className="flex-1 min-w-0">
              <span className="font-medium">{who}</span>
              <span className="text-muted-foreground"> {action} </span>
              <span className="font-medium truncate">{activity.entityName}</span>
              <span className="text-muted-foreground block">
                {formatActivityTime(activity.createdAt)}
              </span>
            </div>
          </div>
        )
      })}
    </div>
  )
}

// ============================================================================
// Helpers
