"use client"

/**
 * useSendMessage - Hook for sending chat messages
 */

import { useState, useCallback } from 'react'
import type { Message, Conversation } from '@/lib/chat-types'
import type { MentionItem } from '@/components/ai/mention-popover'
import { generateTitle, fileToBase64, fileToDataUrl } from '@/lib/chat-utils'
import { useModel } from '@/providers/model-provider'
import { useStreamParser } from './use-stream-parser'

interface SendMessageOptions {
    content: string
    files?: File[]
    mentions?: MentionItem[]
    retryMessageId?: string
    confirmationId?: string
    /** Action trigger display - shows chip instead of raw prompt */
    actionTrigger?: {
        icon: string
        title: string
        subtitle?: string
        meta?: string
    }
}

interface UseSendMessageOptions {
    conversations: Conversation[]
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
    currentConversationId: string | null
    setCurrentConversationId: (id: string | null) => void
}

export function useSendMessage({
    conversations,
    setConversations,
    currentConversationId,
    setCurrentConversationId,
}: UseSendMessageOptions) {
    const { modelId } = useModel()
    const [isLoading, setIsLoading] = useState(false)
    const { parseStreamResponse, dispatchCompletionEvents } = useStreamParser({ setConversations })

    const currentConversation = conversations.find(c => c.id === currentConversationId)
    const messages = currentConversation?.messages || []

    const sendMessage = useCallback(async ({
        content,
        files = [],
        mentions = [],
        retryMessageId,
        confirmationId,
        actionTrigger
    }: SendMessageOptions) => {
        const messageContent = content.trim()
        const hasFiles = files.length > 0

        if (!messageContent && !hasFiles && !retryMessageId && !confirmationId) return
        if (isLoading) return

        let conversationId = currentConversationId
        let updatedMessages = [...messages]

        // If retrying, find and remove the message + subsequent
        if (retryMessageId) {
            const retryIndex = updatedMessages.findIndex(m => m.id === retryMessageId)
            if (retryIndex > 0) {
                updatedMessages = updatedMessages.slice(0, retryIndex)
            }
        }

        // Create assistant message placeholder
        const assistantMessageId = crypto.randomUUID()
        const assistantMessage: Message = {
            id: assistantMessageId,
            role: 'assistant',
            content: ''
        }

        // Create or update conversation
        if (!conversationId) {
            conversationId = crypto.randomUUID()
            const newConversation: Conversation = {
                id: conversationId,
                title: generateTitle(updatedMessages),
                messages: updatedMessages,
                createdAt: Date.now(),
                updatedAt: Date.now()
            }
            setConversations(prev => [newConversation, ...prev])
            setCurrentConversationId(conversationId)

            // Generate AI title asynchronously
            generateAITitle(conversationId, updatedMessages, setConversations)
        } else {
            const currentTitle = conversations.find(c => c.id === conversationId)?.title

            setConversations(prev => prev.map(c =>
                c.id === conversationId
                    ? { ...c, messages: updatedMessages, updatedAt: Date.now() }
                    : c
            ))

            // Regenerate generic title if needed
            if (currentTitle === 'Ny konversation' || currentTitle === 'New conversation') {
                generateAITitle(conversationId, updatedMessages, setConversations)
            }
        }

        setIsLoading(true)
        window.dispatchEvent(new CustomEvent('ai-dialog-start', { detail: { contentType: 'default' } }))

        try {
            // Convert files for display
            const messageAttachments = await Promise.all(
                files.map(async (file) => ({
                    name: file.name,
                    type: file.type,
                    dataUrl: await fileToDataUrl(file)
                }))
            )

            // Auto-inject context for images
            let enhancedContent = messageContent
            const hasImages = files.some(f => f.type.startsWith('image/'))

            if (hasImages && !messageContent.trim()) {
                enhancedContent = '[Användaren har skickat en bild. Beskriv vad du ser och fråga vad de vill göra.]'
            }

            // Add user message if not retry/confirmation
            if (!retryMessageId) {
                const userMessage: Message = {
                    id: crypto.randomUUID(),
                    role: 'user',
                    content: messageContent,
                    attachments: messageAttachments.length > 0 ? messageAttachments : undefined,
                    mentions: mentions.length > 0 ? mentions : undefined,
                    actionTrigger: actionTrigger
                }
                updatedMessages = [...updatedMessages, userMessage]
            }

            // Add assistant placeholder
            updatedMessages = [...updatedMessages, assistantMessage]

            setConversations(prev => prev.map(c =>
                c.id === conversationId
                    ? { ...c, messages: updatedMessages, updatedAt: Date.now() }
                    : c
            ))

            // Convert files for API
            const attachments = await Promise.all(files.map(fileToBase64))

            // Build messages for API
            const messagesForAPI = updatedMessages
                .filter(m => {
                    if (m.role === 'user' && (m.content || m.attachments?.length)) return true
                    if (m.role === 'assistant' && m.content && typeof m.content === 'string' && m.content.trim()) return true
                    return false
                })
                .map((m, index, arr) => {
                    if (m.role === 'user' && index === arr.length - 1) {
                        return { role: m.role, content: enhancedContent || m.content || '' }
                    }
                    return { role: m.role, content: m.content || '' }
                })

            const response = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    messages: messagesForAPI,
                    confirmationId,
                    attachments: attachments.length > 0 ? attachments : undefined,
                    mentions: mentions.length > 0 ? mentions : undefined,
                    model: modelId
                })
            })

            if (!response.ok) {
                await handleErrorResponse(response, conversationId, assistantMessageId, setConversations)
                return
            }

            const contentType = response.headers.get('content-type')

            if (contentType?.includes('application/json')) {
                await handleJsonResponse(response, conversationId, assistantMessageId, setConversations)
                return
            }

            // Handle streaming response
            const { fullContent, lastData } = await parseStreamResponse(
                response,
                conversationId,
                assistantMessageId
            )

            dispatchCompletionEvents(fullContent, lastData)

        } catch (error) {
            console.error('SendMessage error:', error)
            handleSendError(conversationId!, assistantMessageId, setConversations)
        } finally {
            setIsLoading(false)
        }
    }, [messages, currentConversationId, isLoading, conversations, modelId, setConversations, setCurrentConversationId, parseStreamResponse, dispatchCompletionEvents])

    const regenerateResponse = useCallback(() => {
        const lastAssistantMessage = [...messages].reverse().find(m => m.role === 'assistant')
        if (lastAssistantMessage) {
            sendMessage({ content: '', retryMessageId: lastAssistantMessage.id })
        }
    }, [messages, sendMessage])

    return {
        isLoading,
        sendMessage,
        regenerateResponse,
    }
}

// =============================================================================
// Helper Functions
// =============================================================================

function generateAITitle(
    conversationId: string,
    messages: Message[],
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
) {
    fetch('/api/chat/title', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages })
    })
        .then(res => res.json())
        .then(data => {
            if (data.title && data.title !== 'Ny konversation') {
                setConversations(prev => prev.map(c =>
                    c.id === conversationId ? { ...c, title: data.title } : c
                ))
            }
        })
        .catch(err => console.error('Failed to generate title:', err))
}

async function handleErrorResponse(
    response: Response,
    conversationId: string,
    assistantMessageId: string,
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
) {
    if (response.status === 402) {
        setConversations(prev => prev.map(c =>
            c.id === conversationId
                ? {
                    ...c,
                    messages: c.messages.map(msg =>
                        msg.id === assistantMessageId
                            ? {
                                ...msg,
                                content: '⚠️ Du har förbrukat din AI-budget för denna månad. Köp fler credits för att fortsätta använda AI.',
                                display: {
                                    component: 'BuyCreditsPrompt',
                                    props: {
                                        packages: [
                                            { tokens: 2000000, price: 99, label: '2M tokens' },
                                            { tokens: 5000000, price: 199, label: '5M tokens', popular: true, savings: 'Spara 20%' },
                                            { tokens: 15000000, price: 499, label: '15M tokens', savings: 'Spara 33%' },
                                        ]
                                    },
                                    title: 'Köp AI-credits'
                                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                } as any
                            }
                            : msg
                    )
                }
                : c
        ))
        return
    }
    throw new Error('Failed to get response')
}

async function handleJsonResponse(
    response: Response,
    conversationId: string,
    assistantMessageId: string,
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
) {
    const data = await response.json()

    setConversations(prev => prev.map(c =>
        c.id === conversationId
            ? {
                ...c,
                messages: c.messages.map(msg =>
                    msg.id === assistantMessageId
                        ? {
                            ...msg,
                            content: data.content,
                            display: data.display,
                            confirmationRequired: data.confirmationRequired,
                            toolResults: data.toolResults
                        }
                        : msg
                )
            }
            : c
    ))

    window.dispatchEvent(new CustomEvent('ai-dialog-complete', {
        detail: {
            contentType: data.display?.component || 'json',
            title: data.display?.title || 'Klar',
            content: data.content,
            data: data,
            display: data.display,
            navigation: data.navigation,
            highlightId: data.toolResults?.[0]?.result?.id
        }
    }))
}

function handleSendError(
    conversationId: string,
    assistantMessageId: string,
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
) {
    window.dispatchEvent(new CustomEvent('ai-dialog-error', {
        detail: { contentType: 'error', title: 'Fel uppstod', content: 'Ett fel uppstod. Försök igen.' }
    }))

    setConversations(prev => prev.map(c =>
        c.id === conversationId
            ? {
                ...c,
                messages: c.messages.map(msg =>
                    msg.id === assistantMessageId
                        ? { ...msg, content: 'Ett fel uppstod. Försök igen.', error: true }
                        : msg
                )
            }
            : c
    ))
}

"use client"

/**
 * useStreamParser - Hook for parsing streaming chat responses
 */

import { useCallback } from 'react'
import { useRouter } from 'next/navigation'
import type { Message, Conversation } from '@/lib/chat-types'

/** Extract the AI's prose comment, stripping markdown/emoji formatting from tool output */
function cleanAIComment(text: string): string {
    if (!text) return ''
    // Remove lines that are just emoji + bold check results (e.g. "✅ **Name**: desc")
    const lines = text.split('\n').filter(line => {
        const trimmed = line.trim()
        if (!trimmed) return false
        // Skip emoji-prefixed audit result lines
        if (/^[✅⚠️❌🔍📊]/.test(trimmed)) return false
        // Skip lines that are just bold markers
        if (/^\*\*.*\*\*:?$/.test(trimmed)) return false
        return true
    })
    // Strip remaining markdown bold
    return lines.map(l => l.replace(/\*\*/g, '')).join(' ').trim()
}

interface WalkthroughBlock {
    type: string
    props: Record<string, unknown>
    id?: string
}

interface WalkthroughBlockResponse {
    mode: "fixed" | "dynamic"
    title: string
    subtitle?: string
    blocks: WalkthroughBlock[]
}

interface StreamData {
    display?: unknown
    navigation?: { route: string }
    confirmationRequired?: unknown
    toolResults?: unknown[]
    walkthrough?: {
        title: string
        summary: string
        date?: string
        sections: Array<{
            heading: string
            status: "pass" | "warning" | "fail"
            description: string
            details?: string
        }>
    }
    walkthroughBlocks?: WalkthroughBlockResponse
}

interface UseStreamParserOptions {
    setConversations: React.Dispatch<React.SetStateAction<Conversation[]>>
}

export function useStreamParser({ setConversations }: UseStreamParserOptions) {
    const router = useRouter()

    const parseStreamResponse = useCallback(async (
        response: Response,
        conversationId: string,
        assistantMessageId: string
    ): Promise<{ fullContent: string; lastData: StreamData | null }> => {
        const reader = response.body?.getReader()
        const decoder = new TextDecoder()

        if (!reader) {
            return { fullContent: '', lastData: null }
        }

        let fullContent = ''
        let buffer = ''
        let lastData: StreamData | null = null

        while (true) {
            const { done, value } = await reader.read()
            if (done) break

            const textChunk = decoder.decode(value, { stream: true })
            buffer += textChunk

            const lines = buffer.split('\n')
            buffer = lines.pop() || ''

            for (const line of lines) {
                if (!line.trim()) continue

                try {
                    if (line.startsWith('T:')) {
                        const contentDelta = JSON.parse(line.slice(2))
                        fullContent += contentDelta
                    } else if (line.startsWith('TH:')) {
                        // Extended thinking from Sonnet - consume but don't display to user
                        // This is internal reasoning, logged only in development
                        if (process.env.NODE_ENV === 'development') {
                            const thinking = JSON.parse(line.slice(3))
                            console.debug('[AI Thinking]', thinking)
                        }
                    } else if (line.startsWith('W:')) {
                        const walkthroughData = JSON.parse(line.slice(2)) as WalkthroughBlockResponse
                        lastData = {
                            ...(lastData || {}),
                            walkthroughBlocks: walkthroughData,
                        } as StreamData
                    } else if (line.startsWith('D:')) {
                        const data = JSON.parse(line.slice(2)) as StreamData
                        // Merge data chunks instead of overwriting
                        lastData = {
                            ...(lastData || {}),
                            ...data,
                            display: data.display || lastData?.display,
                            toolResults: data.toolResults || lastData?.toolResults,
                            confirmationRequired: data.confirmationRequired || lastData?.confirmationRequired,
                        } as StreamData

                        // Handle immediate navigation
                        if (data.navigation) {
                            router.push(data.navigation.route)
                        }

                        setConversations(prev => prev.map(c =>
                            c.id === conversationId
                                ? {
                                    ...c,
                                    messages: c.messages.map(msg =>
                                        msg.id === assistantMessageId
                                            ? {
                                                ...msg,
                                                display: data.display || msg.display,
                                                confirmationRequired: data.confirmationRequired || msg.confirmationRequired,
                                                toolResults: data.toolResults || msg.toolResults
                                            } as typeof msg
                                            : msg
                                    )
                                }
                                : c
                        ))
                    }
                } catch (e) {
                    console.error('Error parsing stream line:', line, e)
                }
            }

            // Update content state
            setConversations(prev => prev.map(c =>
                c.id === conversationId
                    ? {
                        ...c,
                        messages: c.messages.map(msg =>
                            msg.id === assistantMessageId
                                ? { ...msg, content: fullContent }
                                : msg
                        )
                    }
                    : c
            ))
        }

        return { fullContent, lastData }
    }, [router, setConversations])

    const dispatchCompletionEvents = useCallback((
        fullContent: string,
        lastData: StreamData | null
    ) => {
        const isErrorResponse = fullContent.includes('Ett fel uppstod') ||
            fullContent.includes('fel uppstod vid generering') ||
            (fullContent.includes('error') && fullContent.length < 100)

        // Display-only components that should render inline in chat, not in the overlay dialog
        const inlineOnlyComponents = new Set<string>([
        ])

        // Check all data chunks for inline-only display components
        const displayComponent = (lastData?.display as any)?.component || (lastData?.display as any)?.type || ''
        const isInlineOnly = inlineOnlyComponents.has(displayComponent)

        const hasStructuredOutput = lastData && !isInlineOnly && (
            lastData.display ||
            lastData.navigation ||
            (lastData.toolResults && lastData.toolResults.length > 0) ||
            lastData.confirmationRequired
        )

        // Check for block-based walkthrough (new system)
        if (lastData?.walkthroughBlocks) {
            window.dispatchEvent(new CustomEvent('ai-dialog-walkthrough-blocks', {
                detail: lastData.walkthroughBlocks
            }))
            return
        }

        // Check for walkthrough content (e.g. balanskontroll) — legacy
        const walkthroughData = lastData?.walkthrough || (lastData?.toolResults as any)?.[0]?.result?.walkthrough
        console.log('[walkthrough debug]', { walkthroughData, fullContentLength: fullContent.length, fullContentPreview: fullContent.slice(0, 200), lastDataKeys: lastData ? Object.keys(lastData) : null })
        if (walkthroughData) {
            window.dispatchEvent(new CustomEvent('ai-dialog-walkthrough', {
                detail: {
                    ...walkthroughData,
                    aiComment: cleanAIComment(fullContent) || walkthroughData.aiComment,
                }
            }))
            return
        }

        if (isErrorResponse) {
            window.dispatchEvent(new CustomEvent('ai-dialog-error', {
                detail: { contentType: 'error', title: 'Fel uppstod', content: fullContent }
            }))
        } else if (hasStructuredOutput) {
            window.dispatchEvent(new CustomEvent('ai-dialog-complete', {
                detail: {
                    contentType: (lastData?.display as { component?: string })?.component ||
                        (lastData?.confirmationRequired ? 'confirmation' : 'action'),
                    title: (lastData?.display as { title?: string })?.title ||
                        (lastData?.confirmationRequired ? 'Bekräfta åtgärd' : 'Åtgärd slutförd'),
                    content: fullContent,
                    data: lastData,
                    display: lastData?.display,
                    navigation: lastData?.navigation,
                    confirmationRequired: lastData?.confirmationRequired,
                    highlightId: (lastData?.toolResults?.[0] as { result?: { id?: string } })?.result?.id
                }
            }))
        } else {
            window.dispatchEvent(new CustomEvent('ai-dialog-hide'))
        }
    }, [])

    return {
        parseStreamResponse,
        dispatchCompletionEvents,
    }
}

