import { useMemo } from "react"
import { getSupabaseClient } from '@/lib/database/supabase'
import { FinancialReportProcessor, AccountBalance, FinancialSection } from "@/services/processors/reports"
import { useCachedQuery } from "./use-cached-query"

interface BalanceData {
    bsBalances: AccountBalance[]
    plBalances: AccountBalance[]
    prevBsBalances: AccountBalance[]
    prevPlBalances: AccountBalance[]
}

async function fetchAllBalances(): Promise<BalanceData> {
    const supabase = getSupabaseClient()
    const year = new Date().getFullYear()
    const prevYear = year - 1

    const [bsResult, plResult, prevBsResult, prevPlResult] = await Promise.all([
        // Balance Sheet: All time to current year end
        supabase.rpc('get_account_balances', {
            p_start_date: '2000-01-01',
            p_end_date: new Date(year, 11, 31).toISOString().split('T')[0]
        }),
        // P&L: Current Year
        supabase.rpc('get_account_balances', {
            p_start_date: new Date(year, 0, 1).toISOString().split('T')[0],
            p_end_date: new Date(year, 11, 31).toISOString().split('T')[0]
        }),
        // Balance Sheet: All time to previous year end
        supabase.rpc('get_account_balances', {
            p_start_date: '2000-01-01',
            p_end_date: new Date(prevYear, 11, 31).toISOString().split('T')[0]
        }),
        // P&L: Previous Year
        supabase.rpc('get_account_balances', {
            p_start_date: new Date(prevYear, 0, 1).toISOString().split('T')[0],
            p_end_date: new Date(prevYear, 11, 31).toISOString().split('T')[0]
        })
    ])

    if (bsResult.error) throw bsResult.error
    if (plResult.error) throw plResult.error
    if (prevBsResult.error) throw prevBsResult.error
    if (prevPlResult.error) throw prevPlResult.error

    const toAccountBalances = (data: typeof bsResult.data): AccountBalance[] =>
        (data || []).map(row => ({
            account: String(row.account_number),
            balance: row.balance
        }))

    return {
        bsBalances: toAccountBalances(bsResult.data),
        plBalances: toAccountBalances(plResult.data),
        prevBsBalances: toAccountBalances(prevBsResult.data),
        prevPlBalances: toAccountBalances(prevPlResult.data),
    }
}

export function useFinancialReports() {
    const { data: balances, isLoading } = useCachedQuery<BalanceData>({
        cacheKey: `financial-reports-${new Date().getFullYear()}`,
        queryFn: fetchAllBalances,
        ttlMs: 3 * 60 * 1000, // 3 minutes — balances don't change frequently
    })

    const bsBalances = balances?.bsBalances ?? []
    const plBalances = balances?.plBalances ?? []
    const prevBsBalances = balances?.prevBsBalances ?? []
    const prevPlBalances = balances?.prevPlBalances ?? []

    const incomeStatement = useMemo(() => {
        if (isLoading || !plBalances.length) return null
        return FinancialReportProcessor.calculateIncomeStatement(plBalances)
    }, [plBalances, isLoading])

    const balanceSheet = useMemo(() => {
        if (isLoading || !bsBalances.length) return null
        return FinancialReportProcessor.calculateBalanceSheet(bsBalances)
    }, [bsBalances, isLoading])

    // Sectioned data with YoY comparison
    const incomeStatementSections = useMemo(() => {
        if (isLoading) return null
        if (!plBalances.length) {
            return FinancialReportProcessor.getEmptyIncomeStatementSections()
        }
        const currentSections = FinancialReportProcessor.calculateIncomeStatementSections(plBalances)
        const previousSections = prevPlBalances.length
            ? FinancialReportProcessor.calculateIncomeStatementSections(prevPlBalances)
            : null

        // Merge previous year data into current sections
        return mergeComparativeData(currentSections, previousSections)
    }, [plBalances, prevPlBalances, isLoading])

    const balanceSheetSections = useMemo(() => {
        if (isLoading) return null
        if (!bsBalances.length) {
            return FinancialReportProcessor.getEmptyBalanceSheetSections()
        }
        const currentSections = FinancialReportProcessor.calculateBalanceSheetSections(bsBalances)
        const previousSections = prevBsBalances.length
            ? FinancialReportProcessor.calculateBalanceSheetSections(prevBsBalances)
            : null

        return mergeComparativeData(currentSections, previousSections)
    }, [bsBalances, prevBsBalances, isLoading])

    // Current and previous year for display
    const currentYear = new Date().getFullYear()
    const previousYear = currentYear - 1

    return {
        incomeStatement,
        balanceSheet,
        incomeStatementSections,
        balanceSheetSections,
        isLoading,
        currentYear,
        previousYear
    }
}

/**
 * Merge previous year data into current sections for YoY comparison
 */
function mergeComparativeData(
    currentSections: FinancialSection[],
    previousSections: FinancialSection[] | null
): FinancialSection[] {
    if (!previousSections) return currentSections

    return currentSections.map((section, sectionIdx) => {
        const prevSection = previousSections[sectionIdx]

        return {
            ...section,
            previousTotal: prevSection?.total ?? 0,
            items: section.items.map((item, itemIdx) => ({
                ...item,
                previousValue: prevSection?.items[itemIdx]?.value ?? 0
            }))
        }
    })
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useVerifications } from "./use-verifications"
import { useCompany } from "@/providers/company-provider"
import { getSupabaseClient } from '@/lib/database/supabase'
import {
    getApplicableChecks,
    resolveChecks,
    getCheckProgress,
    migrateOldChecks,
    type ChecklistCompanyProfile,
    type ResolvedCheck,
} from '@/lib/checklist-engine'

export type PeriodStatus = 'open' | 'review' | 'locked'

export interface MonthStatus {
    id?: string
    year: number
    month: number // 1-12
    status: PeriodStatus
    manualChecks: Record<string, boolean>
    notes?: string
    dayNotes?: Record<string, string>
    locked_at?: string
    locked_by?: string
}

export function useMonthClosing() {
    const supabase = getSupabaseClient()
    const { verifications } = useVerifications()
    const { company } = useCompany()
    const [periods, setPeriods] = useState<MonthStatus[]>([])
    const [pendingCounts, setPendingCounts] = useState<Record<string, number>>({})

    // Load periods from Supabase
    useEffect(() => {
        if (!company?.id) return

        let isMounted = true
        async function loadPeriods() {
            try {
                const { data, error } = await supabase
                    .from('financialperiods')
                    .select('*')
                    .eq('type', 'monthly')

                if (isMounted) {
                    if (!error && data) {
                        setPeriods(data.map(p => {
                            const parts = p.id.split('-M')
                            const year = parseInt(parts[0])
                            const month = parseInt(parts[1])

                            // Migrate old JSONB format to new format
                            const raw = (p.reconciliation_checks as Record<string, unknown>) || {}
                            const { manualChecks, notes } = migrateOldChecks(raw)
                            const dayNotes = (raw.dayNotes as Record<string, string>) || undefined

                            return {
                                id: p.id,
                                year,
                                month,
                                status: p.status === 'closed' ? 'locked' : (p.status as PeriodStatus),
                                manualChecks,
                                notes,
                                dayNotes,
                                locked_at: p.locked_at || undefined,
                                locked_by: p.locked_by || undefined
                            }
                        }))
                    }
                }
            } catch (err) {
                console.error("Error loading periods:", err)
            }
        }

        loadPeriods()
        return () => { isMounted = false }
    }, [company?.id])

    const getPeriod = (year: number, month: number): MonthStatus => {
        return periods.find(p => p.year === year && p.month === month) || {
            year,
            month,
            status: 'open' as PeriodStatus,
            manualChecks: {},
        }
    }

    const savePeriod = async (year: number, month: number, updates: Partial<MonthStatus>) => {
        if (!company?.id) return

        const current = getPeriod(year, month)
        const updated = { ...current, ...updates }
        const periodId = `${year}-M${month.toString().padStart(2, '0')}`

        // Optimistic UI
        setPeriods(prev => {
            const index = prev.findIndex(p => p.year === year && p.month === month)
            if (index >= 0) {
                const n = [...prev]
                n[index] = updated
                return n
            } else {
                return [...prev, updated]
            }
        })

        // Persist — serialize manualChecks + notes into reconciliation_checks JSONB
        try {
            const dbStatus = updated.status === 'locked' ? 'closed' : updated.status

            const reconciliationPayload: Record<string, boolean | string | Record<string, string>> = { ...updated.manualChecks }
            if (updated.notes) {
                reconciliationPayload.notes = updated.notes
            }
            if (updated.dayNotes && Object.keys(updated.dayNotes).length > 0) {
                reconciliationPayload.dayNotes = updated.dayNotes
            }

            const { error } = await supabase
                .from('financialperiods')
                .upsert({
                    id: periodId,
                    company_id: company.id,
                    type: 'monthly',
                    name: `Månadsbokslut ${year}-${month}`,
                    start_date: `${year}-${month.toString().padStart(2, '0')}-01`,
                    end_date: `${year}-${month.toString().padStart(2, '0')}-28`,
                    status: dbStatus,
                    reconciliation_checks: reconciliationPayload,
                    locked_at: updated.locked_at,
                    locked_by: updated.locked_by
                }, { onConflict: 'id' })

            if (error) {
                console.error("Failed to save period:", error)
            }
        } catch (err) {
            console.error("Upsert error:", err)
        }
    }

    const lockPeriod = (year: number, month: number) => {
        savePeriod(year, month, {
            status: 'locked',
            locked_at: new Date().toISOString()
        })
    }

    const unlockPeriod = (year: number, month: number) => {
        savePeriod(year, month, { status: 'open', locked_at: undefined })
    }

    const toggleCheck = (year: number, month: number, checkId: string) => {
        const period = getPeriod(year, month)
        savePeriod(year, month, {
            manualChecks: {
                ...period.manualChecks,
                [checkId]: !period.manualChecks[checkId]
            }
        })
    }

    const saveNotes = (year: number, month: number, notes: string) => {
        savePeriod(year, month, { notes })
    }

    const getDayNote = (year: number, month: number, day: number): string => {
        const period = getPeriod(year, month)
        return period.dayNotes?.[String(day)] || ""
    }

    const saveDayNote = (year: number, month: number, day: number, text: string) => {
        const period = getPeriod(year, month)
        const dayNotes = { ...period.dayNotes, [String(day)]: text }
        // Remove empty entries
        if (!text) delete dayNotes[String(day)]
        savePeriod(year, month, { dayNotes })
    }

    // Verification stats (discrepancy count for auto checks)
    const getVerificationStats = (year: number, month: number) => {
        const monthVerifications = verifications.filter(v => {
            const d = new Date(v.date)
            return d.getFullYear() === year && (d.getMonth() + 1) === month
        })

        const verificationCount = monthVerifications.length

        let discrepancyCount = 0
        for (const v of monthVerifications) {
            if (v.rows && Array.isArray(v.rows)) {
                const totalDebit = v.rows.reduce((sum: number, row: { debit?: number }) => sum + (row.debit || 0), 0)
                const totalCredit = v.rows.reduce((sum: number, row: { credit?: number }) => sum + (row.credit || 0), 0)
                if (Math.abs(totalDebit - totalCredit) > 0.01) {
                    discrepancyCount++
                }
            }
        }

        return { verificationCount, discrepancyCount }
    }

    // Set pending transaction counts (provided by caller to avoid duplicate fetches)
    const updatePendingCounts = useCallback((counts: Record<string, number>) => {
        setPendingCounts(counts)
    }, [])

    /**
     * Build fully resolved checks for a given month.
     * Returns the list of ResolvedCheck[] with auto values computed.
     */
    const getResolvedChecks = (year: number, month: number): ResolvedCheck[] => {
        if (!company) return []

        const profile: ChecklistCompanyProfile = {
            companyType: company.companyType,
            hasEmployees: company.hasEmployees,
            hasMomsRegistration: company.hasMomsRegistration,
            vatFrequency: company.vatFrequency,
            fiscalYearEnd: company.fiscalYearEnd,
        }

        const definitions = getApplicableChecks(profile, year, month)
        const period = getPeriod(year, month)

        const periodKey = `${year}-${String(month).padStart(2, '0')}`
        const pending = pendingCounts[periodKey] ?? 0

        const autoStates: Record<string, boolean> = {
            no_pending_transactions: pending === 0,
        }

        return resolveChecks(definitions, period.manualChecks, autoStates)
    }

    return {
        getPeriod,
        lockPeriod,
        unlockPeriod,
        toggleCheck,
        saveNotes,
        getDayNote,
        saveDayNote,
        getVerificationStats,
        getResolvedChecks,
        getCheckProgress,
        updatePendingCounts,
    }
}

"use client"

/**
 * useRealtime - Real-time collaboration hooks
 *
 * Enables multi-user collaboration by subscribing to:
 * 1. Database changes - Know when data is updated
 * 2. Presence - See who's online and what they're viewing
 * 3. Broadcast - Custom events like "user is editing"
 *
 * Uses Supabase Realtime under the hood.
 */

import { useEffect, useState, useCallback, useRef } from "react"
import { getSupabaseClient } from "@/lib/database/supabase"
import { useAuth } from "./use-auth"
import type { RealtimeChannel, RealtimePresenceState } from "@supabase/supabase-js"

// ============================================================================
// Types
// ============================================================================

export interface PresenceUser {
  id: string
  email?: string
  name?: string
  avatar?: string
  currentPage?: string
  lastSeen: Date
  isEditing?: boolean
  editingRecord?: string // ID of record being edited
}

export interface RealtimeEvent<T = unknown> {
  type: "INSERT" | "UPDATE" | "DELETE"
  table: string
  record: T
  oldRecord?: T
  timestamp: Date
}

interface UseRealtimeOptions {
  /** Channel name (usually company ID or shared context) */
  channelName: string
  /** Current page the user is viewing */
  currentPage?: string
  /** Callback when data changes */
  onDataChange?: (event: RealtimeEvent) => void
  /** Tables to subscribe to */
  tables?: string[]
}

interface UseRealtimeReturn {
  /** Users currently online in this channel */
  onlineUsers: PresenceUser[]
  /** Whether the realtime connection is active */
  isConnected: boolean
  /** Broadcast a custom event to all users */
  broadcast: (event: string, payload: unknown) => void
  /** Update your presence (e.g., "I'm editing invoice X") */
  updatePresence: (data: Partial<PresenceUser>) => void
  /** Track when you start/stop editing a record */
  startEditing: (recordId: string) => void
  stopEditing: () => void
  /** Check if someone else is editing a specific record */
  isRecordBeingEdited: (recordId: string) => PresenceUser | null
}

// ============================================================================
// Main Hook
// ============================================================================

export function useRealtime({
  channelName,
  currentPage,
  onDataChange,
  tables = [],
}: UseRealtimeOptions): UseRealtimeReturn {
  const { user } = useAuth()
  const [onlineUsers, setOnlineUsers] = useState<PresenceUser[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const channelRef = useRef<RealtimeChannel | null>(null)
  const supabaseRef = useRef(getSupabaseClient())

  // Initialize channel and subscriptions
  useEffect(() => {
    if (!user?.id || !channelName) return

    const supabase = supabaseRef.current
    const channel = supabase.channel(`room:${channelName}`, {
      config: {
        presence: { key: user.id },
      },
    })

    // ========================================
    // 1. Presence - Who's online
    // ========================================
    channel.on("presence", { event: "sync" }, () => {
      const state = channel.presenceState<PresenceUser>()
      const users = Object.values(state)
        .flat()
        .filter((u) => u.id !== user.id) // Exclude self
      setOnlineUsers(users as PresenceUser[])
    })

    channel.on("presence", { event: "join" }, ({ newPresences }) => {
      console.log("[Realtime] User joined:", newPresences)
    })

    channel.on("presence", { event: "leave" }, ({ leftPresences }) => {
      console.log("[Realtime] User left:", leftPresences)
    })

    // ========================================
    // 2. Database Changes
    // ========================================
    tables.forEach((table) => {
      channel.on(
        "postgres_changes",
        {
          event: "*", // INSERT, UPDATE, DELETE
          schema: "public",
          table,
        },
        (payload) => {
          const event: RealtimeEvent = {
            type: payload.eventType as "INSERT" | "UPDATE" | "DELETE",
            table,
            record: payload.new,
            oldRecord: payload.old,
            timestamp: new Date(),
          }
          console.log("[Realtime] Database change:", event)
          onDataChange?.(event)
        }
      )
    })

    // ========================================
    // 3. Custom Broadcasts
    // ========================================
    channel.on("broadcast", { event: "*" }, (payload) => {
      console.log("[Realtime] Broadcast received:", payload)
    })

    // Subscribe and track presence
    channel.subscribe(async (status) => {
      if (status === "SUBSCRIBED") {
        setIsConnected(true)
        // Announce our presence
        await channel.track({
          id: user.id,
          email: user.email,
          name: user.user_metadata?.full_name || user.email?.split("@")[0],
          avatar: user.user_metadata?.avatar_url,
          currentPage,
          lastSeen: new Date(),
          isEditing: false,
        })
      } else if (status === "CLOSED" || status === "CHANNEL_ERROR") {
        setIsConnected(false)
      }
    })

    channelRef.current = channel

    // Cleanup
    return () => {
      channel.unsubscribe()
      channelRef.current = null
      setIsConnected(false)
    }
  }, [user?.id, channelName, tables.join(","), onDataChange])

  // Update presence when page changes
  useEffect(() => {
    if (channelRef.current && currentPage) {
      channelRef.current.track({
        id: user?.id,
        currentPage,
        lastSeen: new Date(),
      })
    }
  }, [currentPage, user?.id])

  // ========================================
  // Actions
  // ========================================

  const broadcast = useCallback((event: string, payload: unknown) => {
    channelRef.current?.send({
      type: "broadcast",
      event,
      payload,
    })
  }, [])

  const updatePresence = useCallback(
    (data: Partial<PresenceUser>) => {
      if (channelRef.current && user?.id) {
        channelRef.current.track({
          id: user.id,
          ...data,
          lastSeen: new Date(),
        })
      }
    },
    [user?.id]
  )

  const startEditing = useCallback(
    (recordId: string) => {
      updatePresence({ isEditing: true, editingRecord: recordId })
      broadcast("editing:start", { userId: user?.id, recordId })
    },
    [updatePresence, broadcast, user?.id]
  )

  const stopEditing = useCallback(() => {
    updatePresence({ isEditing: false, editingRecord: undefined })
    broadcast("editing:stop", { userId: user?.id })
  }, [updatePresence, broadcast, user?.id])

  const isRecordBeingEdited = useCallback(
    (recordId: string): PresenceUser | null => {
      return onlineUsers.find((u) => u.editingRecord === recordId) || null
    },
    [onlineUsers]
  )

  return {
    onlineUsers,
    isConnected,
    broadcast,
    updatePresence,
    startEditing,
    stopEditing,
    isRecordBeingEdited,
  }
}

// ============================================================================
// Convenience Hooks
// ============================================================================

/**
 * Hook for showing who's viewing the same page as you
 */
export function usePagePresence(pagePath: string) {
  const { user } = useAuth()

  // Use company ID as channel (all company members see each other)
  // In real implementation, get this from CompanyProvider
  const channelName = user?.id ? `company-${user.id}` : ""

  const { onlineUsers, isConnected } = useRealtime({
    channelName,
    currentPage: pagePath,
  })

  // Filter to users on the same page
  const usersOnSamePage = onlineUsers.filter((u) => u.currentPage === pagePath)

  return {
    usersOnSamePage,
    allOnlineUsers: onlineUsers,
    isConnected,
  }
}

/**
 * Hook for preventing edit conflicts
 */
export function useEditLock(table: string, recordId: string) {
  const { user } = useAuth()
  const channelName = user?.id ? `edit-${table}-${recordId}` : ""

  const { onlineUsers, startEditing, stopEditing, isRecordBeingEdited } =
    useRealtime({
      channelName,
      tables: [table],
    })

  const lockedBy = isRecordBeingEdited(recordId)
  const isLocked = lockedBy !== null && lockedBy.id !== user?.id

  return {
    isLocked,
    lockedBy,
    acquireLock: () => startEditing(recordId),
    releaseLock: stopEditing,
    editors: onlineUsers.filter((u) => u.isEditing),
  }
}

/**
 * React Query hooks for transactions data fetching
 * 
 * This is a drop-in replacement for use-transactions.ts with React Query benefits:
 * - Automatic caching and deduplication
 * - Background refetching (stale-while-revalidate)
 * - Optimistic updates with automatic rollback
 * - Request deduplication across components
 * - Configurable cache times
 */

import { useState, useCallback, useMemo, useEffect } from "react"
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import type { TransactionFilters, SortConfig, Transaction, TransactionWithAI } from "@/types"
import type { TransactionStatus } from "@/lib/status-types"
import * as transactionService from "@/services/transactions"
import { useAuth } from "./use-auth"

// ============================================================================
// Query Keys - Centralized key management for cache invalidation
// ============================================================================

export const transactionQueryKeys = {
    all: ["transactions"] as const,
    list: (userId: string | null) => [...transactionQueryKeys.all, "list", userId] as const,
    paginated: (userId: string | null, page: number, pageSize: number, filters?: TransactionFilters, sort?: SortConfig<Transaction>) =>
        [...transactionQueryKeys.all, "paginated", userId, page, pageSize, JSON.stringify(filters), JSON.stringify(sort)] as const,
    byStatus: (userId: string | null, status: TransactionStatus) =>
        [...transactionQueryKeys.all, "byStatus", userId, status] as const,
    stats: (userId: string | null) => [...transactionQueryKeys.all, "stats", userId] as const,
    detail: (id: string) => [...transactionQueryKeys.all, "detail", id] as const,
} as const

// ============================================================================
// Cache Configuration
// ============================================================================

const CACHE_CONFIG = {
    // Keep data fresh for 30 seconds before refetching in background
    staleTime: 30 * 1000,
    // Keep unused data in cache for 5 minutes
    gcTime: 5 * 60 * 1000,
    // Paginated data stays fresh for 1 minute (less frequently accessed)
    paginatedStaleTime: 60 * 1000,
} as const

// ============================================================================
// useTransactions Hook - Main transactions data (React Query version)
// Drop-in replacement for the original useTransactions
// ============================================================================

export function useTransactions() {
    const { user } = useAuth()
    const userId = user?.id ?? null
    const isAuthenticated = !!user
    const queryClient = useQueryClient()

    // Main query for transactions list
    const {
        data: transactions = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: transactionQueryKeys.list(userId),
        queryFn: async () => {
            if (isAuthenticated && userId) {
                const response = await transactionService.getTransactionsWithAI(userId)
                if (!response.success) throw new Error(response.error || "Failed to fetch transactions")
                return response.data || []
            }
            return []
        },
        staleTime: CACHE_CONFIG.staleTime,
        gcTime: CACHE_CONFIG.gcTime,
        enabled: isAuthenticated,
    })

    // Update status mutation with optimistic updates
    const updateStatusMutation = useMutation({
        mutationFn: async ({ id, status }: { id: string; status: TransactionStatus }) => {
            if (isAuthenticated && userId) {
                const response = await transactionService.updateTransactionStatus(id, userId, status)
                if (!response.success) throw new Error(response.error || "Failed to update status")
            }
            return { id, status }
        },
        onMutate: async ({ id, status }) => {
            // Cancel outgoing refetches
            await queryClient.cancelQueries({ queryKey: transactionQueryKeys.list(userId) })

            // Snapshot previous value for rollback
            const previousTransactions = queryClient.getQueryData<TransactionWithAI[]>(
                transactionQueryKeys.list(userId)
            )

            // Optimistically update the cache
            if (previousTransactions) {
                queryClient.setQueryData<TransactionWithAI[]>(
                    transactionQueryKeys.list(userId),
                    previousTransactions.map(t => t.id === id ? { ...t, status } : t)
                )
            }

            return { previousTransactions }
        },
        onError: (_err, _variables, context) => {
            // Rollback on error
            if (context?.previousTransactions) {
                queryClient.setQueryData(
                    transactionQueryKeys.list(userId),
                    context.previousTransactions
                )
            }
        },
        onSettled: () => {
            // Refetch to ensure we have the latest data
            queryClient.invalidateQueries({ queryKey: transactionQueryKeys.all })
        },
    })

    // Delete mutation with optimistic updates
    const deleteMutation = useMutation({
        mutationFn: async (id: string) => {
            if (!isAuthenticated || !userId) {
                throw new Error("Must be authenticated to delete transactions")
            }
            const response = await transactionService.deleteTransaction(id, userId)
            if (!response.success) throw new Error(response.error || "Failed to delete transaction")
            return id
        },
        onMutate: async (id) => {
            await queryClient.cancelQueries({ queryKey: transactionQueryKeys.list(userId) })

            const previousTransactions = queryClient.getQueryData<TransactionWithAI[]>(
                transactionQueryKeys.list(userId)
            )

            if (previousTransactions) {
                queryClient.setQueryData<TransactionWithAI[]>(
                    transactionQueryKeys.list(userId),
                    previousTransactions.filter(t => t.id !== id)
                )
            }

            return { previousTransactions }
        },
        onError: (_err, _id, context) => {
            if (context?.previousTransactions) {
                queryClient.setQueryData(
                    transactionQueryKeys.list(userId),
                    context.previousTransactions
                )
            }
        },
        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: transactionQueryKeys.all })
        },
    })

    // Wrapper functions to match original API
    const updateStatus = useCallback(async (id: string, status: TransactionStatus) => {
        await updateStatusMutation.mutateAsync({ id, status })
    }, [updateStatusMutation])

    const deleteTransaction = useCallback(async (id: string) => {
        await deleteMutation.mutateAsync(id)
    }, [deleteMutation])

    return {
        transactions,
        isLoading,
        error: error || updateStatusMutation.error || deleteMutation.error,
        refetch,
        updateStatus,
        deleteTransaction,
    }
}

// ============================================================================
// useTransactionsPaginated Hook - Paginated data with filters
// ============================================================================

export function useTransactionsPaginated(initialPageSize: number = 20) {
    const { user } = useAuth()
    const userId = user?.id ?? null
    const isAuthenticated = !!user

    const [page, setPage] = useState(1)
    const [filters, setFilters] = useState<TransactionFilters>({})
    const [sort, setSort] = useState<SortConfig<Transaction> | undefined>()

    // Reset page when filters change
    useEffect(() => { setPage(1) }, [filters])

    const {
        data,
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: transactionQueryKeys.paginated(userId, page, initialPageSize, filters, sort),
        queryFn: async () => {
            if (isAuthenticated && userId) {
                const response = await transactionService.getTransactionsPaginated(
                    userId, page, initialPageSize, filters, sort
                )
                return response
            }
            return { data: [], total: 0, page: 1, pageSize: initialPageSize, hasMore: false }
        },
        staleTime: CACHE_CONFIG.paginatedStaleTime,
        gcTime: CACHE_CONFIG.gcTime,
        enabled: isAuthenticated,
        // Keep previous data while fetching next page
        placeholderData: (previousData) => previousData,
    })

    const transactions = data?.data ?? []
    const total = data?.total ?? 0
    const hasMore = data?.hasMore ?? false

    const nextPage = useCallback(() => { if (hasMore) setPage(p => p + 1) }, [hasMore])
    const prevPage = useCallback(() => { if (page > 1) setPage(p => p - 1) }, [page])

    return {
        transactions,
        isLoading,
        error,
        page,
        pageSize: initialPageSize,
        total,
        hasMore,
        filters,
        sort,
        setFilters,
        setSort,
        setPage,
        nextPage,
        prevPage,
        refetch,
    }
}

