/**
 * Prefetch transactions for a user (useful for route prefetching)
 */
export async function prefetchTransactions(
    queryClient: ReturnType<typeof useQueryClient>,
    userId: string
) {
    await queryClient.prefetchQuery({
        queryKey: transactionQueryKeys.list(userId),
        queryFn: async () => {
            const response = await transactionService.getTransactionsWithAI(userId)
            if (!response.success) throw new Error(response.error || "Failed to fetch transactions")
            return response.data || []
        },
        staleTime: CACHE_CONFIG.staleTime,
    })
}

/**
 * Invalidate all transaction queries (useful after bulk operations)
 */
export function useInvalidateTransactions() {
    const queryClient = useQueryClient()
    return useCallback(() => {
        queryClient.invalidateQueries({ queryKey: transactionQueryKeys.all })
    }, [queryClient])
}

/**
 * Scope Brain - Unified AI Agent
 *
 * Single agent with access to all tools and domain expertise.
 * Uses OpenAI GPT-4o with tool calling and streaming.
 */

import type {
    AgentContext,
    AgentResponse,
    AgentToolResult,
    LLMMessage,
    LLMToolDefinition,
} from '../types'
import { aiToolRegistry } from '../../ai-tools/registry'
import { selectModel, getModelId, type ModelConfig } from './model-selector'
import { buildSystemPrompt } from './system-prompt'
import type OpenAI from 'openai'

// =============================================================================
// Types
// =============================================================================

export interface ScopeBrainOptions {
    /** Override automatic model selection */
    forceModel?: ModelConfig
    /** Maximum tool execution iterations */
    maxToolIterations?: number
    /** Temperature for LLM calls */
    temperature?: number
}

export interface StreamChunk {
    type: 'text' | 'thinking' | 'tool_start' | 'tool_result' | 'error' | 'done'
    content?: string
    toolName?: string
    toolResult?: AgentToolResult
    error?: string
}

// =============================================================================
// Scope Brain Implementation
// =============================================================================

export class ScopeBrain {
    private options: ScopeBrainOptions

    constructor(options: ScopeBrainOptions = {}) {
        this.options = {
            maxToolIterations: 10,
            temperature: 0.7,
            ...options,
        }
    }

    // =========================================================================
    // Main Handle Method
    // =========================================================================

    async handle(message: string, context: AgentContext): Promise<AgentResponse> {
        try {
            const modelConfig = this.options.forceModel ?? selectModel(message)
            const modelId = getModelId(modelConfig)

            console.log(`[ScopeBrain] Using model: ${modelId}`)

            const messages = this.buildMessages(message, context)
            const tools = this.getAllToolDefinitions()

            const { text, toolResults } = await this.callLLMWithTools(modelId, messages, tools, context)

            return {
                success: true,
                message: text,
                agentId: 'orchestrator',
                toolResults: toolResults.length > 0 ? toolResults : undefined,
            }
        } catch (error) {
            console.error('[ScopeBrain] Error:', error)
            return {
                success: false,
                message: 'Ett fel uppstod. Försök igen.',
                error: error instanceof Error ? error.message : 'Unknown error',
                shouldRetry: true,
                agentId: 'orchestrator',
            }
        }
    }

    // =========================================================================
    // Streaming Support
    // =========================================================================

    async *handleStream(
        message: string,
        context: AgentContext
    ): AsyncGenerator<StreamChunk> {
        try {
            const modelConfig = this.options.forceModel ?? selectModel(message)
            const modelId = getModelId(modelConfig)

            console.log(`[ScopeBrain] Streaming with model: ${modelId}`)

            const messages = this.buildMessages(message, context)
            const tools = this.getAllToolDefinitions()

            yield* this.streamLLMWithTools(modelId, messages, tools, context)

            yield { type: 'done' }
        } catch (error) {
            yield {
                type: 'error',
                error: error instanceof Error ? error.message : 'Unknown error',
            }
        }
    }

    // =========================================================================
    // LLM Integration
    // =========================================================================

    private async callLLMWithTools(
        modelId: string,
        messages: LLMMessage[],
        tools: LLMToolDefinition[],
        context: AgentContext,
    ): Promise<{ text: string; toolResults: AgentToolResult[] }> {
        const { default: OpenAIClient } = await import('openai')
        const openai = new OpenAIClient({ apiKey: process.env.OPENAI_API_KEY })

        const allToolResults: AgentToolResult[] = []
        let iterations = 0
        let currentMessages = [...messages]

        while (iterations < (this.options.maxToolIterations ?? 10)) {
            const openaiMessages = this.convertToOpenAIMessages(currentMessages)
            const openaiTools = this.convertToOpenAITools(tools)

            const response = await openai.chat.completions.create({
                model: modelId,
                messages: openaiMessages,
                tools: openaiTools.length > 0 ? openaiTools : undefined,
                tool_choice: openaiTools.length > 0 ? 'auto' : undefined,
                max_tokens: 4096,
                temperature: this.options.temperature ?? 0.7,
            })

            const choice = response.choices[0]
            const textContent = choice.message.content || ''
            // Cast to the standard tool call type (OpenAI SDK union can include custom types)
            type StandardToolCall = { id: string; function: { name: string; arguments: string } }
            const toolCalls = (choice.message.tool_calls || []) as StandardToolCall[]

            if (choice.finish_reason !== 'tool_calls' || toolCalls.length === 0) {
                return { text: textContent, toolResults: allToolResults }
            }

            const toolResults = await Promise.all(
                toolCalls.map(async (tc) => {
                    let params: Record<string, unknown> = {}
                    try { params = JSON.parse(tc.function.arguments || '{}') } catch { /* use empty */ }
                    return this.executeTool(tc.function.name, params, context)
                })
            )
            allToolResults.push(...toolResults)

            currentMessages.push({ role: 'assistant', content: textContent })

            for (let i = 0; i < toolCalls.length; i++) {
                const tc = toolCalls[i]
                currentMessages.push({
                    role: 'tool',
                    content: JSON.stringify(toolResults[i].result ?? toolResults[i].error),
                    toolCallId: tc.id,
                    name: tc.function.name,
                })
            }

            iterations++
        }

        throw new Error(`Tool execution loop exceeded ${this.options.maxToolIterations} iterations`)
    }

    private async *streamLLMWithTools(
        modelId: string,
        messages: LLMMessage[],
        tools: LLMToolDefinition[],
        context: AgentContext,
    ): AsyncGenerator<StreamChunk> {
        const { default: OpenAIClient } = await import('openai')
        const openai = new OpenAIClient({ apiKey: process.env.OPENAI_API_KEY })

        let currentMessages = [...messages]
        let iterations = 0

        while (iterations < (this.options.maxToolIterations ?? 10)) {
            const openaiMessages = this.convertToOpenAIMessages(currentMessages)
            const openaiTools = this.convertToOpenAITools(tools)

            const stream = await openai.chat.completions.create({
                model: modelId,
                messages: openaiMessages,
                tools: openaiTools.length > 0 ? openaiTools : undefined,
                tool_choice: openaiTools.length > 0 ? 'auto' : undefined,
                max_tokens: 4096,
                temperature: this.options.temperature ?? 0.7,
                stream: true,
            })

            let fullText = ''
            // Map from tool call index → accumulated buffer
            const toolCallBuffers = new Map<number, { id: string; name: string; args: string }>()

            for await (const chunk of stream) {
                const delta = chunk.choices[0]?.delta

                if (delta?.content) {
                    fullText += delta.content
                    yield { type: 'text', content: delta.content }
                }

                if (delta?.tool_calls) {
                    for (const tc of delta.tool_calls) {
                        const idx = tc.index
                        if (!toolCallBuffers.has(idx)) {
                            toolCallBuffers.set(idx, { id: tc.id || '', name: tc.function?.name || '', args: '' })
                            if (tc.function?.name) {
                                yield { type: 'tool_start', toolName: tc.function.name }
                            }
                        }
                        const buf = toolCallBuffers.get(idx)!
                        if (tc.id) buf.id = tc.id
                        if (tc.function?.name) buf.name = tc.function.name
                        if (tc.function?.arguments) buf.args += tc.function.arguments
                    }
                }
            }

            if (toolCallBuffers.size === 0) {
                return
            }

            // Execute tools and add to message history
            const toolCalls = Array.from(toolCallBuffers.values())
            const toolResults: AgentToolResult[] = []

            for (const tc of toolCalls) {
                let params: Record<string, unknown> = {}
                try { params = JSON.parse(tc.args || '{}') } catch { /* use empty */ }
                const result = await this.executeTool(tc.name, params, context)
                toolResults.push(result)
                yield { type: 'tool_result', toolName: tc.name, toolResult: result }
            }

            currentMessages.push({ role: 'assistant', content: fullText })

            for (let i = 0; i < toolCalls.length; i++) {
                currentMessages.push({
                    role: 'tool',
                    content: JSON.stringify(toolResults[i].result ?? toolResults[i].error),
                    toolCallId: toolCalls[i].id,
                    name: toolCalls[i].name,
                })
            }

            iterations++
        }
    }

    // =========================================================================
    // Tool Execution
    // =========================================================================

    private async executeTool(
        toolName: string,
        params: Record<string, unknown>,
        context: AgentContext
    ): Promise<AgentToolResult> {
        try {
            const result = await aiToolRegistry.execute(toolName, params, {
                userId: context.userId,
                companyId: context.companyId,
            })

            return {
                toolCallId: crypto.randomUUID(),
                toolName,
                success: result.success,
                result: result.data,
                error: result.error,
            }
        } catch (error) {
            return {
                toolCallId: crypto.randomUUID(),
                toolName,
                success: false,
                error: error instanceof Error ? error.message : 'Unknown error',
            }
        }
    }

    // =========================================================================
    // Message Building
    // =========================================================================

    private buildMessages(userMessage: string, context: AgentContext): LLMMessage[] {
        const systemPrompt = buildSystemPrompt(context)

        const messages: LLMMessage[] = [
            { role: 'system', content: systemPrompt },
        ]

        for (const msg of context.conversationHistory) {
            if (msg.from === 'user') {
                messages.push({ role: 'user', content: msg.content })
            } else {
                messages.push({ role: 'assistant', content: msg.content })
            }
        }

        messages.push({ role: 'user', content: userMessage })

        return messages
    }

    private getAllToolDefinitions(): LLMToolDefinition[] {
        return aiToolRegistry.getAll().map(tool => ({
            type: 'function' as const,
            function: {
                name: tool.name,
                description: tool.description,
                parameters: tool.parameters as Record<string, unknown>,
            },
        }))
    }

    // =========================================================================
    // OpenAI Format Conversion
    // =========================================================================

    private convertToOpenAIMessages(messages: LLMMessage[]): OpenAI.ChatCompletionMessageParam[] {
        return messages.map(m => {
            if (m.role === 'tool') {
                return {
                    role: 'tool' as const,
                    tool_call_id: m.toolCallId!,
                    content: m.content,
                }
            }
            if (m.role === 'system') {
                return { role: 'system' as const, content: m.content }
            }
            if (m.role === 'assistant') {
                return { role: 'assistant' as const, content: m.content }
            }
            return { role: 'user' as const, content: m.content }
        })
    }

    private convertToOpenAITools(tools: LLMToolDefinition[]): OpenAI.ChatCompletionTool[] {
        return tools.map(t => ({
            type: 'function' as const,
            function: {
                name: t.function.name,
                description: t.function.description,
                parameters: t.function.parameters,
            },
        }))
    }
}

// =============================================================================
// Factory Functions
// =============================================================================

export function createScopeBrain(options?: ScopeBrainOptions): ScopeBrain {
    return new ScopeBrain(options)
}

export async function handleWithScopeBrain(
    message: string,
    context: AgentContext,
    options?: ScopeBrainOptions
): Promise<AgentResponse> {
    const brain = new ScopeBrain(options)
    return brain.handle(message, context)
}

/**
 * Bokföring AI Tools - Balance Sheet Audit
 *
 * Comprehensive balanskontroll that cross-references data
 * from multiple domains like a Swedish accountant would.
 */

import { defineTool } from '../registry'
import { db } from '../../database/server-db'
import { getSupabaseAdmin } from '../../database/supabase'

// =============================================================================
// Types
// =============================================================================

export interface AuditCheck {
    name: string
    status: 'pass' | 'warning' | 'fail'
    description: string
    details?: string
}

export interface AuditResult {
    date: string
    fiscalYear: number
    checks: AuditCheck[]
    summary: {
        total: number
        passed: number
        warnings: number
        failed: number
    }
}

// =============================================================================
// Balance Sheet Audit Tool
// =============================================================================

export const runBalanceSheetAuditTool = defineTool<Record<string, never>, AuditResult>({
    name: 'run_balance_sheet_audit',
    description: 'Kör en komplett balanskontroll som kontrollerar balansräkningsprov, momsavstämning, kundfordringar, leverantörsskulder, löneavstämning, avskrivningar, eget kapital och periodiseringar. Samlar data från hela bokföringen och korsrefererar som en revisor.',
    category: 'read',
    requiresConfirmation: false,
    parameters: { type: 'object', properties: {} },
    execute: async () => {
        const year = new Date().getFullYear()
        const dateFrom = `${year}-01-01`
        const dateTo = `${year}-12-31`
        const supabase = getSupabaseAdmin()

        // Gather all data in parallel
        const [
            balancesResult,
            customerInvoices,
            supplierInvoices,
            payslips,
            shareholders,
            taxReports,
        ] = await Promise.all([
            supabase.rpc('get_account_balances', {
                p_start_date: '2000-01-01',
                p_end_date: dateTo,
            }),
            db.getCustomerInvoices({ limit: 500 }),
            db.getSupplierInvoices({ limit: 500 }),
            db.getPayslips(500),
            db.getShareholders(),
            db.getTaxReports('vat'),
        ])

        const balances: Array<{ account: string; balance: number }> = (balancesResult.data || []).map((row: { account_number: number; balance: number }) => ({
            account: String(row.account_number),
            balance: row.balance,
        }))

        // Build account balance lookup
        const accountBalance = (start: number, end: number): number => {
            return balances
                .filter(b => {
                    const acc = parseInt(b.account)
                    return acc >= start && acc <= end
                })
                .reduce((sum, b) => sum + b.balance, 0)
        }

        const hasAccountsInRange = (start: number, end: number): boolean => {
            return balances.some(b => {
                const acc = parseInt(b.account)
                return acc >= start && acc <= end && Math.abs(b.balance) > 0.01
            })
        }

        const checks: AuditCheck[] = []

        // =====================================================================
        // 1. Balansräkningsprov — Assets = Equity + Liabilities
        // =====================================================================
        {
            const assets = -(accountBalance(1000, 1999)) // Assets have negative balance in Swedish accounting
            const equityAndLiabilities = accountBalance(2000, 2999)
            const diff = Math.abs(assets - equityAndLiabilities)

            if (diff < 1) {
                checks.push({
                    name: 'Balansräkningsprov',
                    status: 'pass',
                    description: 'Tillgångar = Eget kapital + Skulder',
                    details: `Tillgångar: ${assets.toLocaleString('sv-SE')} kr, EK+Skulder: ${equityAndLiabilities.toLocaleString('sv-SE')} kr`,
                })
            } else {
                checks.push({
                    name: 'Balansräkningsprov',
                    status: 'fail',
                    description: 'Tillgångar stämmer inte med Eget kapital + Skulder',
                    details: `Differens: ${diff.toLocaleString('sv-SE')} kr (Tillgångar: ${assets.toLocaleString('sv-SE')} kr, EK+Skulder: ${equityAndLiabilities.toLocaleString('sv-SE')} kr)`,
                })
            }
        }

        // =====================================================================
        // 2. Momsavstämning — Booked VAT matches declarations
        // =====================================================================
        {
            const outputVat = accountBalance(2610, 2619) // Utgående moms
            const inputVat = accountBalance(2640, 2649)   // Ingående moms
            const vatDebt = accountBalance(2650, 2659)    // Momsredovisning

            const bookedVatNet = outputVat + inputVat + vatDebt

            if (Math.abs(bookedVatNet) < 100) {
                checks.push({
                    name: 'Momsavstämning',
                    status: 'pass',
                    description: 'Momskonton stämmer',
                    details: `Utgående: ${outputVat.toLocaleString('sv-SE')} kr, Ingående: ${inputVat.toLocaleString('sv-SE')} kr`,
                })
            } else {
                checks.push({
                    name: 'Momsavstämning',
                    status: 'warning',
                    description: 'Momskonton har oavstämd differens',
                    details: `Oavstämt saldo: ${bookedVatNet.toLocaleString('sv-SE')} kr. Kontrollera att momsdeklaration är bokförd.`,
                })
            }
        }

        // =====================================================================
        // 3. Kundfordringar — Open invoices match account 1510
        // =====================================================================
        {
            const accountBal = -(accountBalance(1510, 1519))
            const openInvoices = (customerInvoices || [])
                .filter((i: any) => i.status !== 'paid' && i.status !== 'cancelled')
            const invoiceTotal = openInvoices.reduce((sum: number, i: any) => sum + (i.total_amount || i.totalAmount || 0), 0)

            const overdueInvoices = openInvoices.filter((i: any) => {
                const due = new Date(i.due_date || i.dueDate)
                const daysOverdue = (Date.now() - due.getTime()) / (1000 * 60 * 60 * 24)
                return daysOverdue > 90
            })

            if (overdueInvoices.length > 0) {
                checks.push({
                    name: 'Kundfordringar',
                    status: 'warning',
                    description: `${overdueInvoices.length} fakturor förfallna >90 dagar`,
                    details: `Konto 1510: ${accountBal.toLocaleString('sv-SE')} kr, Öppna fakturor: ${invoiceTotal.toLocaleString('sv-SE')} kr`,
                })
            } else if (Math.abs(accountBal - invoiceTotal) > 100 && (accountBal > 0 || invoiceTotal > 0)) {
                checks.push({
                    name: 'Kundfordringar',
                    status: 'warning',
                    description: 'Konto 1510 matchar inte öppna fakturor',
                    details: `Konto 1510: ${accountBal.toLocaleString('sv-SE')} kr, Öppna fakturor: ${invoiceTotal.toLocaleString('sv-SE')} kr`,
                })
            } else {
                checks.push({
                    name: 'Kundfordringar',
                    status: 'pass',
                    description: 'Kundfordringar stämmer',
                    details: `Konto 1510: ${accountBal.toLocaleString('sv-SE')} kr`,
                })
            }
        }

        // =====================================================================
        // 4. Leverantörsskulder — Open bills match account 2440
        // =====================================================================
        {
            const accountBal = accountBalance(2440, 2449)
            const openBills = (supplierInvoices || [])
                .filter((i: any) => i.status !== 'paid' && i.status !== 'cancelled')
            const billsTotal = openBills.reduce((sum: number, i: any) => sum + (i.total_amount || i.totalAmount || 0), 0)

            if (Math.abs(accountBal - billsTotal) > 100 && (Math.abs(accountBal) > 0 || billsTotal > 0)) {
                checks.push({
                    name: 'Leverantörsskulder',
                    status: 'warning',
                    description: 'Konto 2440 matchar inte öppna leverantörsfakturor',
                    details: `Konto 2440: ${accountBal.toLocaleString('sv-SE')} kr, Öppna fakturor: ${billsTotal.toLocaleString('sv-SE')} kr`,
                })
            } else {
                checks.push({
                    name: 'Leverantörsskulder',
                    status: 'pass',
                    description: 'Leverantörsskulder stämmer',
                    details: `Konto 2440: ${accountBal.toLocaleString('sv-SE')} kr`,
                })
            }
        }

        // =====================================================================
        // 5. Löneavstämning — Payroll liabilities match payslips
        // =====================================================================
        {
            const skatteSkuld = accountBalance(2710, 2719)     // Personalskatt
            const agAvgifter = accountBalance(2730, 2739)      // Arbetsgivaravgifter
            const nettoLon = accountBalance(2790, 2799)        // Löneskulder

            const totalLiabilities = skatteSkuld + agAvgifter + nettoLon
            const payslipList = payslips || []

            if (payslipList.length === 0 && Math.abs(totalLiabilities) < 1) {
                checks.push({
                    name: 'Löneavstämning',
                    status: 'pass',
                    description: 'Inga löner bokförda',
                })
            } else if (Math.abs(totalLiabilities) > 100) {
                checks.push({
                    name: 'Löneavstämning',
                    status: 'warning',
                    description: 'Utestående löneskulder',
                    details: `Personalskatt: ${skatteSkuld.toLocaleString('sv-SE')} kr, AG-avgifter: ${agAvgifter.toLocaleString('sv-SE')} kr, Löneskuld: ${nettoLon.toLocaleString('sv-SE')} kr`,
                })
            } else {
                checks.push({
                    name: 'Löneavstämning',
                    status: 'pass',
                    description: 'Lönekonton avstämda',
                    details: `${payslipList.length} lönebesked bokförda`,
                })
            }
        }

        // =====================================================================
        // 6. Avskrivningar — Depreciation booked for fixed assets
        // =====================================================================
        {
            const hasFixedAssets = hasAccountsInRange(1200, 1299)
            const hasDepreciation = hasAccountsInRange(7800, 7899)

            if (hasFixedAssets && !hasDepreciation) {
                checks.push({
                    name: 'Avskrivningar',
                    status: 'fail',
                    description: `Anläggningstillgångar finns men avskrivningar saknas för ${year}`,
                    details: 'Konton 1200-1299 har saldon men inga avskrivningar på 7800-7899.',
                })
            } else if (hasFixedAssets && hasDepreciation) {
                checks.push({
                    name: 'Avskrivningar',
                    status: 'pass',
                    description: 'Avskrivningar bokförda',
                })
            } else {
                checks.push({
                    name: 'Avskrivningar',
                    status: 'pass',
                    description: 'Inga anläggningstillgångar att skriva av',
                })
            }
        }

        // =====================================================================
        // 7. Eget kapital — Matches shareholder register
        // =====================================================================
        {
            const aktiekapital = accountBalance(2081, 2081) // Aktiekapital
            const shareholderList = shareholders || []

            if (shareholderList.length === 0) {
                if (Math.abs(aktiekapital) > 0) {
                    checks.push({
                        name: 'Eget kapital',
                        status: 'warning',
                        description: 'Aktiekapital bokfört men inget ägarregister registrerat',
                        details: `Konto 2081: ${aktiekapital.toLocaleString('sv-SE')} kr`,
                    })
                } else {
                    checks.push({
                        name: 'Eget kapital',
                        status: 'pass',
                        description: 'Inget eget kapital att kontrollera',
                    })
                }
            } else {
                checks.push({
                    name: 'Eget kapital',
                    status: 'pass',
                    description: 'Ägarregister registrerat',
                    details: `${shareholderList.length} ägare, Aktiekapital konto 2081: ${aktiekapital.toLocaleString('sv-SE')} kr`,
                })
            }
        }

        // =====================================================================
        // 8. Periodiseringar — Accruals/prepayments at period end
        // =====================================================================
        {
            const forutbetald = hasAccountsInRange(1700, 1799) // Förutbetalda kostnader
            const upplupen = hasAccountsInRange(2900, 2999)     // Upplupna kostnader

            const now = new Date()
            const isYearEnd = now.getMonth() >= 10 // Nov-Dec

            if (isYearEnd && !forutbetald && !upplupen) {
                checks.push({
                    name: 'Periodiseringar',
                    status: 'warning',
                    description: 'Inga periodiseringar bokförda nära årsskifte',
                    details: 'Kontrollera om förutbetalda kostnader (1700) eller upplupna kostnader (2900) behöver bokföras.',
                })
            } else {
                checks.push({
                    name: 'Periodiseringar',
                    status: 'pass',
                    description: forutbetald || upplupen
                        ? 'Periodiseringar finns bokförda'
                        : 'Inga periodiseringar krävs för perioden',
                })
            }
        }

        // Build summary
        const summary = {
            total: checks.length,
            passed: checks.filter(c => c.status === 'pass').length,
            warnings: checks.filter(c => c.status === 'warning').length,
            failed: checks.filter(c => c.status === 'fail').length,
        }

        const result: AuditResult = {
            date: new Date().toISOString().split('T')[0],
            fiscalYear: year,
            checks,
            summary,
        }

        // Build message for AI
        const statusEmoji = summary.failed > 0 ? '❌' : summary.warnings > 0 ? '⚠️' : '✅'
        const checkDetails = checks.map(c => {
            const icon = c.status === 'pass' ? '✅' : c.status === 'warning' ? '⚠️' : '❌'
            return `${icon} **${c.name}**: ${c.description}` + (c.details ? `\n   ${c.details}` : '')
        }).join('\n\n')

        const message = `${statusEmoji} Balanskontroll klar: ${summary.passed}/${summary.total} godkända` +
            (summary.warnings > 0 ? `, ${summary.warnings} varningar` : '') +
            (summary.failed > 0 ? `, ${summary.failed} fel` : '') +
            '.\n\n' + checkDetails +
            '\n\n---\n\n' +
            'Resultatet visas i en walkthrough-vy för användaren. Skriv en kort kommentar (2-4 meningar) som en revisor skulle göra: ' +
            'beskriv din tankeprocess, vad du har analyserat, om något väckte din uppmärksamhet, och om det finns något användaren bör agera på. ' +
            'Skriv i första person, direkt till användaren. Skriv INTE ut kontrollerna igen — de visas redan i vyn.'

        return {
            success: true,
            data: {
                ...result,
                walkthrough: {
                    title: 'Balanskontroll',
                    summary: `${summary.passed}/${summary.total} godkända` +
                        (summary.warnings > 0 ? `, ${summary.warnings} varningar` : '') +
                        (summary.failed > 0 ? `, ${summary.failed} fel` : ''),
                    date: result.date,
                    sections: checks.map(c => ({
                        heading: c.name,
                        status: c.status,
                        description: c.description,
                        details: c.details,
                    })),
                },
            },
            message,
        }
    },
})

export const auditTools = [runBalanceSheetAuditTool]

import { AITool, InteractionContext } from "@/lib/ai-tools/types"
import { verificationService } from '@/services/verification-service'

interface VerificationRow {
    account: string
    description?: string
    debit?: number
    credit?: number
}

export const createVerificationTool: AITool = {
    name: "create_verification",
    description: "Proposes a new manual journal entry (verification). Use this when user wants to book something manually. Requires balanced debit/credit rows.",
    requiresConfirmation: true,
    category: 'write',
    parameters: {
        type: 'object',
        properties: {
            description: { type: 'string', description: 'Description of the transaction' },
            date: { type: 'string', description: 'Date YYYY-MM-DD. Defaults to today.' },
            rows: {
                type: 'array',
                description: 'List of transaction rows. Must balance.',
                items: {
                    type: 'object',
                    properties: {
                        account: { type: 'string', description: 'Account number (e.g. 1930)' },
                        description: { type: 'string', description: 'Row specific description if different' },
                        debit: { type: 'number', description: 'Debit amount' },
                        credit: { type: 'number', description: 'Credit amount' }
                    },
                    required: ['account']
                }
            }
        },
        required: ['description', 'rows']
    },

    execute: async (params: unknown, context: InteractionContext) => {
        const { description, date, rows } = params as { description: string, date?: string, rows: VerificationRow[] }

        // Validate balance
        const totalDebit = rows.reduce((sum, r) => sum + (r.debit || 0), 0)
        const totalCredit = rows.reduce((sum, r) => sum + (r.credit || 0), 0)

        if (Math.abs(totalDebit - totalCredit) > 0.01) {
            return {
                success: false,
                error: `Verifikationen balanserar inte. Debet: ${totalDebit} kr, Kredit: ${totalCredit} kr. Differens: ${Math.abs(totalDebit - totalCredit)} kr.`,
            }
        }

        // If confirmed, persist to database
        if (context?.isConfirmed) {
            try {
                const verification = await verificationService.createVerification({
                    series: 'A',
                    date: date || new Date().toISOString().split('T')[0],
                    description,
                    entries: rows.map(r => ({
                        account: r.account,
                        debit: r.debit || 0,
                        credit: r.credit || 0,
                        description: r.description || description,
                    })),
                    sourceType: 'ai',
                })

                return {
                    success: true,
                    data: verification,
                    message: `Verifikation "${description}" har bokförts. ${rows.length} rader, totalt ${totalDebit.toLocaleString('sv-SE')} kr.`,
                }
            } catch (error) {
                return {
                    success: false,
                    error: 'Kunde inte spara verifikation till databasen.',
                }
            }
        }

        // Preflight: return confirmation request
        const rowSummary = rows.map(r =>
            `${r.account}: ${r.debit ? `D ${r.debit}` : ''} ${r.credit ? `K ${r.credit}` : ''}`
        ).join(', ')

        return {
            success: true,
            message: `Jag har förberett ett verifikat för "${description}". Bekräfta för att bokföra.`,
            confirmationRequired: {
                title: `Vill du bokföra "${description}"?`,
                description: "Detta skapar en verifikation i bokföringen.",
                summary: [
                    { label: "Verifikation", value: description },
                    { label: "Datum", value: date || new Date().toISOString().split('T')[0] },
                    { label: "Rader", value: `${rows.length} rader` },
                    { label: "Belopp", value: `${totalDebit.toLocaleString('sv-SE')} kr` },
                ],
                action: {
                    toolName: "create_verification",
                    params: params as Record<string, unknown>
                }
            }
        }
    }
}

/**
 * Bokföring AI Tools - Inventarier (Assets)
 *
 * Tools for managing fixed assets, depreciation, and disposal.
 */

import { defineTool, AIConfirmationRequest } from '../registry'
import { inventarieService, type Inventarie } from '@/services/inventarie-service'

// =============================================================================
// Get Assets Tool
// =============================================================================

export interface GetAssetsParams {
    limit?: number
    kategori?: string
    status?: 'aktiv' | 'såld' | 'avskriven'
}

export const getAssetsTool = defineTool<GetAssetsParams, Inventarie[]>({
    name: 'get_assets',
    description: 'Hämta inventarier och anläggningstillgångar (maskiner, datorer, möbler etc). Visar inköpspris, kvarvarande värde och avskrivningsstatus.',
    category: 'read',
    requiresConfirmation: false,
    parameters: {
        type: 'object',
        properties: {
            limit: { type: 'number', description: 'Max antal att hämta (standard: 50)' },
            kategori: { type: 'string', description: 'Filtrera på kategori (t.ex. "Datorer", "Möbler")' },
            status: { type: 'string', enum: ['aktiv', 'såld', 'avskriven'], description: 'Filtrera på status' },
        },
    },
    execute: async (params) => {
        const { inventarier, totalCount } = await inventarieService.getInventarier({
            limit: params.limit ?? 50,
            kategori: params.kategori,
        })

        // Filter by status locally if needed
        let filtered = inventarier
        if (params.status) {
            filtered = inventarier.filter(i => i.status === params.status)
        }

        const totalValue = filtered.reduce((sum, i) => sum + i.inkopspris, 0)

        return {
            success: true,
            data: filtered,
            message: filtered.length > 0
                ? `${filtered.length} inventarier med totalt inköpsvärde ${totalValue.toLocaleString('sv-SE')} kr.`
                : 'Inga inventarier hittades.',
        }
    },
})

// =============================================================================
// Create Asset Tool
// =============================================================================

export interface CreateAssetParams {
    namn: string
    inkopspris: number
    inkopsdatum?: string
    kategori?: string
    livslangdAr?: number
    anteckningar?: string
}

export const createAssetTool = defineTool<CreateAssetParams, Inventarie>({
    name: 'create_asset',
    description: 'Registrera en ny inventarie/anläggningstillgång. Skapar automatiskt avskrivningsplan baserat på ekonomisk livslängd. Använd när användaren köpt dator, maskin, bil, eller annan utrustning över halva prisbasbeloppet. Kräver bekräftelse.',
    category: 'write',
    requiresConfirmation: true,
    parameters: {
        type: 'object',
        properties: {
            namn: { type: 'string', description: 'Namn på tillgången (t.ex. "MacBook Pro 16")' },
            inkopspris: { type: 'number', description: 'Inköpspris i kronor' },
            inkopsdatum: { type: 'string', description: 'Inköpsdatum (YYYY-MM-DD), standard idag' },
            kategori: { type: 'string', description: 'Kategori (t.ex. "Datorer", "Möbler", "Fordon")' },
            livslangdAr: { type: 'number', description: 'Avskrivningstid i år (standard: 5)' },
            anteckningar: { type: 'string', description: 'Valfria anteckningar' },
        },
        required: ['namn', 'inkopspris'],
    },
    execute: async (params) => {
        const inkopsdatum = params.inkopsdatum || new Date().toISOString().split('T')[0]
        const livslangdAr = params.livslangdAr ?? 5
        const kategori = params.kategori || 'Inventarier'

        // Calculate annual depreciation
        const arligAvskrivning = Math.round(params.inkopspris / livslangdAr)
        const manatligAvskrivning = Math.round(arligAvskrivning / 12)

        const asset: Inventarie = {
            id: `inv-${Date.now()}`,
            namn: params.namn,
            inkopspris: params.inkopspris,
            inkopsdatum,
            kategori,
            livslangdAr,
            anteckningar: params.anteckningar,
            status: 'aktiv',
        }

        const confirmationRequest: AIConfirmationRequest = {
            title: 'Registrera inventarie',
            description: `Lägg till ${params.namn} som inventarie`,
            summary: [
                { label: 'Namn', value: params.namn },
                { label: 'Inköpspris', value: `${params.inkopspris.toLocaleString('sv-SE')} kr` },
                { label: 'Kategori', value: kategori },
                { label: 'Avskrivningstid', value: `${livslangdAr} år` },
                { label: 'Årlig avskrivning', value: `${arligAvskrivning.toLocaleString('sv-SE')} kr` },
                { label: 'Månatlig avskrivning', value: `${manatligAvskrivning.toLocaleString('sv-SE')} kr` },
            ],
            action: { toolName: 'create_asset', params },
            requireCheckbox: false,
        }

        return {
            success: true,
            data: asset,
            message: `Inventarie "${params.namn}" förberedd för registrering med ${livslangdAr} års avskrivning.`,
            confirmationRequired: confirmationRequest,
        }
    },
})

// =============================================================================
// Calculate Depreciation Tool
// =============================================================================

export interface CalculateDepreciationParams {
    period?: string // e.g., "december 2025" or "2025"
    assetId?: string // Specific asset, or all if omitted
}

export interface DepreciationResult {
    period: string
    totalAmount: number
    assets: Array<{
        id: string
        namn: string
        avskrivning: number
        kvarvarandeVarde: number
    }>
}

export const calculateDepreciationTool = defineTool<CalculateDepreciationParams, DepreciationResult>({
    name: 'calculate_depreciation',
    description: 'Beräkna avskrivning för inventarier. Visar hur mycket som ska skrivas av varje månad/år och kvarvarande bokfört värde.',
    category: 'read',
    requiresConfirmation: false,
    parameters: {
        type: 'object',
        properties: {
            period: { type: 'string', description: 'Period (t.ex. "december 2025" eller "2025")' },
            assetId: { type: 'string', description: 'ID för specifik inventarie (utelämna för alla)' },
        },
    },
    execute: async (params) => {
        const { inventarier } = await inventarieService.getInventarier({ limit: 100 })

        // Filter active assets
        let assets = inventarier.filter(i => i.status === 'aktiv' || !i.status)

        if (params.assetId) {
            assets = assets.filter(i => i.id === params.assetId)
        }

        const period = params.period || new Date().toLocaleString('sv-SE', { month: 'long', year: 'numeric' })

        // Calculate monthly depreciation for each asset
        const depreciationDetails = assets.map(asset => {
            const monthlyDep = Math.round(asset.inkopspris / (asset.livslangdAr * 12))
            // Simplified: assume asset is midway through its life for remaining value
            const monthsOwned = 12 // Simplified
            const totalDepreciated = monthlyDep * monthsOwned
            const remainingValue = Math.max(0, asset.inkopspris - totalDepreciated)

            return {
                id: asset.id,
                namn: asset.namn,
                avskrivning: monthlyDep,
                kvarvarandeVarde: remainingValue,
            }
        })

        const totalAmount = depreciationDetails.reduce((sum, d) => sum + d.avskrivning, 0)

        return {
            success: true,
            data: {
                period,
                totalAmount,
                assets: depreciationDetails,
            },
            message: `Avskrivning för ${period}: ${totalAmount.toLocaleString('sv-SE')} kr på ${assets.length} inventarier.`,
        }
    },
})

