]

/**
 * Purchase entry creator
 * For recording supplier invoices and purchase transactions
 */

import type { JournalEntry, JournalEntryLine, SwedishVatRate } from '../types'
import { roundToOre } from '../validation'
import { calculateVat, getVatAccount } from '../vat'
import { generateEntryId } from '../utils'

export interface PurchaseEntryParams {
  /** Invoice/transaction date (YYYY-MM-DD) */
  date: string
  /** Supplier name or description */
  description: string
  /** Total amount (gross, including VAT) */
  grossAmount: number
  /** Expense account to debit */
  expenseAccount: string
  /** VAT rate for this purchase */
  vatRate?: SwedishVatRate
  /** Payment method account (default: 2440 Leverantörsskulder) */
  liabilityAccount?: string
  /** If paid immediately, use bank account instead */
  paidImmediately?: boolean
  /** Bank account for immediate payment */
  bankAccount?: string
  /** Optional invoice reference */
  invoiceReference?: string
  /** Series identifier */
  series?: string
}

/**
 * Create a purchase/expense journal entry
 * 
 * Standard flow:
 * 1. Debit expense account (net amount)
 * 2. Debit input VAT account (VAT amount)
 * 3. Credit supplier liability (gross amount)
 * 
 * @example
 * // Supplier invoice with VAT
 * createPurchaseEntry({
 *   date: '2024-01-15',
 *   description: 'Office rent January',
 *   grossAmount: 12500,
 *   expenseAccount: '5010', // Lokalhyra
 *   vatRate: 25,
 * })
 * 
 * @example
 * // Immediate payment (e.g., card purchase)
 * createPurchaseEntry({
 *   date: '2024-01-15',
 *   description: 'Software subscription',
 *   grossAmount: 999,
 *   expenseAccount: '6540', // IT-kostnader
 *   vatRate: 25,
 *   paidImmediately: true,
 *   bankAccount: '1930',
 * })
 */
export function createPurchaseEntry(params: PurchaseEntryParams): JournalEntry {
  const {
    date,
    description,
    grossAmount,
    expenseAccount,
    vatRate = 25,
    liabilityAccount = '2440', // Leverantörsskulder
    paidImmediately = false,
    bankAccount = '1930',
    invoiceReference,
    series = 'B', // B-series for supplier invoices
  } = params

  const rows: JournalEntryLine[] = []
  const gross = roundToOre(grossAmount)

  if (vatRate > 0) {
    const vatMultiplier = vatRate / 100
    const netAmount = roundToOre(gross / (1 + vatMultiplier))
    const vatAmount = roundToOre(gross - netAmount)
    const vatAccount = getVatAccount(vatRate, 'input')

    // Debit expense (net)
    rows.push({
      account: expenseAccount,
      debit: netAmount,
      credit: 0,
      description: `${description} (exkl moms)`,
    })

    // Debit input VAT
    rows.push({
      account: vatAccount,
      debit: vatAmount,
      credit: 0,
      description: `Ingående moms ${vatRate}%`,
    })
  } else {
    // No VAT - debit full amount to expense
    rows.push({
      account: expenseAccount,
      debit: gross,
      credit: 0,
      description,
    })
  }

  // Credit the appropriate account
  const creditAccount = paidImmediately ? bankAccount : liabilityAccount
  const creditDescription = paidImmediately 
    ? 'Betalning' 
    : invoiceReference 
      ? `Lev.skuld ref: ${invoiceReference}` 
      : 'Leverantörsskuld'

  rows.push({
    account: creditAccount,
    debit: 0,
    credit: gross,
    description: creditDescription,
  })

  return {
    id: generateEntryId(),
    date,
    description: invoiceReference ? `${description} (${invoiceReference})` : description,
    series,
    rows,
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Create a supplier payment entry (paying off supplier liability)
 * 
 * Flow:
 * 1. Debit supplier liability (reduce debt)
 * 2. Credit bank (money leaving)
 */
export function createSupplierPayment(params: {
  date: string
  description: string
  amount: number
  liabilityAccount?: string
  bankAccount?: string
  series?: string
}): JournalEntry {
  const {
    date,
    description,
    amount,
    liabilityAccount = '2440',
    bankAccount = '1930',
    series = 'B',
  } = params

  const roundedAmount = roundToOre(amount)

  return {
    id: generateEntryId(),
    date,
    description,
    series,
    rows: [
      {
        account: liabilityAccount,
        debit: roundedAmount,
        credit: 0,
        description: 'Betalning leverantörsskuld',
      },
      {
        account: bankAccount,
        debit: 0,
        credit: roundedAmount,
        description: 'Utbetalning',
      },
    ],
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Salary entry creator
 * For recording payroll transactions (Swedish lönehantering)
 */

import type { JournalEntry, JournalEntryLine } from '../types'
import { roundToOre } from '../validation'
import { generateEntryId } from '../utils'

/**
 * Swedish salary components
 */
export interface SalaryComponents {
  /** Gross salary (bruttolön) */
  grossSalary: number
  /** Preliminary tax withheld (preliminärskatt) */
  preliminaryTax: number
  /** Employer social contributions (arbetsgivaravgifter) */
  employerContributions: number
  /** Optional: pension contributions */
  pensionContribution?: number
  /** Optional: other deductions */
  otherDeductions?: number
}

export interface SalaryEntryParams {
  /** Payment date */
  date: string
  /** Employee name or description */
  description: string
  /** Salary components */
  salary: SalaryComponents
  /** Pay immediately from bank */
  paidImmediately?: boolean
  /** Bank account */
  bankAccount?: string
  /** Series identifier */
  series?: string
}

/**
 * Calculate Swedish employer contributions (arbetsgivaravgifter)
 *
 * @param grossSalary Gross salary amount
 * @param rate Employer contribution rate as decimal (e.g. 0.3142). Required — caller must fetch from taxService.
 */
export function calculateEmployerContributions(
  grossSalary: number,
  rate: number
): number {
  return roundToOre(grossSalary * rate)
}

/**
 * Create a salary payment journal entry
 * 
 * Swedish payroll accounting flow:
 * 1. Debit 7010 (Löner) - gross salary as expense
 * 2. Debit 7510 (Arbetsgivaravgifter) - employer contributions
 * 3. Credit 2710 (Personalens källskatt) - tax liability
 * 4. Credit 2730 (Arbetsgivaravgifter skuld) - employer contribution liability
 * 5. Credit 2920 (Upplupna löner) or 1930 (Bank) - net salary
 * 
 * @example
 * createSalaryEntry({
 *   date: '2024-01-25',
 *   description: 'Lön januari - Anna Andersson',
 *   salary: {
 *     grossSalary: 45000,
 *     preliminaryTax: 13500,
 *     employerContributions: 14139, // 45000 * 0.3142
 *   },
 *   paidImmediately: true,
 * })
 */
export function createSalaryEntry(params: SalaryEntryParams): JournalEntry {
  const {
    date,
    description,
    salary,
    paidImmediately = false,
    bankAccount = '1930',
    series = 'L', // L-series for salary/payroll
  } = params

  const {
    grossSalary,
    preliminaryTax,
    employerContributions,
    pensionContribution = 0,
    otherDeductions = 0,
  } = salary

  const rows: JournalEntryLine[] = []

  // Net salary (what the employee receives)
  const netSalary = roundToOre(grossSalary - preliminaryTax - pensionContribution - otherDeductions)

  // 1. Debit salary expense (gross)
  rows.push({
    account: '7010',
    debit: roundToOre(grossSalary),
    credit: 0,
    description: 'Bruttolön',
  })

  // 2. Debit employer contributions expense
  rows.push({
    account: '7510',
    debit: roundToOre(employerContributions),
    credit: 0,
    description: 'Arbetsgivaravgifter',
  })

  // 3. Credit tax liability (källskatt)
  rows.push({
    account: '2710',
    debit: 0,
    credit: roundToOre(preliminaryTax),
    description: 'Personalens källskatt',
  })

  // 4. Credit employer contribution liability
  rows.push({
    account: '2730',
    debit: 0,
    credit: roundToOre(employerContributions),
    description: 'Skuld arbetsgivaravgifter',
  })

  // 5. Pension contribution if applicable
  if (pensionContribution > 0) {
    rows.push({
      account: '2740',
      debit: 0,
      credit: roundToOre(pensionContribution),
      description: 'Skuld pensionspremier',
    })
  }

  // 6. Other deductions if applicable
  if (otherDeductions > 0) {
    rows.push({
      account: '2790',
      debit: 0,
      credit: roundToOre(otherDeductions),
      description: 'Övriga löneavdrag',
    })
  }

  // 7. Net salary - either paid immediately or as accrued liability
  if (paidImmediately) {
    rows.push({
      account: bankAccount,
      debit: 0,
      credit: netSalary,
      description: 'Löneutbetalning',
    })
  } else {
    rows.push({
      account: '2920',
      debit: 0,
      credit: netSalary,
      description: 'Upplupna löner',
    })
  }

  return {
    id: generateEntryId(),
    date,
    description,
    series,
    rows,
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Create a tax payment entry (paying off payroll taxes)
 * Used when paying Skatteverket on the 12th of each month
 */
export function createPayrollTaxPayment(params: {
  date: string
  description: string
  preliminaryTax: number
  employerContributions: number
  bankAccount?: string
  taxAccount?: string
  series?: string
}): JournalEntry {
  const {
    date,
    description,
    preliminaryTax,
    employerContributions,
    bankAccount = '1930',
    taxAccount = '1630', // Skattekonto
    series = 'L',
  } = params

  const totalAmount = roundToOre(preliminaryTax + employerContributions)

  return {
    id: generateEntryId(),
    date,
    description,
    series,
    rows: [
      // Clear tax liabilities
      {
        account: '2710',
        debit: roundToOre(preliminaryTax),
        credit: 0,
        description: 'Betalning källskatt',
      },
      {
        account: '2730',
        debit: roundToOre(employerContributions),
        credit: 0,
        description: 'Betalning arbetsgivaravgifter',
      },
      // Payment from bank
      {
        account: bankAccount,
        debit: 0,
        credit: totalAmount,
        description: 'Skattebetalning',
      },
    ],
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Create a salary accrual entry (for monthly accruals)
 * Used for accruing vacation pay, bonuses, etc.
 */
export function createSalaryAccrual(params: {
  date: string
  description: string
  amount: number
  type: 'vacation' | 'bonus' | 'other'
  series?: string
}): JournalEntry {
  const { date, description, amount, type, series = 'L' } = params

  // Map type to accounts
  const accountMap = {
    vacation: { expense: '7090', liability: '2920' },
    bonus: { expense: '7010', liability: '2920' },
    other: { expense: '7090', liability: '2990' },
  }

  const accounts = accountMap[type]
  const roundedAmount = roundToOre(amount)

  return {
    id: generateEntryId(),
    date,
    description,
    series,
    rows: [
      {
        account: accounts.expense,
        debit: roundedAmount,
        credit: 0,
        description: `Reservering ${type === 'vacation' ? 'semesterlön' : type === 'bonus' ? 'bonus' : 'övrigt'}`,
      },
      {
        account: accounts.liability,
        debit: 0,
        credit: roundedAmount,
        description: 'Upplupen skuld',
      },
    ],
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Sales entry creator
 * For recording customer invoices and sales transactions
 */

import type { JournalEntry, JournalEntryLine, SwedishVatRate } from '../types'
import { roundToOre } from '../validation'
import { calculateVat, getVatAccount } from '../vat'
import { generateEntryId } from '../utils'

export interface SalesEntryParams {
  /** Invoice date (YYYY-MM-DD) */
  date: string
  /** Customer name or description */
  description: string
  /** Total amount (gross, including VAT) */
  grossAmount: number
  /** Revenue account to credit */
  revenueAccount?: string
  /** VAT rate for this sale */
  vatRate?: SwedishVatRate
  /** Customer receivable account (default: 1510 Kundfordringar) */
  receivableAccount?: string
  /** If paid immediately (cash/card), use bank instead */
  paidImmediately?: boolean
  /** Bank account for immediate payment */
  bankAccount?: string
  /** Optional invoice number */
  invoiceNumber?: string
  /** Series identifier */
  series?: string
}

/**
 * Create a sales/income journal entry
 * 
 * Standard flow:
 * 1. Debit customer receivable (or bank) with gross amount
 * 2. Credit revenue account (net amount)
 * 3. Credit output VAT account (VAT amount)
 * 
 * @example
 * // Customer invoice with VAT
 * createSalesEntry({
 *   date: '2024-01-15',
 *   description: 'Consulting services January',
 *   grossAmount: 50000,
 *   revenueAccount: '3010', // Försäljning tjänster
 *   vatRate: 25,
 * })
 * 
 * @example
 * // Cash sale
 * createSalesEntry({
 *   date: '2024-01-15',
 *   description: 'Product sale',
 *   grossAmount: 1250,
 *   revenueAccount: '3001', // Försäljning varor
 *   vatRate: 25,
 *   paidImmediately: true,
 * })
 */
export function createSalesEntry(params: SalesEntryParams): JournalEntry {
  const {
    date,
    description,
    grossAmount,
    revenueAccount = '3010', // Försäljning tjänster
    vatRate = 25,
    receivableAccount = '1510', // Kundfordringar
    paidImmediately = false,
    bankAccount = '1930',
    invoiceNumber,
    series = 'A', // A-series for customer invoices
  } = params

  const rows: JournalEntryLine[] = []
  const gross = roundToOre(grossAmount)

  // Debit the appropriate account (receivable or bank)
  const debitAccount = paidImmediately ? bankAccount : receivableAccount
  const debitDescription = paidImmediately 
    ? 'Inbetalning' 
    : invoiceNumber 
      ? `Kundfaktura ${invoiceNumber}` 
      : 'Kundfordran'

  rows.push({
    account: debitAccount,
    debit: gross,
    credit: 0,
    description: debitDescription,
  })

  if (vatRate > 0) {
    const vatMultiplier = vatRate / 100
    const netAmount = roundToOre(gross / (1 + vatMultiplier))
    const vatAmount = roundToOre(gross - netAmount)
    const vatAccount = getVatAccount(vatRate, 'output')

    // Credit revenue (net)
    rows.push({
      account: revenueAccount,
      debit: 0,
      credit: netAmount,
      description: `${description} (exkl moms)`,
    })

    // Credit output VAT
    rows.push({
      account: vatAccount,
      debit: 0,
      credit: vatAmount,
      description: `Utgående moms ${vatRate}%`,
    })
  } else {
    // No VAT - credit full amount to revenue
    rows.push({
      account: revenueAccount,
      debit: 0,
      credit: gross,
      description,
    })
  }

  return {
    id: generateEntryId(),
    date,
    description: invoiceNumber ? `${description} (Faktura ${invoiceNumber})` : description,
    series,
    rows,
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Create a customer payment entry (receiving payment on receivable)
 * 
 * Flow:
 * 1. Debit bank (money coming in)
 * 2. Credit customer receivable (reduce claim)
 */
export function createPaymentReceivedEntry(params: {
  date: string
  description: string
  amount: number
  receivableAccount?: string
  bankAccount?: string
  invoiceReference?: string
  series?: string
}): JournalEntry {
  const {
    date,
    description,
    amount,
    receivableAccount = '1510',
    bankAccount = '1930',
    invoiceReference,
    series = 'A',
  } = params

  const roundedAmount = roundToOre(amount)

  return {
    id: generateEntryId(),
    date,
    description: invoiceReference ? `${description} (${invoiceReference})` : description,
    series,
    rows: [
      {
        account: bankAccount,
        debit: roundedAmount,
        credit: 0,
        description: 'Inbetalning kundfordran',
      },
      {
        account: receivableAccount,
        debit: 0,
        credit: roundedAmount,
        description: invoiceReference ? `Faktura ${invoiceReference}` : 'Kundfordran',
      },
    ],
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

/**
 * Create a credit note entry (reversing a sale)
 */
export function createCreditNoteEntry(params: {
  date: string
  description: string
  grossAmount: number
  revenueAccount?: string
  vatRate?: SwedishVatRate
  receivableAccount?: string
  creditNoteNumber?: string
  series?: string
}): JournalEntry {
  const {
    date,
    description,
    grossAmount,
    revenueAccount = '3010',
    vatRate = 25,
    receivableAccount = '1510',
    creditNoteNumber,
    series = 'A',
  } = params

  const rows: JournalEntryLine[] = []
  const gross = roundToOre(grossAmount)

  // Opposite of sales entry: debit revenue, debit VAT, credit receivable
  if (vatRate > 0) {
    const vatMultiplier = vatRate / 100
    const netAmount = roundToOre(gross / (1 + vatMultiplier))
    const vatAmount = roundToOre(gross - netAmount)
    const vatAccount = getVatAccount(vatRate, 'output')

    rows.push(
      { account: revenueAccount, debit: netAmount, credit: 0, description: 'Kreditering' },
      { account: vatAccount, debit: vatAmount, credit: 0, description: `Moms kreditering ${vatRate}%` },
      { account: receivableAccount, debit: 0, credit: gross, description: 'Kreditfaktura' },
    )
  } else {
    rows.push(
      { account: revenueAccount, debit: gross, credit: 0, description: 'Kreditering' },
      { account: receivableAccount, debit: 0, credit: gross, description: 'Kreditfaktura' },
    )
  }

  return {
    id: generateEntryId(),
    date,
    description: creditNoteNumber 
      ? `Kreditfaktura ${creditNoteNumber}: ${description}` 
      : `Kreditering: ${description}`,
    series,
    rows,
    finalized: false,
    createdAt: new Date().toISOString(),
  }
}

