/**
 * Transactions Repository
 * 
 * Handles all transaction-related database operations.
 */

import type { SupabaseClient } from '@supabase/supabase-js'
import type { Database } from '@/types/database'
import type { TransactionInput, TransactionMetadata, Json } from './types'

type DbClient = SupabaseClient<Database>

export function createTransactionsRepository(supabase: DbClient) {
    return {
        /**
         * Get transactions with optional filters
         */
        async list(filters: {
            limit?: number
            startDate?: string
            endDate?: string
            minAmount?: number
            maxAmount?: number
            status?: string
        } = {}) {
            let query = supabase
                .from('transactions')
                .select('*')
                .order('date', { ascending: false })

            if (filters.startDate) query = query.gte('date', filters.startDate)
            if (filters.endDate) query = query.lte('date', filters.endDate)
            if (filters.minAmount !== undefined) query = query.gte('amount', filters.minAmount)
            if (filters.status) query = query.eq('status', filters.status)
            if (filters.limit) query = query.limit(filters.limit)

            const { data, error } = await query
            if (error) console.error('Supabase Error (getTransactions):', error)
            return data || []
        },

        /**
         * Get a single transaction by ID
         */
        async getById(id: string) {
            const { data, error } = await supabase
                .from('transactions')
                .select('*')
                .eq('id', id)
                .single()

            if (error) return null
            return data
        },

        /**
         * Create a new transaction
         */
        async create(tx: TransactionInput) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const { data, error } = await supabase
                .from('transactions')
                .insert({
                    id: tx.id,
                    date: tx.date,
                    description: tx.description,
                    name: tx.description || 'Transaction',
                    amount: String(tx.amount || 0),
                    amount_value: Number(tx.amount || 0),
                    status: tx.status,
                    category: tx.category,
                    source: tx.source || 'manual',
                    created_by: tx.createdBy || tx.created_by,
                    metadata: tx as unknown as Json
                } as any)
                .select()
                .single()

            if (error) console.error('Supabase Error:', error)
            return data || tx
        },

        /**
         * Update transaction metadata
         */
        async updateMetadata(id: string, metadata: TransactionMetadata) {
            // First get existing meta
            const { data: existing } = await supabase
                .from('transactions')
                .select('metadata')
                .eq('id', id)
                .single()

            const existingMeta = (existing?.metadata as Record<string, unknown>) || {}
            const newMeta = { ...existingMeta, ...metadata }

            await supabase
                .from('transactions')
                .update({
                    metadata: newMeta as unknown as Json,
                    status: metadata.status || undefined,
                    category: metadata.category || undefined
                })
                .eq('id', id)

            return newMeta
        },

        /**
         * Update a transaction
         */
        async update(id: string, updates: Record<string, unknown>) {
            await supabase.from('transactions').update(updates).eq('id', id)
            return { id, ...updates }
        },

        /**
         * Delete a transaction
         */
        async delete(id: string) {
            const { error } = await supabase
                .from('transactions')
                .delete()
                .eq('id', id)

            return !error
        },
    }
}

export type TransactionsRepository = ReturnType<typeof createTransactionsRepository>

/**
 * Förmåner (Employee Benefits) Data Layer
 * 
 * Supabase-backed operations for managing employee benefits.
 * Includes catalog of all Swedish benefits and assignment tracking.
 */

import { getSupabaseClient, isSupabaseConfigured } from './database/supabase'
import type {
    FormanCatalogItem,
    EmployeeBenefit,
    AssignBenefitInput,
    BenefitTaxImpact,
    BenefitCategory,
} from './ai/tool-types'
import { formanerCatalog } from './ai/reference-data'
import { taxService } from '@/services/tax-service'

// =============================================================================
// Database Row Types
// =============================================================================

interface FormanCatalogRow {
    id: string
    name: string
    category: BenefitCategory
    max_amount?: number
    tax_free: boolean
    formansvarde_calculation?: string
    description?: string
    rules?: Record<string, unknown>
    bas_account?: string
}

interface EmployeeBenefitRow {
    id: string
    company_id: string
    employee_name: string
    benefit_type: string
    amount: number | string
    year: number
    month?: number
    formansvarde?: number | string
    notes?: string
    created_at: string
}

// =============================================================================
// Catalog Operations
// =============================================================================

/**
 * List all available benefits from catalog
 * Falls back to static data if Supabase not configured
 */
export async function listAvailableBenefits(
    companyType?: 'AB' | 'EF' | 'EnskildFirma'
): Promise<FormanCatalogItem[]> {
    // Try Supabase first
    if (isSupabaseConfigured()) {
        const supabase = getSupabaseClient()
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const { data, error } = await supabase
            .from('formaner_catalog' as any)
            .select('*')
            .order('name')

        if (!error && data?.length) {
            const mapped = (data as unknown as FormanCatalogRow[]).map(mapCatalogFromDb)
            return filterByCompanyType(mapped, companyType)
        }
    }

    // Fallback to static catalog
    return filterByCompanyType(formanerCatalog, companyType)
}

/**
 * Get a specific benefit by ID
 */
export async function getBenefitDetails(id: string): Promise<FormanCatalogItem | null> {
    if (isSupabaseConfigured()) {
        const supabase = getSupabaseClient()
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const { data } = await supabase
            .from('formaner_catalog' as any)
            .select('*')
            .eq('id', id)
            .single()

        if (data) return mapCatalogFromDb(data as unknown as FormanCatalogRow)
    }

    // Fallback
    return formanerCatalog.find(b => b.id === id) || null
}

/**
 * List benefits by category
 */
export async function listBenefitsByCategory(
    category: BenefitCategory
): Promise<FormanCatalogItem[]> {
    const all = await listAvailableBenefits()
    return all.filter(b => b.category === category)
}

// =============================================================================
// Employee Benefit Assignment
// =============================================================================

/**
 * Assign a benefit to an employee
 */
export async function assignBenefit(
    input: AssignBenefitInput
): Promise<EmployeeBenefit | null> {
    if (!isSupabaseConfigured()) {
        console.warn('Supabase not configured')
        return null
    }

    // Calculate förmånsvärde if applicable
    const benefit = await getBenefitDetails(input.benefitType)
    const formansvarde = benefit?.taxFree ? 0 : calculateFormansvarde(input.benefitType, input.amount)

    const supabase = getSupabaseClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('employee_benefits' as any)
        .insert({
            employee_name: input.employeeName,
            benefit_type: input.benefitType,
            amount: input.amount,
            year: input.year,
            month: input.month,
            formansvarde: formansvarde,
            notes: input.notes,
        })
        .select()
        .single()

    if (error) {
        console.error('Error assigning benefit:', error)
        return null
    }

    return mapBenefitFromDb(data as unknown as EmployeeBenefitRow)
}

/**
 * Get all benefits assigned to an employee for a year
 */
export async function getEmployeeBenefits(
    employeeName: string,
    year: number
): Promise<EmployeeBenefit[]> {
    if (!isSupabaseConfigured()) return []

    const supabase = getSupabaseClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('employee_benefits' as any)
        .select('*')
        .eq('employee_name', employeeName)
        .eq('year', year)
        .order('created_at', { ascending: false })

    if (error) {
        console.error('Error fetching employee benefits:', error)
        return []
    }

    return ((data || []) as unknown as EmployeeBenefitRow[]).map(mapBenefitFromDb)
}

/**
 * Get remaining allowance for a benefit (e.g., friskvård)
 */
export async function getRemainingAllowance(
    employeeName: string,
    benefitType: string,
    year: number
): Promise<number> {
    const benefit = await getBenefitDetails(benefitType)
    if (!benefit?.maxAmount) return Infinity // No limit

    const used = await getEmployeeBenefits(employeeName, year)
    const usedAmount = used
        .filter(b => b.benefitType === benefitType)
        .reduce((sum, b) => sum + b.amount, 0)

    return Math.max(0, benefit.maxAmount - usedAmount)
}

/**
 * Suggest unused benefits for an employee
 */
export async function suggestUnusedBenefits(
    employeeName: string,
    year: number,
    companyType: 'AB' | 'EF' | 'EnskildFirma' = 'AB'
): Promise<FormanCatalogItem[]> {
    const available = await listAvailableBenefits(companyType)
    const used = await getEmployeeBenefits(employeeName, year)
    const usedTypes = new Set(used.map(b => b.benefitType))

    // Return tax-free benefits not yet used
    return available.filter(b =>
        b.taxFree &&
        !usedTypes.has(b.id) &&
        b.maxAmount // Only suggest benefits with clear limits
    )
}

// =============================================================================
// Tax Calculations
// =============================================================================

/**
 * Calculate the tax impact of a benefit
 */
export async function calculateBenefitTaxImpact(
    benefitType: string,
    amount: number
): Promise<BenefitTaxImpact> {
    const benefit = await getBenefitDetails(benefitType)
    const taxFree = benefit?.taxFree ?? false
    const formansvarde = taxFree ? 0 : calculateFormansvarde(benefitType, amount)

    const currentYear = new Date().getFullYear()
    const rates = await taxService.getAllTaxRates(currentYear)
    if (!rates) {
        throw new Error(`Skattesatser för ${currentYear} saknas — kan inte beräkna förmånsskatt.`)
    }
    const employerFeesRate = rates.employerContributionRate
    const employeeTaxRate = rates.marginalTaxRateApprox

    const employeeTax = formansvarde * employeeTaxRate
    const employerFees = taxFree ? 0 : formansvarde * employerFeesRate
    const netCost = amount + employerFees

    return {
        benefitType,
        amount,
        taxFree,
        formansvarde,
        employeeTax,
        employerFees,
        netCost,
    }
}

/**
 * Calculate förmånsvärde for taxable benefits.
 * Rates must be provided — no silent fallbacks.
 */
function calculateFormansvarde(benefitType: string, amount: number, rates?: { formansvardeKost: number; formansvardeLunch: number; drivmedelFormansvardeMultiplier?: number }): number {
    const kostRate = rates?.formansvardeKost ?? 0
    const lunchRate = rates?.formansvardeLunch ?? 0
    const drivmedelMultiplier = rates?.drivmedelFormansvardeMultiplier ?? 1.2

    switch (benefitType) {
        case 'kost':
            return kostRate
        case 'lunch':
            return lunchRate
        case 'drivmedel':
            return amount * drivmedelMultiplier
        case 'tjanstebil':
            return amount
        default:
            return amount
    }
}

// =============================================================================
// Helpers
// =============================================================================

function filterByCompanyType(
    benefits: FormanCatalogItem[],
    companyType?: 'AB' | 'EF' | 'EnskildFirma'
): FormanCatalogItem[] {
    if (!companyType) return benefits

    return benefits.filter(b => {
        if (!b.rules) return true
        return b.rules[companyType] !== false
    })
}

// function mapCatalogFromDb(row: any): FormanCatalogItem {
function mapCatalogFromDb(row: FormanCatalogRow): FormanCatalogItem {
    return {
        id: row.id,
        name: row.name,
        category: row.category,
        maxAmount: row.max_amount ? Number(row.max_amount) : undefined,
        taxFree: row.tax_free,
        formansvardeCalculation: row.formansvarde_calculation,
        description: row.description,
        rules: row.rules,
        basAccount: row.bas_account,
    }
}

function mapBenefitFromDb(row: EmployeeBenefitRow): EmployeeBenefit {
    return {
        id: row.id,
        companyId: row.company_id,
        employeeName: row.employee_name,
        benefitType: row.benefit_type,
        amount: Number(row.amount),
        year: row.year,
        month: row.month,
        formansvarde: row.formansvarde ? Number(row.formansvarde) : undefined,
        notes: row.notes,
        createdAt: new Date(row.created_at),
    }
}

/**
 * Server-Side Model Authorization
 * 
 * Prevents users from accessing AI models they haven't paid for.
 * This is the critical security layer that validates model access
 * server-side, preventing client-side bypass attacks.
 */

// TODO: Run `npx supabase gen types typescript` after applying migration

import { getSupabaseAdmin } from './database/supabase'
import { getModelById, DEFAULT_MODEL_ID, AI_MODELS, type ModelTier, type AIModel } from './ai/models'

// ============================================================================
// Types
// ============================================================================

interface UsageRow {
    tokens_used?: number
    requests_count?: number
    period_start?: string
    period_end?: string
}

export interface ModelAuthResult {
    authorized: boolean
    modelId: string           // Authorized model ID (may be fallback)
    model: AIModel
    userTier: UserTier
    requestedTier: ModelTier | 'unknown'
    reason?: string
}

export type UserTier = 'demo' | 'free' | 'pro' | 'enterprise'

export interface UsageStats {
    tokensUsed: number
    requestsCount: number
    periodStart: Date
    periodEnd: Date
}

export interface SecurityEvent {
    eventType: 'unauthorized_model_access' | 'rate_limit_exceeded' | 'suspicious_activity' | 'auth_failure' | 'admin_action'
    userId?: string
    requestedResource?: string
    allowedResource?: string
    userTier?: string
    ipAddress?: string
    userAgent?: string
    metadata?: Record<string, unknown>
}

// ============================================================================
// Tier Access Control
// ============================================================================

/**
 * Defines which user tiers can access which model tiers.
 * Users can access their tier and all lower tiers.
 * Demo users cannot access any real AI models.
 */
const TIER_ACCESS: Record<UserTier, ModelTier[]> = {
    'demo': [], // Demo users get simulated responses, no real AI
    'free': [], // Free deprecated, treat same as demo
    'pro': ['free', 'pro'],
    'enterprise': ['free', 'pro', 'enterprise'],
}

/**
 * Monthly token limits per tier
 */
export const TIER_LIMITS: Record<UserTier, { tokensPerMonth: number; requestsPerDay: number }> = {
    'demo': { tokensPerMonth: 0, requestsPerDay: 0 }, // Demo gets simulated AI, no real tokens
    'free': { tokensPerMonth: 0, requestsPerDay: 0 }, // Free deprecated, same as demo
    'pro': { tokensPerMonth: 500_000, requestsPerDay: 500 },
    'enterprise': { tokensPerMonth: 5_000_000, requestsPerDay: 5000 },
}

// ============================================================================
// Core Authorization Functions
// ============================================================================

/**
 * Get user's subscription tier from database
 * Returns 'demo' by default for unauthenticated/new users
 */
export async function getUserTier(userId: string): Promise<UserTier> {
    try {
        const supabase = getSupabaseAdmin()

        // Query the profiles table for subscription tier
        const { data: profile, error: profileError } = await supabase
            .from('profiles')
            .select('subscription_tier')
            .eq('id', userId)
            .single()

        if (profileError || !profile) {
            console.warn('[ModelAuth] Profile not found for user:', userId)
            return 'demo'
        }

        const tier = profile.subscription_tier as UserTier

        // Treat 'free' as 'demo' (free is deprecated)
        if (tier === 'free') {
            return 'demo'
        }

        // Validate tier is one of our known values
        if (['demo', 'pro', 'enterprise'].includes(tier)) {
            return tier
        }

        return 'demo'
    } catch (error) {
        console.error('[ModelAuth] Failed to get user tier:', error)
        // Default to 'demo' to prevent unauthorized access due to DB issues
        return 'demo'
    }
}

/**
 * Check if user is in demo mode (simulated AI, no real API calls)
 */
export function isDemoMode(tier: UserTier): boolean {
    return tier === 'demo' || tier === 'free'
}

/**
 * Authorize a model request
 * Returns the authorized model ID (original if allowed, fallback if not)
 */
export async function authorizeModel(
    userId: string,
    requestedModelId: string
): Promise<ModelAuthResult> {
    const userTier = await getUserTier(userId)
    const model = getModelById(requestedModelId)

    // Unknown model - use default
    if (!model) {
        const defaultModel = getModelById(DEFAULT_MODEL_ID)!
        return {
            authorized: false,
            modelId: DEFAULT_MODEL_ID,
            model: defaultModel,
            userTier,
            requestedTier: 'unknown',
            reason: `Unknown model requested: ${requestedModelId}`
        }
    }

    const allowedTiers = TIER_ACCESS[userTier]
    const isAuthorized = allowedTiers.includes(model.tier)

    if (isAuthorized) {
        return {
            authorized: true,
            modelId: requestedModelId,
            model,
            userTier,
            requestedTier: model.tier,
        }
    }

    // Find the best fallback model for the user's tier
    // Prefer same provider, then fall back to default
    const fallbackModel = AI_MODELS.find(m =>
        allowedTiers.includes(m.tier) && m.provider === model.provider
    ) || getModelById(DEFAULT_MODEL_ID)!

    return {
        authorized: false,
        modelId: fallbackModel.id,
        model: fallbackModel,
        userTier,
        requestedTier: model.tier,
        reason: `Model '${model.name}' requires ${model.tier} tier, user has ${userTier}`
    }
}

/**
 * Get models available to a user based on their tier
 */
export async function getAvailableModels(userId: string): Promise<AIModel[]> {
    const userTier = await getUserTier(userId)
    const allowedTiers = TIER_ACCESS[userTier]

    return AI_MODELS.filter(model => allowedTiers.includes(model.tier))
}

