    get subscriptions() { return getStripe().subscriptions },
    get checkout() { return getStripe().checkout },
    get billingPortal() { return getStripe().billingPortal },
    get webhooks() { return getStripe().webhooks },
    constructEvent: (...args: Parameters<Stripe['webhooks']['constructEvent']>) =>
        getStripe().webhooks.constructEvent(...args),
}

// ============================================================================
// Price IDs (set in environment variables)
// ============================================================================

export const PRICE_IDS = {
    pro: process.env.STRIPE_PRO_PRICE_ID || '',
    enterprise: process.env.STRIPE_ENTERPRISE_PRICE_ID || '',
}

// Map Stripe price IDs to subscription tiers
export function getTierFromPriceId(priceId: string): 'pro' | 'enterprise' | 'free' {
    if (priceId === PRICE_IDS.pro) return 'pro'
    if (priceId === PRICE_IDS.enterprise) return 'enterprise'
    return 'free'
}

// ============================================================================
// Customer Management
// ============================================================================

/**
 * Get or create a Stripe customer for a user
 */
export async function getOrCreateCustomer(
    userId: string,
    email: string,
    name?: string
): Promise<string> {
    const { getSupabaseAdmin } = await import('./database/supabase')
    const supabase = getSupabaseAdmin()

    // Check if user already has a Stripe customer ID
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data: profile } = await supabase
        .from('profiles' as any)
        .select('stripe_customer_id')
        .eq('id', userId)
        .single()

    const profileData = profile as { stripe_customer_id?: string } | null
    if (profileData?.stripe_customer_id) {
        return profileData.stripe_customer_id
    }

    // Create new customer
    const customer = await stripe.customers.create({
        email,
        name: name || undefined,
        metadata: {
            supabase_user_id: userId,
        },
    })

    // Store customer ID in profile
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    await supabase
        .from('profiles' as any)
        .update({ stripe_customer_id: customer.id })
        .eq('id', userId)

    return customer.id
}

// ============================================================================
// Checkout Session
// ============================================================================

export interface CreateCheckoutOptions {
    userId: string
    email: string
    tier: 'pro' | 'enterprise'
    successUrl: string
    cancelUrl: string
    discountCode?: string  // Optional Stripe promotion code
}

/**
 * Create a Stripe Checkout session for subscription
 */
export async function createCheckoutSession(options: CreateCheckoutOptions): Promise<string> {
    const { userId, email, tier, successUrl, cancelUrl, discountCode } = options

    const priceId = PRICE_IDS[tier]
    if (!priceId) {
        throw new Error(`No price ID configured for tier: ${tier}`)
    }

    // Get or create customer
    const customerId = await getOrCreateCustomer(userId, email)

    // Build session config
    const sessionConfig: Stripe.Checkout.SessionCreateParams = {
        customer: customerId,
        mode: 'subscription',
        line_items: [
            {
                price: priceId,
                quantity: 1,
            },
        ],
        success_url: successUrl,
        cancel_url: cancelUrl,
        metadata: {
            supabase_user_id: userId,
            tier,
        },
        subscription_data: {
            metadata: {
                supabase_user_id: userId,
            },
        },
    }

    // Add discount code if provided
    if (discountCode) {
        sessionConfig.discounts = [{ promotion_code: discountCode }]
    }

    const session = await stripe.checkout.sessions.create(sessionConfig)

    if (!session.url) {
        throw new Error('Failed to create checkout session')
    }

    return session.url
}

// ============================================================================
// Customer Portal
// ============================================================================

/**
 * Create a Stripe Customer Portal session for managing subscription
 */
export async function createPortalSession(
    customerId: string,
    returnUrl: string
): Promise<string> {
    const session = await stripe.billingPortal.sessions.create({
        customer: customerId,
        return_url: returnUrl,
    })

    return session.url
}

// ============================================================================
// Subscription Management
// ============================================================================

/**
 * Update user's subscription tier based on Stripe subscription status
 */
export async function updateUserTier(
    userId: string,
    tier: 'free' | 'pro' | 'enterprise'
): Promise<void> {
    const { getSupabaseAdmin } = await import('./database/supabase')
    const supabase = getSupabaseAdmin()

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    await supabase
        .from('profiles' as any)
        .update({ subscription_tier: tier })
        .eq('id', userId)

    console.log(`[Stripe] Updated user ${userId} to tier: ${tier}`)
}

/**
 * Get user ID from Stripe customer ID
 */
export async function getUserIdFromCustomer(customerId: string): Promise<string | null> {
    const { getSupabaseAdmin } = await import('./database/supabase')
    const supabase = getSupabaseAdmin()

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data } = await supabase
        .from('profiles' as any)
        .select('id')
        .eq('stripe_customer_id', customerId)
        .single()

    return (data as { id?: string } | null)?.id || null
}

// ============================================================================
// Credit Management
// ============================================================================

/**
 * Add purchased credits to a user's account
 */
export async function addUserCredits(
    userId: string,
    credits: number,
    stripePaymentId?: string,
    pricePaidCents?: number
): Promise<void> {
    const { getSupabaseAdmin } = await import('./database/supabase')
    const supabase = getSupabaseAdmin()

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { error } = await supabase.rpc('add_user_credits' as any, {
        p_user_id: userId,
        p_credits: credits,
        p_stripe_payment_id: stripePaymentId ?? null,
        p_price_paid_cents: pricePaidCents ?? null,
    } as any)

    if (error) {
        console.error('[Stripe] Failed to add credits:', error)
        throw new Error('Failed to add credits to user account')
    }

    console.log(`[Stripe] Added ${credits} credits to user ${userId}`)
}

/**
 * Get a user's current credit balance
 */
export async function getUserCredits(userId: string): Promise<number> {
    const { getSupabaseAdmin } = await import('./database/supabase')
    const supabase = getSupabaseAdmin()

    const { data, error } = await supabase.rpc('get_user_credits', {
        p_user_id: userId,
    })

    if (error) {
        console.error('[Stripe] Failed to get credits:', error)
        return 0
    }

    return data || 0
}

"use client"

import { createContext, useContext, useState, useCallback, useEffect, useMemo, useRef, type ReactNode } from "react"
import type { SceneType } from "@/components/ai/pixel-mascots"
import type { WalkthroughContent } from "@/components/ai/walkthrough-overlay"
import type { WalkthroughResponse } from "@/components/ai/blocks"
import { emitEvent } from "@/services/event-service"

// Types for AI Dialog state
export type AIDialogStatus = "hidden" | "thinking" | "complete" | "error" | "walkthrough" | "walkthrough-blocks"

// Navigation info for accept flow
export interface AIDialogNavigation {
    /** Route to navigate to */
    route: string
    /** Label for the destination */
    label?: string
    /** Open in new tab */
    newTab?: boolean
}

// Display info for structured output
export interface AIDialogDisplay {
    /** Display type/card component */
    type: string
    /** Data for the card */
    data?: unknown
    /** Title for the card */
    title?: string
}

export interface AIDialogOutput {
    /** The type of content being generated */
    contentType: string
    /** Display title for the output */
    title: string
    /** The generated content to preview */
    content: React.ReactNode
    /** Raw data that will be applied on accept */
    data?: unknown
    /** ID to highlight after accepting */
    highlightId?: string
    /** Navigation info if AI wants to navigate somewhere */
    navigation?: AIDialogNavigation
    /** Structured display for card rendering */
    display?: AIDialogDisplay
    /** Confirmation request for write actions */
    confirmationRequired?: {
        id: string
        title: string
        description?: string
        summary: Array<{ label: string; value: string }>
        warnings?: string[]
        action?: unknown
        requireCheckbox?: boolean
    }
}

// Map content types to scene types
const CONTENT_TO_SCENE: Record<string, SceneType> = {
    receipt: 'reading',
    receipts: 'reading',
    transaction: 'reading',
    transactions: 'reading',
    document: 'reading',
    invoice: 'reading',
    invoices: 'reading',
    report: 'cooking',
    reports: 'cooking',
    analysis: 'cooking',
    search: 'searching',
    query: 'searching',
    find: 'searching',
    default: 'playing',
}

interface AIDialogContextType {
    /** Current status of the AI dialog */
    status: AIDialogStatus
    /** Output data when status is "complete" */
    output: AIDialogOutput | null
    /** Whether we're on mobile (no overlay) */
    isMobile: boolean
    /** Current scene type for thinking animation */
    sceneType: SceneType
    /** Show the AI dialog in thinking state */
    showThinking: (contentType?: string) => void
    /** Show the AI dialog with completed output */
    showComplete: (output: AIDialogOutput) => void
    /** Hide the AI dialog */
    hide: () => void
    /** Accept the output and trigger highlight */
    accept: () => void
    /** Request edit (focuses sidebar input) */
    requestEdit: () => void
    /** ID currently being highlighted */
    highlightedId: string | null
    /** Clear the highlight */
    clearHighlight: () => void
    /** Walkthrough content when status is "walkthrough" */
    walkthroughContent: WalkthroughContent | null
    /** Block-based walkthrough response */
    walkthroughBlocks: WalkthroughResponse | null
    /** Close the walkthrough overlay */
    closeWalkthrough: () => void
    /** Whether the AI is thinking in the background while a walkthrough is displayed */
    isThinkingInBackground: boolean
}

const AIDialogContext = createContext<AIDialogContextType | null>(null)

export function useAIDialog() {
    const context = useContext(AIDialogContext)
    if (!context) {
        throw new Error("useAIDialog must be used within an AIDialogProvider")
    }
    return context
}

// Optional hook that doesn't throw if not in provider
export function useAIDialogOptional() {
    return useContext(AIDialogContext)
}

interface AIDialogProviderProps {
    children: ReactNode
}

export function AIDialogProvider({ children }: AIDialogProviderProps) {
    const [status, setStatus] = useState<AIDialogStatus>("hidden")
    const [output, setOutput] = useState<AIDialogOutput | null>(null)
    const [highlightedId, setHighlightedId] = useState<string | null>(null)
    const [isMobile, setIsMobile] = useState(false)
    const [sceneType, setSceneType] = useState<SceneType>("playing")
    const [walkthroughContent, setWalkthroughContent] = useState<WalkthroughContent | null>(null)
    const [walkthroughBlocks, setWalkthroughBlocks] = useState<WalkthroughResponse | null>(null)
    const [isThinkingInBackground, setIsThinkingInBackground] = useState(false)

    // Helper to determine scene type from content type
    const getSceneType = useCallback((contentType?: string): SceneType => {
        if (!contentType) return 'playing'
        const normalizedType = contentType.toLowerCase()
        return CONTENT_TO_SCENE[normalizedType] || CONTENT_TO_SCENE.default
    }, [])

    // Check for mobile viewport
    useEffect(() => {
        const checkMobile = () => {
            setIsMobile(window.innerWidth < 768)
        }
        checkMobile()
        window.addEventListener("resize", checkMobile)
        return () => window.removeEventListener("resize", checkMobile)
    }, [])

    // Listen for AI events from use-chat hook
    useEffect(() => {
        const handleAIStart = (e: CustomEvent<{ contentType?: string }>) => {
            if (!isMobile) {
                // Don't replace a visible walkthrough with thinking state
                if (status === "walkthrough" || status === "walkthrough-blocks") {
                    setIsThinkingInBackground(true)
                    return
                }
                setStatus("thinking")
                setOutput(null)
                setSceneType(getSceneType(e.detail?.contentType))
            }
        }

        const handleAIComplete = (e: CustomEvent<AIDialogOutput>) => {
            if (!isMobile) {
                setIsThinkingInBackground(false)
                setStatus("complete")
                setOutput(e.detail)
            }
        }

        const handleAIError = (e: CustomEvent<AIDialogOutput>) => {
            if (!isMobile) {
                setIsThinkingInBackground(false)
                setStatus("error")
                setOutput(e.detail)
                setSceneType("error")
            }
        }

        const handleAIHide = () => {
            setStatus("hidden")
            setOutput(null)
            setWalkthroughContent(null)
        }

        const handleAIWalkthrough = (e: CustomEvent<WalkthroughContent>) => {
            if (!isMobile) {
                setStatus("walkthrough")
                setWalkthroughContent(e.detail)
                setOutput(null)
            }
        }

        const handleAIWalkthroughBlocks = (e: CustomEvent<WalkthroughResponse>) => {
            if (!isMobile) {
                setIsThinkingInBackground(false)
                setStatus("walkthrough-blocks")
                setWalkthroughBlocks(e.detail)
                setOutput(null)
            }
        }

        window.addEventListener("ai-dialog-start", handleAIStart as EventListener)
        window.addEventListener("ai-dialog-complete", handleAIComplete as EventListener)
        window.addEventListener("ai-dialog-error", handleAIError as EventListener)
        window.addEventListener("ai-dialog-hide", handleAIHide)
        window.addEventListener("ai-dialog-walkthrough", handleAIWalkthrough as EventListener)
        window.addEventListener("ai-dialog-walkthrough-blocks", handleAIWalkthroughBlocks as EventListener)

        return () => {
            window.removeEventListener("ai-dialog-start", handleAIStart as EventListener)
            window.removeEventListener("ai-dialog-complete", handleAIComplete as EventListener)
            window.removeEventListener("ai-dialog-error", handleAIError as EventListener)
            window.removeEventListener("ai-dialog-hide", handleAIHide)
            window.removeEventListener("ai-dialog-walkthrough", handleAIWalkthrough as EventListener)
            window.removeEventListener("ai-dialog-walkthrough-blocks", handleAIWalkthroughBlocks as EventListener)
        }
    }, [isMobile, getSceneType, status])

    const showThinking = useCallback((contentType?: string) => {
        if (!isMobile) {
            setStatus("thinking")
            setOutput(null)
            setSceneType(getSceneType(contentType))
        }
    }, [isMobile, getSceneType])

    const showComplete = useCallback((newOutput: AIDialogOutput) => {
        if (!isMobile) {
            setStatus("complete")
            setOutput(newOutput)
        }
    }, [isMobile])

    const hide = useCallback(() => {
        setStatus("hidden")
        setOutput(null)
        setWalkthroughContent(null)
        setWalkthroughBlocks(null)
    }, [])

    const closeWalkthrough = useCallback(() => {
        // Persist walkthrough to händelser before clearing
        if (walkthroughBlocks) {
            emitEvent({
                source: 'ai',
                category: 'system',
                action: 'walkthrough_generated',
                title: walkthroughBlocks.title,
                actor: { type: 'ai', name: 'Scope AI' },
                description: walkthroughBlocks.subtitle,
                metadata: {
                    walkthroughBlocks,
                    closedAt: new Date().toISOString(),
                },
            }).catch(() => {
                // Fire-and-forget — don't block close on network failure
            })
        }
        setStatus("hidden")
        setWalkthroughContent(null)
        setWalkthroughBlocks(null)
        setIsThinkingInBackground(false)
    }, [walkthroughBlocks])

    const accept = useCallback(() => {
        // Set highlight if provided
        if (output?.highlightId) {
            setHighlightedId(output.highlightId)
            // Auto-clear highlight after 5 seconds
            setTimeout(() => setHighlightedId(null), 5000)
        }

        // Dispatch navigation event if navigation info exists
        if (output?.navigation) {
            window.dispatchEvent(new CustomEvent("ai-navigate", {
                detail: output.navigation
            }))
        }

        hide()
        // Dispatch event for any listeners that need to know about acceptance
        window.dispatchEvent(new CustomEvent("ai-dialog-accepted", {
            detail: {
                data: output?.data,
                display: output?.display,
                navigation: output?.navigation,
            }
        }))
    }, [output, hide])

    const requestEdit = useCallback(() => {
        // Focus the sidebar chat input with prefill hint
        window.dispatchEvent(new CustomEvent("ai-chat-focus-input", {
            detail: { prefill: "Ändra så att " }
        }))
    }, [])

    const clearHighlight = useCallback(() => {
        setHighlightedId(null)
    }, [])

    const value = useMemo(() => ({
        status,
        output,
        isMobile,
        sceneType,
        showThinking,
        showComplete,
        hide,
        accept,
        requestEdit,
        highlightedId,
        clearHighlight,
        walkthroughContent,
        walkthroughBlocks,
        closeWalkthrough,
        isThinkingInBackground,
    }), [status, output, isMobile, sceneType, showThinking, showComplete, hide, accept, requestEdit, highlightedId, clearHighlight, walkthroughContent, walkthroughBlocks, closeWalkthrough, isThinkingInBackground])

    return (
        <AIDialogContext.Provider value={value}>
            {children}
        </AIDialogContext.Provider>
    )
}

