const mapShareHolding = (row: ShareHoldingRow): ShareHolding => ({
    id: row.id,
    companyId: row.company_id,
    companyName: row.company_name,
    orgNumber: row.org_number,
    holdingType: (row.holding_type || 'other') as ShareHolding['holdingType'],
    sharesCount: row.shares_count,
    purchaseDate: row.purchase_date ? new Date(row.purchase_date) : undefined,
    purchasePrice: row.purchase_price ? Number(row.purchase_price) : undefined,
    currentValue: row.current_value ? Number(row.current_value) : undefined,
    dividendReceived: Number(row.dividend_received || 0),
    basAccount: row.bas_account || '1350',
    notes: row.notes,
    createdAt: new Date(row.created_at),
    updatedAt: new Date(row.updated_at),
})

export const listShareHoldings = () => 
    listFromTable<ShareHoldingRow, ShareHolding>('shareholdings', mapShareHolding, 'company_name')

export const createShareHolding = (input: CreateShareHoldingInput) =>
    createInTable<ShareHoldingRow, ShareHolding>('shareholdings', {
        company_name: input.companyName,
        org_number: input.orgNumber,
        holding_type: input.holdingType ?? 'other',
        shares_count: input.sharesCount,
        purchase_date: input.purchaseDate?.toISOString().split('T')[0],
        purchase_price: input.purchasePrice,
        current_value: input.purchasePrice, // Start at purchase price
        notes: input.notes,
    }, mapShareHolding)

export const updateShareHolding = (id: string, updates: Partial<ShareHolding>) =>
    updateInTable<ShareHoldingRow, ShareHolding>('shareholdings', id, {
        ...(updates.currentValue && { current_value: updates.currentValue }),
        ...(updates.dividendReceived && { dividend_received: updates.dividendReceived }),
        ...(updates.notes !== undefined && { notes: updates.notes }),
    }, mapShareHolding)

export const deleteShareHolding = (id: string) => deleteFromTable('shareholdings', id)

/**
 * Record dividend received
 */
export async function recordDividend(id: string, amount: number): Promise<ShareHolding | null> {
    try {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const { data: existing } = await supabase()
            .from('shareholdings' as any)
            .select('dividend_received')
            .eq('id', id)
            .single()

        const row = existing as { dividend_received?: number } | null
        const newTotal = (row?.dividend_received || 0) + amount
        return updateShareHolding(id, { dividendReceived: newTotal })
    } catch {
        return null
    }
}

/**
 * Calculate unrealized gain/loss
 */
export function calculateUnrealizedGain(holding: ShareHolding): number {
    const currentValue = holding.currentValue || 0
    const purchasePrice = holding.purchasePrice || 0
    return currentValue - purchasePrice
}

// =============================================================================
// Portfolio Summary
// =============================================================================

export interface InvestmentSummary {
    shares: { count: number; totalValue: number; unrealizedGain: number }
    totalValue: number
}

export async function getInvestmentSummary(): Promise<InvestmentSummary> {
    const shares = await listShareHoldings()

    const sharesValue = shares.reduce((sum, s) => sum + (s.currentValue || 0), 0)
    const sharesGain = shares.reduce((sum, s) => sum + calculateUnrealizedGain(s), 0)

    return {
        shares: { count: shares.length, totalValue: sharesValue, unrealizedGain: sharesGain },
        totalValue: sharesValue,
    }
}

/**
 * Periodiseringsfonder Data Layer
 * 
 * Supabase-backed CRUD operations for tax allocation reserves.
 * AI tools call these functions to manage periodiseringsfonder.
 */

import { getSupabaseClient, isSupabaseConfigured } from '@/lib/database/supabase'
import type { Periodiseringsfond, CreatePeriodiseringsfondInput, TaxSavingsCalculation } from './ai-tool-types'
import { taxService } from '@/services/tax-service'

// =============================================================================
// Database Row Types
// =============================================================================

interface PeriodiseringsfondRow {
    id: string
    company_id: string
    year: number
    amount: number | string
    dissolved_amount?: number | string
    expires_at: string
    status: 'active' | 'dissolved' | 'partially_dissolved'
    notes?: string
    created_at: string
    updated_at: string
}

// =============================================================================
// CRUD Operations
// =============================================================================

/**
 * List all periodiseringsfonder for the current company
 */
export async function listPeriodiseringsfonder(): Promise<Periodiseringsfond[]> {
    if (!isSupabaseConfigured()) {
        console.warn('Supabase not configured, returning empty array')
        return []
    }

    const supabase = getSupabaseClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('periodiseringsfonder' as any)
        .select('*')
        .order('year', { ascending: false })

    if (error) {
        console.error('Error fetching periodiseringsfonder:', error)
        return []
    }

    return ((data || []) as unknown as PeriodiseringsfondRow[]).map(mapFromDb)
}

/**
 * Create a new periodiseringsfond
 */
export async function createPeriodiseringsfond(
    input: CreatePeriodiseringsfondInput
): Promise<Periodiseringsfond | null> {
    if (!isSupabaseConfigured()) {
        console.warn('Supabase not configured')
        return null
    }

    // Calculate expiry date (6 years from end of tax year)
    const expiresAt = new Date(input.year + 6, 11, 31) // Dec 31, 6 years later

    const supabase = getSupabaseClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('periodiseringsfonder' as any)
        .insert({
            year: input.year,
            amount: input.amount,
            expires_at: expiresAt.toISOString().split('T')[0],
            notes: input.notes,
            status: 'active',
            dissolved_amount: 0,
        })
        .select()
        .single()

    if (error) {
        console.error('Error creating periodiseringsfond:', error)
        return null
    }

    return mapFromDb(data as unknown as PeriodiseringsfondRow)
}

/**
 * Dissolve (or partially dissolve) a periodiseringsfond
 */
export async function dissolvePeriodiseringsfond(
    id: string,
    amount?: number // If not provided, dissolve fully
): Promise<Periodiseringsfond | null> {
    if (!isSupabaseConfigured()) {
        return null
    }

    const supabase = getSupabaseClient()

    // First get the current fond
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data: existingData } = await supabase
        .from('periodiseringsfonder' as any)
        .select('*')
        .eq('id', id)
        .single()

    const existing = existingData as unknown as PeriodiseringsfondRow | null

    if (!existing) return null

    const existingAmount = Number(existing.amount)
    const existingDissolved = Number(existing.dissolved_amount || 0)
    const dissolveAmount = amount ?? (existingAmount - existingDissolved)
    const newDissolvedAmount = existingDissolved + dissolveAmount
    const newStatus = newDissolvedAmount >= existingAmount ? 'dissolved' : 'partially_dissolved'

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('periodiseringsfonder' as any)
        .update({
            dissolved_amount: newDissolvedAmount,
            status: newStatus,
            updated_at: new Date().toISOString(),
        })
        .eq('id', id)
        .select()
        .single()

    if (error) {
        console.error('Error dissolving periodiseringsfond:', error)
        return null
    }

    return mapFromDb(data as unknown as PeriodiseringsfondRow)
}

/**
 * Get periodiseringsfonder expiring within N months
 */
export async function getExpiringFonder(withinMonths: number = 12): Promise<Periodiseringsfond[]> {
    if (!isSupabaseConfigured()) {
        return []
    }

    const futureDate = new Date()
    futureDate.setMonth(futureDate.getMonth() + withinMonths)

    const supabase = getSupabaseClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await supabase
        .from('periodiseringsfonder' as any)
        .select('*')
        .eq('status', 'active')
        .lte('expires_at', futureDate.toISOString().split('T')[0])
        .order('expires_at', { ascending: true })

    if (error) {
        console.error('Error fetching expiring fonder:', error)
        return []
    }

    return ((data || []) as unknown as PeriodiseringsfondRow[]).map(mapFromDb)
}

// =============================================================================
// Tax Calculations
// =============================================================================

/**
 * Calculate tax savings from creating a periodiseringsfond.
 * Requires tax rates from the database — returns null if unavailable.
 * @param amount Amount to set aside
 * @param companyType AB (25%, 20.6% tax) or EF/Enskild (30%, income tax)
 */
export async function calculateTaxSavings(
    amount: number,
    companyType: 'AB' | 'EF' | 'EnskildFirma' = 'AB',
    year: number = new Date().getFullYear()
): Promise<TaxSavingsCalculation | null> {
    const rates = await taxService.getAllTaxRates(year)
    if (!rates) {
        console.error(`[periodiseringsfonder] Cannot calculate tax savings: rates for ${year} unavailable`)
        return null
    }

    // AB: taxed at corporate rate
    // EF/Enskild: taxed at approximate marginal income tax
    const taxRate = companyType === 'AB' ? rates.corporateTaxRate : rates.marginalTaxRateApprox

    const taxSaved = amount * taxRate
    const expiresAt = new Date(year + 6, 11, 31)

    return {
        periodiseringsfondAmount: amount,
        taxRate,
        taxSaved,
        expiresAt,
    }
}

/**
 * Get total active periodiseringsfonder amount
 */
export async function getTotalActiveFonder(): Promise<number> {
    const fonder = await listPeriodiseringsfonder()
    return fonder
        .filter(f => f.status === 'active' || f.status === 'partially_dissolved')
        .reduce((sum, f) => sum + (f.amount - f.dissolvedAmount), 0)
}

// =============================================================================
// Helpers
// =============================================================================

function mapFromDb(row: PeriodiseringsfondRow): Periodiseringsfond {
    return {
        id: row.id,
        companyId: row.company_id,
        year: row.year,
        amount: Number(row.amount),
        dissolvedAmount: Number(row.dissolved_amount || 0),
        expiresAt: new Date(row.expires_at),
        status: row.status,
        notes: row.notes,
        createdAt: new Date(row.created_at),
        updatedAt: new Date(row.updated_at),
    }
}

/**
 * INK2 SRU Main Processor
 * Calculates complete INK2/INK2R/INK2S declarations
 */

import type { Verification } from "@/hooks/use-verifications"
import type { SRUDeclaration, SRUField, TaxPeriod } from "@/types/sru"
import type { CompanyInfo, INK2CalculationResult, AccountBalance } from './types'
import { calculateAccountBalances } from './types'
import { calculateBalanceSheet } from './balance-sheet'
import { calculateIncomeStatement } from './income-statement'
import { calculateTaxAdjustments } from './tax-adjustments'

export const INK2SRUProcessor = {
  /**
   * Calculate all INK2 fields from verifications
   */
  calculateAll(
    verifications: Verification[],
    company: CompanyInfo,
    _taxPeriod: TaxPeriod
  ): INK2CalculationResult {
    // Calculate account balances for the fiscal year
    const balances = calculateAccountBalances(
      verifications,
      company.fiscalYearStart,
      company.fiscalYearEnd
    )

    // Calculate each section
    const balanceSheet = calculateBalanceSheet(balances)
    const incomeStatement = calculateIncomeStatement(balances)
    const taxAdjustments = calculateTaxAdjustments(incomeStatement, balances)

    // Format dates for main form
    const formatDate = (d: Date) =>
      `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, '0')}${String(d.getDate()).padStart(2, '0')}`

    // Main form fields
    const mainForm: SRUField[] = [
      { code: 7011, value: formatDate(company.fiscalYearStart) },
      { code: 7012, value: formatDate(company.fiscalYearEnd) },
    ]

    // Transfer result to main form
    const profit = taxAdjustments.find(f => f.code === 7670)
    const loss = taxAdjustments.find(f => f.code === 7770)

    if (profit) mainForm.push({ code: 7104, value: profit.value })
    if (loss) mainForm.push({ code: 7114, value: loss.value })

    // Calculate summary
    const totalAssets = balanceSheet
      .filter(f => typeof f.code === 'number' && f.code >= 7201 && f.code <= 7281)
      .reduce((sum, f) => sum + (typeof f.value === 'number' ? f.value : 0), 0)

    const totalEquityAndLiabilities = balanceSheet
      .filter(f => typeof f.code === 'number' && f.code >= 7301 && f.code <= 7370)
      .reduce((sum, f) => sum + (typeof f.value === 'number' ? f.value : 0), 0)

    const revenue = incomeStatement
      .filter(f => [7410, 7413, 7417, 7419].includes(f.code as number))
      .reduce((sum, f) => sum + (typeof f.value === 'number' ? f.value : 0), 0)

    const expenses = incomeStatement
      .filter(f => [7511, 7512, 7513, 7514, 7515, 7517, 7522, 7528].includes(f.code as number))
      .reduce((sum, f) => sum + (typeof f.value === 'number' ? f.value : 0), 0)

    return {
      mainForm,
      balanceSheet,
      incomeStatement,
      taxAdjustments,
      summary: {
        totalAssets,
        totalEquityAndLiabilities,
        revenue,
        expenses,
        profit: typeof profit?.value === 'number' ? profit.value : 0,
        taxableIncome: (typeof profit?.value === 'number' ? profit.value : 0) - 
          (typeof loss?.value === 'number' ? loss.value : 0),
      },
    }
  },

  /**
   * Generate complete SRU declarations
   */
  generateDeclarations(
    verifications: Verification[],
    company: CompanyInfo,
    taxPeriod: TaxPeriod
  ): SRUDeclaration[] {
    const result = this.calculateAll(verifications, company, taxPeriod)

    const baseDecl = {
      orgnr: company.orgnr,
      name: company.name,
    }

    return [
      // INK2 Main form
      {
        ...baseDecl,
        blankettType: 'INK2' as const,
        period: taxPeriod,
        fields: result.mainForm,
      },
      // INK2R (both balance sheet and income statement combined)
      {
        ...baseDecl,
        blankettType: 'INK2R' as const,
        period: taxPeriod,
        fields: [
          { code: 7011, value: result.mainForm.find(f => f.code === 7011)?.value || '' },
          { code: 7012, value: result.mainForm.find(f => f.code === 7012)?.value || '' },
          ...result.balanceSheet,
          ...result.incomeStatement,
        ],
      },
      // INK2S
      {
        ...baseDecl,
        blankettType: 'INK2S' as const,
        period: taxPeriod,
        fields: [
          { code: 7011, value: result.mainForm.find(f => f.code === 7011)?.value || '' },
          { code: 7012, value: result.mainForm.find(f => f.code === 7012)?.value || '' },
          ...result.taxAdjustments,
        ],
      },
    ]
  },
}

/**
 * Tax Declaration Types
 * For Swedish INK2/SRU tax declarations
 */

import type { Verification } from "@/hooks/use-verifications"
import type { SRUField, TaxPeriod } from "@/types/sru"

/**
 * Account balance for tax calculations
 */
export interface AccountBalance {
  account: string
  debit: number
  credit: number
  balance: number  // Credit - Debit (standard accounting sign)
}

/**
 * Company information for tax filing
 */
export interface CompanyInfo {
  orgnr: string
  name: string
  fiscalYearStart: Date
  fiscalYearEnd: Date
}

/**
 * Result of INK2 calculation
 */
export interface INK2CalculationResult {
  mainForm: SRUField[]       // INK2
  balanceSheet: SRUField[]   // INK2R balance
  incomeStatement: SRUField[] // INK2R income
  taxAdjustments: SRUField[] // INK2S
  summary: {
    totalAssets: number
    totalEquityAndLiabilities: number
    revenue: number
    expenses: number
    profit: number
    taxableIncome: number
  }
}

/**
 * Calculate account balances from verifications for a specific period
 */
export function calculateAccountBalances(
  verifications: Verification[],
  startDate: Date,
  endDate: Date
): Map<string, AccountBalance> {
  const balances = new Map<string, AccountBalance>()

  verifications.forEach(v => {
    const vDate = new Date(v.date)
    if (vDate < startDate || vDate > endDate) return

    v.rows.forEach(row => {
      const existing = balances.get(row.account) || {
        account: row.account,
        debit: 0,
        credit: 0,
        balance: 0,
      }

      existing.debit += row.debit || 0
      existing.credit += row.credit || 0
      existing.balance = existing.credit - existing.debit

      balances.set(row.account, existing)
    })
  })

  return balances
}

/**
 * Sum accounts matching a range
 */
export function sumAccountRange(
  balances: Map<string, AccountBalance>,
  start: number,
  end: number
): number {
  let total = 0

  balances.forEach((bal, account) => {
    const accNum = parseInt(account.slice(0, 4))
    if (accNum >= start && accNum <= end) {
      total += bal.balance
    }
  })

  return total
}

/**
 * VAT Report Calculator
 * Calculates VAT reports from various data sources
 */

import type { Verification } from "@/hooks/use-verifications"
import type { VatReport } from './types'
import {
  createEmptyVatReport,
  recalculateVatReport,
  getVatDeadline,
  formatDate,
  parsePeriod,
  isDateInQuarter,
} from './utils'

export const VatCalculator = {
  /**
   * Calculate VAT report from verifikationer for a given period.
   * Maps BAS account codes to the appropriate rutor.
   */
  calculateFromVerifications(verifikationer: Verification[], period: string): VatReport {
    const { quarter, year } = parsePeriod(period)
    const startMonth = (quarter - 1) * 3
    const endMonth = startMonth + 2

    // Filter Transactions
    const periodTransactions = verifikationer.filter(v => {
      const d = new Date(v.date)
      return d.getFullYear() === year && d.getMonth() >= startMonth && d.getMonth() <= endMonth
    })

    const dueDate = getVatDeadline(quarter, year)
    const today = new Date()
    let status: VatReport["status"] = "upcoming"
    if (today > dueDate) status = "overdue"

    // Start with empty report
    const report = createEmptyVatReport(period, formatDate(dueDate), status)

    // Map accounts to rutor
    // BAS account mappings for Swedish VAT:
    // Output VAT: 2610-2639
    // Input VAT: 2640-2649
    // Sales (Bases): 3000-3399 (Box 05), 3xxx Exempt (Box 42)
    // Purchases (Reverse Charge Bases): 4515 (Box 20), 4535 (Box 21)

    periodTransactions.forEach(v => {
      if (!v.rows) return

      v.rows.forEach(row => {
        const konto = row.account
        const credit = row.credit || 0
        const debit = row.debit || 0
        const netCredit = credit - debit
        const netDebit = debit - credit

        // 1. VAT ACCOUNTS (Moms)
        // Output VAT 25% (2610-2619)
        if (konto >= "2610" && konto <= "2619") {
          report.ruta10 += credit // Usually credit for output VAT
        }
        // Output VAT 12% (2620-2629)
        else if (konto >= "2620" && konto <= "2629") {
          report.ruta11 += credit
        }
        // Output VAT 6% (2630-2639)
        else if (konto >= "2630" && konto <= "2639") {
          report.ruta12 += credit
        }
        // Input VAT (2640-2649)
        else if (konto >= "2640" && konto <= "2649") {
          report.ruta48 += debit // Usually debit for input VAT
        }

        // 2. SALES BASES (Försäljning) - Net Credit
        // Box 05: Momspliktig försäljning 25% (Standard 3000-3099, 3100-3199 varies but often 25%)
        if ((konto >= "3000" && konto <= "3099") || (konto >= "3100" && konto <= "3399")) {
          report.ruta05 += netCredit
        }
        // Box 42: Momsfri försäljning (Approved exempt accounts range) e.g. 36xx, 37xx often used for exempt
        // Or specific accounts for EU sales (Box 35, 39 etc)
        // Simple heuristic for now: If it's a 3-series account but NOT caught above, put in 42?
        // Better: Explicitly map common "Momsfri" accounts.
        else if (konto.startsWith("3") && !((konto >= "3000" && konto <= "3399"))) {
          // 3600-3699 Internt/Sidointäkter often exempt or 3900 Övrigt
          report.ruta42 += netCredit
        }


        // 3. PURCHASE BASES (Inköp / Reverse Charge) - Net Debit
        // Box 20: Goods from EU
        if (konto === "4515") {
          report.ruta20 += netDebit
        }
        // Box 21: Services from EU (e.g. Google/Facebook Ads) - Account 4535
        else if (konto === "4535") {
          report.ruta21 += netDebit
        }
        // Box 22: Services from outside EU - Account 4531
        else if (konto === "4531") {
          report.ruta22 += netDebit
        }

      })
    })

    // Note: We NO LONGER reverse-calculate 05, 06, 07 from the VAT. 
    // We rely on the actual booking accounts.
    // However, for 12% and 6% sales (Box 06, 07), we might need specific account ranges
    // or we can fallback to the reverse calc ONLY if the account scan didn't find anything 
    // to avoid breaking legacy data that might not use standard accounts.

    // Fallback: If Box 06 is empty but we have Box 11 (12% VAT), guess based on VAT
    if (report.ruta06 === 0 && report.ruta11 > 0) report.ruta06 = Math.round(report.ruta11 / 0.12)
    if (report.ruta07 === 0 && report.ruta12 > 0) report.ruta07 = Math.round(report.ruta12 / 0.06)

    return recalculateVatReport(report)
  },

  /**
   * Calculate VAT report from transactions for a given period.
   */
  calculateFromTransactions(
    transactions: { amountValue: number; vatAmount?: number; vatRate?: number; timestamp: Date }[],
    period: string
  ): VatReport {
    const { quarter, year } = parsePeriod(period)
    const startMonth = (quarter - 1) * 3
    const endMonth = startMonth + 2

    const periodTransactions = transactions.filter(t => {
      const d = new Date(t.timestamp)
      return d.getFullYear() === year && d.getMonth() >= startMonth && d.getMonth() <= endMonth
    })

    const dueDate = getVatDeadline(quarter, year)
    const today = new Date()
    let status: VatReport["status"] = "upcoming"
    if (today > dueDate) status = "overdue"

    const report = createEmptyVatReport(period, formatDate(dueDate), status)

    periodTransactions.forEach(t => {
      if (t.vatAmount) {
        if (t.vatAmount > 0) {
          // Utgående moms
          if (t.vatRate === 25) report.ruta10 += t.vatAmount
          else if (t.vatRate === 12) report.ruta11 += t.vatAmount
          else if (t.vatRate === 6) report.ruta12 += t.vatAmount
        } else {
          // Ingående moms
          report.ruta48 += Math.abs(t.vatAmount)
        }
      }
    })

    if (report.ruta10 > 0) report.ruta05 = Math.round(report.ruta10 / 0.25)
    if (report.ruta11 > 0) report.ruta06 = Math.round(report.ruta11 / 0.12)
    if (report.ruta12 > 0) report.ruta07 = Math.round(report.ruta12 / 0.06)

    return recalculateVatReport(report)
  },

  /**
   * Calculate VAT report from source documents.
   */
  calculateFromDocuments(params: {
    customerInvoices: Array<{ issueDate: string; vatAmount?: number; vatRate?: number }>
    supplierInvoices: Array<{ invoiceDate: string; vatAmount: number }>
    receipts?: Array<{ date: string; vatAmount?: number }>
    period: string
  }): VatReport {
    const { customerInvoices, supplierInvoices, receipts = [], period } = params
    const { quarter, year } = parsePeriod(period)
    const startMonth = (quarter - 1) * 3
    const endMonth = startMonth + 2

    const isInPeriod = (dateStr: string) => {
      const d = new Date(dateStr)
      return d.getFullYear() === year && d.getMonth() >= startMonth && d.getMonth() <= endMonth
    }

    const dueDate = getVatDeadline(quarter, year)
    const today = new Date()
    let status: VatReport["status"] = "upcoming"
    if (today > dueDate) status = "overdue"

    const report = createEmptyVatReport(period, formatDate(dueDate), status)

    // Utgående moms from customer invoices
    customerInvoices
      .filter(inv => isInPeriod(inv.issueDate))
      .forEach(inv => {
        if (inv.vatAmount) {
          if (inv.vatRate === 25) report.ruta10 += inv.vatAmount
          else if (inv.vatRate === 12) report.ruta11 += inv.vatAmount
          else if (inv.vatRate === 6) report.ruta12 += inv.vatAmount
        }
      })

    // Ingående moms from supplier invoices
    supplierInvoices
      .filter(inv => isInPeriod(inv.invoiceDate))
      .forEach(inv => {
        report.ruta48 += inv.vatAmount
      })

    // Ingående moms from receipts
    receipts
      .filter(r => isInPeriod(r.date))
      .forEach(r => {
        if (r.vatAmount) report.ruta48 += r.vatAmount
      })

    if (report.ruta10 > 0) report.ruta05 = Math.round(report.ruta10 / 0.25)
    if (report.ruta11 > 0) report.ruta06 = Math.round(report.ruta11 / 0.12)
    if (report.ruta12 > 0) report.ruta07 = Math.round(report.ruta12 / 0.06)

    return recalculateVatReport(report)
  },

  /**
   * Calculate VAT report from Real Verifications (Ledger).
   */
  calculateFromRealVerifications(verifications: Verification[], period: string): VatReport {
    const { quarter, year } = parsePeriod(period)
    const startMonth = (quarter - 1) * 3
    const endMonth = startMonth + 2

    const dueDate = getVatDeadline(quarter, year)
    const today = new Date()
    let status: VatReport["status"] = "upcoming"
    if (today > dueDate) status = "overdue"

    const report = createEmptyVatReport(period, formatDate(dueDate), status)

    verifications.forEach(v => {
      const d = new Date(v.date)
      if (!isDateInQuarter(d, quarter, year)) return

      v.rows.forEach(row => {
        const konto = row.account
        const liabilityNet = (row.credit || 0) - (row.debit || 0)
        const assetNet = (row.debit || 0) - (row.credit || 0)

        if (konto >= "2610" && konto <= "2619") report.ruta10 += liabilityNet
        else if (konto >= "2620" && konto <= "2629") report.ruta11 += liabilityNet
        else if (konto >= "2630" && konto <= "2639") report.ruta12 += liabilityNet
        else if (konto >= "2640" && konto <= "2649") report.ruta48 += assetNet
      })
    })

    if (report.ruta10 > 0) report.ruta05 = Math.round(report.ruta10 / 0.25)
    if (report.ruta11 > 0) report.ruta06 = Math.round(report.ruta11 / 0.12)
    if (report.ruta12 > 0) report.ruta07 = Math.round(report.ruta12 / 0.06)

    return recalculateVatReport(report)
  },
}

